-- Poems batch 437
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-37','送高適弟耽歸臨淮作','王維','唐','御定全唐诗','yuding','','[]','少年客淮泗，落魄居下邳。遨遊向燕趙，結客過臨淄。',216,'御定全唐詩/json/125.json','["少年客淮泗，落魄居下邳。遨遊向燕趙，結客過臨淄。", "山東諸侯國，迎送紛交馳。自爾厭遊俠，閉戶方垂帷。", "深明戴家禮，頗學毛公詩。備知經濟道，高臥陶唐時。", "聖主詔天下，賢人不得遺。公吏奉纁組，安車去茅茨。", "君王蒼龍闕，九門十二逵。群公朝謁罷，冠劍下丹墀。", "野鶴終踉蹌，威鳳徒參差。或問理人術，但致還山詞。", "天書降北闕，賜帛歸東菑。都門謝親故，行路日逶遲。", "孤帆萬里外，淼漫將何之。江天海陵郡，雲日淮南祠。", "杳冥滄洲上，蕩漭無人知。緯蕭或賣藥，出處安能期。"]'),
('yuding-38','送綦毋潛落第還鄉','王維','唐','御定全唐诗','yuding','','[]','聖代無隱者，英靈盡來歸。遂令東山客，不得顧采薇。',96,'御定全唐詩/json/125.json','["聖代無隱者，英靈盡來歸。遂令東山客，不得顧采薇。", "既至君門遠，孰雲吾道非。江淮度寒食，京洛縫春衣。", "置酒臨長道，同心與我違。行當浮桂棹，未幾拂荊扉。", "遠樹帶行客，孤村當落暉。吾謀適不用，勿謂知音稀。"]'),
('yuding-39','送張舍人佐江州同薛璩十韻','王維','唐','御定全唐诗','yuding','','[]','束帶趨承明，守官唯謁者。清晨聽銀蚪，薄暮辭金馬。',120,'御定全唐詩/json/125.json','["束帶趨承明，守官唯謁者。清晨聽銀蚪，薄暮辭金馬。", "受辭未嘗易，當是方知寡。清范何風流，高文有風雅。", "忽佐江上州，當自潯陽下。逆旅到三湘，長途應百舍。", "香爐遠峰出，石鏡澄湖瀉。董奉杏成林，陶潛菊盈把。", "范蠡常好之，廬山我心也。送君思遠道，欲以數行灑。"]'),
('yuding-40','送韋大夫東京留守','王維','唐','御定全唐诗','yuding','','[]','人外遺世慮，空端結遐心。曾是巢許淺，始知堯舜深。',192,'御定全唐詩/json/125.json','["人外遺世慮，空端結遐心。曾是巢許淺，始知堯舜深。", "蒼生詎有物，黃屋如喬林。上德撫神運，沖和穆宸襟。", "雲雷康屯難，江海遂飛沉。天工寄人英，龍袞瞻君臨。", "名器苟不假，保厘固其任。素質貫方領，清景照華簪。", "慷慨念王室，從容獻官箴。雲旗蔽三川，畫角發龍吟。", "晨揚天漢聲，夕卷大河陰。窮人業已甯，逆虜遺之擒。", "然後解金組，拂衣東山岑。給事黃門省，秋光正沉沉。", "壯心與身退，老病隨年侵。君子從相訪，重玄其可尋。"]'),
('yuding-41','資聖寺送甘二','王維','唐','御定全唐诗','yuding','','[]','浮生信如寄，薄宦夫何有。來往本無歸，別離方此受。',48,'御定全唐詩/json/125.json','["浮生信如寄，薄宦夫何有。來往本無歸，別離方此受。", "柳色藹春餘，槐陰清夏首。不覺禦溝上，銜悲執杯酒。"]'),
('yuding-42','留別山中溫古上人兄並示舍弟縉','王維','唐','御定全唐诗','yuding','','[]','解薜登天朝，去師偶時哲。豈惟山中人，兼負松上月。',96,'御定全唐詩/json/125.json','["解薜登天朝，去師偶時哲。豈惟山中人，兼負松上月。", "宿昔同遊止，致身雲霞末。開軒臨潁陽，臥視飛鳥沒。", "好依磐石飯，屢對瀑泉渴。理齊小狎隱，道勝寧外物。", "舍弟官崇高，宗兄此削髮。荊扉但灑掃，乘閑當過歇。"]'),
('yuding-43','觀別者','王維','唐','御定全唐诗','yuding','','[]','青青楊柳陌，陌上別離人。愛子游燕趙，高堂有老親。',96,'御定全唐詩/json/125.json','["青青楊柳陌，陌上別離人。愛子游燕趙，高堂有老親。", "不行無可養，行去百憂新。切切委兄弟，依依向四鄰。", "都門帳飲畢，從此謝親賓。揮涕逐前侶，含淒動征輪。", "車徒望不見，時見起行塵。吾亦辭家久，看之淚滿巾。"]'),
('yuding-44','別弟縉後登青龍寺望藍田山','王維','唐','御定全唐诗','yuding','','[]','陌上新離別，蒼茫四郊晦。登高不見君，故山複雲外。',48,'御定全唐詩/json/125.json','["陌上新離別，蒼茫四郊晦。登高不見君，故山複雲外。", "遠樹蔽行人，長天隱秋塞。心悲宦遊子，何處飛征蓋。"]'),
('yuding-45','別綦毋潛','王維','唐','御定全唐诗','yuding','','[]','端笏明光宮，曆稔朝雲陛。詔刊延閣書，高議平津邸。',96,'御定全唐詩/json/125.json','["端笏明光宮，曆稔朝雲陛。詔刊延閣書，高議平津邸。", "適意偶輕人，虛心削繁禮。盛得江左風，彌工建安體。", "高張多絕弦，截河有清濟。嚴冬爽群木，伊洛方清泚。", "渭水冰下流，潼關雪中啟。荷蓧幾時還，塵纓待君洗。"]'),
('yuding-46','晦日游大理韋卿城南別業四聲依次用各六韻','王維','唐','御定全唐诗','yuding','','[]','與世澹無事，自然江海人。側聞塵外游，解驂fL朱輪。',289,'御定全唐詩/json/125.json','["與世澹無事，自然江海人。側聞塵外游，解驂fL朱輪。", "平野照暄景，上天垂春雲。張組竟北阜，泛舟過東鄰。", "故鄉信高會，牢醴及佳辰。幸同擊壤樂，心荷堯為君。", "郊居杜陵下，永日同攜手。仁裏靄川陽，平原見峰首。", "園廬鳴春鳩，林薄媚新柳。上卿始登席，故老前為壽。", "臨當游南陂，約略執杯酒。歸歟絀微官，惆悵心自咎。", "冬中餘雪在，墟上春流駛。風日暢懷抱，山川多秀氣。", "雕胡先晨炊，庖膾亦雲至。高情浪海嶽，浮生寄天地。", "君子外簪纓，埃塵良不啻。所樂衡門中，陶然忘其貴。", "高館臨澄陂，曠然蕩心目。淡蕩動雲天，玲瓏映墟曲。", "鵲巢結空林，雉雊響幽谷。應接無閒暇，徘徊以躑躅。", "紆組上春堤，側弁倚喬木。弦望忽已晦，後期洲應綠。"]'),
('yuding-47','冬日遊覽','王維','唐','御定全唐诗','yuding','','[]','步出城東門，試騁千里目。青山橫蒼林，赤日團平陸。',84,'御定全唐詩/json/125.json','["步出城東門，試騁千里目。青山橫蒼林，赤日團平陸。", "渭北走邯鄲，關東出函穀。秦地萬方會，來朝九州牧。", "雞鳴咸陽中，冠蓋相追逐。丞相過列侯，群公餞光祿。", "相如方老病，獨歸茂陵宿。"]'),
('yuding-48','華岳','王維','唐','御定全唐诗','yuding','','[]','西嶽出浮雲，積雪在太清。連天凝黛色，百里遙青冥。',120,'御定全唐詩/json/125.json','["西嶽出浮雲，積雪在太清。連天凝黛色，百里遙青冥。", "白日為之寒，森沉華陰城。昔聞乾坤閉，造化生巨靈。", "右足踏方止，左手推削成。天地忽開拆，大河注東溟。", "遂為西峙嶽，雄雄鎮秦京。大君包覆載，至德被群生。", "上帝佇昭告，金天思奉迎。人祇望幸久，何獨禪雲亭。"]'),
('yuding-49','同盧拾遺過韋給事東山別業二十韻給事首春休沐維已陪遊及乎是行亦預聞命會無車馬不果斯諾','王維','唐','御定全唐诗','yuding','','[]','托身侍雲陛，昧旦趨華軒。遂陪鵷鴻侶，霄漢同飛翻。',240,'御定全唐詩/json/125.json','["托身侍雲陛，昧旦趨華軒。遂陪鵷鴻侶，霄漢同飛翻。", "君子垂惠顧，期我于田園。側聞景龍際，親降南面尊。", "萬乘駐山外，順風祈一言。高陽多夔龍，荊山積璵璠。", "盛德啟前烈，大賢鐘後昆。侍郎文昌宮，給事東掖垣。", "謁帝俱來下，冠蓋盈丘樊。閨風首邦族，庭訓延鄉村。", "埰地包山河，樹井竟川原。岩端回綺檻，穀口開朱門。", "階下群峰首，雲中瀑水源。鳴玉滿春山，列筵先朝暾。", "會舞何颯遝，擊鐘彌朝昏。是時陽和節，清晝猶未暄。", "藹藹樹色深，嚶嚶鳥聲繁。顧己負宿諾，延頸慚芳蓀。", "蹇步守窮巷，高駕難攀援。素是獨往客，脫冠情彌敦。"]'),
('yuding-50','藍田山石門精舍','王維','唐','御定全唐诗','yuding','','[]','落日山水好，漾舟信歸風。探奇不覺遠，因以緣源窮。',144,'御定全唐詩/json/125.json','["落日山水好，漾舟信歸風。探奇不覺遠，因以緣源窮。", "遙愛雲木秀，初疑路不同。安知清流轉，偶與前山通。", "舍舟理輕策，果然愜所適。老僧四五人，逍遙蔭松柏。", "朝梵林未曙，夜禪山更寂。道心及牧童，世事問樵客。", "暝宿長林下，焚香臥瑤席。澗芳襲人衣，山月映石壁。", "再尋畏迷誤，明發更登曆。笑謝桃源人，花紅複來覿。"]'),
('yuding-51','青溪','王維','唐','御定全唐诗','yuding','','[]','言入黃花川，每逐清溪水。隨山將萬轉，趣途無百里。',72,'御定全唐詩/json/125.json','["言入黃花川，每逐清溪水。隨山將萬轉，趣途無百里。", "聲喧亂石中，色靜深松裏。漾漾泛菱荇，澄澄映葭葦。", "我心素已閑，清川澹如此。請留磐石上，垂釣將已矣。"]'),
('yuding-52','崔濮陽兄季重前山興','王維','唐','御定全唐诗','yuding','','[]','秋色有佳興，況君池上閑。悠悠西林下，自識門前山。',72,'御定全唐詩/json/125.json','["秋色有佳興，況君池上閑。悠悠西林下，自識門前山。", "千里橫黛色，數峰出雲間。嵯峨對秦國，合遝藏荊關。", "殘雨斜日照，夕嵐飛鳥還。故人今尚爾，歎息此頹顏。"]'),
('yuding-53','李處士山居','王維','唐','御定全唐诗','yuding','','[]','君子盈天階，小人甘自免。方隨煉金客，林上家絕巘。',48,'御定全唐詩/json/125.json','["君子盈天階，小人甘自免。方隨煉金客，林上家絕巘。", "背嶺花未開，入雲樹深淺。清晝猶自眠，山鳥時一囀。"]'),
('yuding-54','丁田家有贈','王維','唐','御定全唐诗','yuding','','[]','君心尚棲隱，久欲傍歸路。在朝每為言，解印果成趣。',132,'御定全唐詩/json/125.json','["君心尚棲隱，久欲傍歸路。在朝每為言，解印果成趣。", "晨雞鳴鄰里，群動從所務。農夫行餉田，閨妾起縫素。", "開軒禦衣服，散帙理章句。時吟招隱詩，或制閒居賦。", "新晴望郊郭，日映桑榆暮。陰晝小苑城，微明渭川樹。", "揆予宅閭井，幽賞何由屢。道存終不忘，跡異難相遇。", "此時惜離別，再來芳菲度。"]'),
('yuding-55','渭川田家','王維','唐','御定全唐诗','yuding','','[]','斜陽照墟落，窮巷牛羊歸。野老念牧童，倚杖候荊扉。',60,'御定全唐詩/json/125.json','["斜陽照墟落，窮巷牛羊歸。野老念牧童，倚杖候荊扉。", "雉雊麥苗秀，蠶眠桑葉稀。田夫荷鋤至，相見語依依。", "即此羨閒逸，悵然吟式微。"]'),
('yuding-56','春中田園作','王維','唐','御定全唐诗','yuding','','[]','屋上春鳩鳴，村邊杏花白。持斧伐遠揚，荷鋤覘泉脈。',48,'御定全唐詩/json/125.json','["屋上春鳩鳴，村邊杏花白。持斧伐遠揚，荷鋤覘泉脈。", "歸燕識故巢，舊人看新曆。臨觴忽不禦，惆悵遠行客。"]'),
('yuding-57','過李楫宅','王維','唐','御定全唐诗','yuding','','[]','閑門秋草色，終日無車馬。客來深巷中，犬吠寒林下。',60,'御定全唐詩/json/125.json','["閑門秋草色，終日無車馬。客來深巷中，犬吠寒林下。", "散發時未簪，道書行尚把。與我同心人，樂道安貧者。", "一罷宜城酌，還歸洛陽社。"]'),
('yuding-58','韋侍郎山居','王維','唐','御定全唐诗','yuding','','[]','幸忝君子顧，遂陪塵外蹤。閑花滿岩谷，瀑水映杉松。',72,'御定全唐詩/json/125.json','["幸忝君子顧，遂陪塵外蹤。閑花滿岩谷，瀑水映杉松。", "啼鳥忽歸澗，歸雲時抱峰。良游盛簪紱，繼跡多夔龍。", "詎枉青門道，胡聞長樂鐘。清晨去朝謁，車馬何從容。"]'),
('yuding-59','飯覆釜山僧','王維','唐','御定全唐诗','yuding','','[]','晚知清淨理，日與人群疏。將候遠山僧，先期掃弊廬。',84,'御定全唐詩/json/125.json','["晚知清淨理，日與人群疏。將候遠山僧，先期掃弊廬。", "果從雲峰裏，顧我蓬蒿居。藉草飯松屑，焚香看道書。", "然燈晝欲盡，鳴磬夜方初。一悟寂為樂，此日閑有餘。", "思歸何必深，身世猶空虛。"]'),
('yuding-60','謁璿上人','王維','唐','御定全唐诗','yuding','','[]','少年不足言，識道年已長。事往安可悔，餘生幸能養。',120,'御定全唐詩/json/125.json','["少年不足言，識道年已長。事往安可悔，餘生幸能養。", "誓從斷臂血，不復嬰世網。浮名寄纓佩，空性無羈鞅。", "夙承大導師，焚香此瞻仰。頹然居一室，覆載紛萬象。", "高柳早鶯啼，長廊春雨響。床下阮家屐，窗前筇竹杖。", "方將見身雲，陋彼示天壤。一心在法要，願以無生獎。"]'),
('yuding-61','瓜園詩','王維','唐','御定全唐诗','yuding','','[]','餘適欲鋤瓜，倚鋤聽叩門。鳴騶導驄馬，常從夾朱軒。',132,'御定全唐詩/json/125.json','["餘適欲鋤瓜，倚鋤聽叩門。鳴騶導驄馬，常從夾朱軒。", "窮巷正傳呼，故人儻相存。攜手追涼風，放心望乾坤。", "藹藹帝王州，宮觀一何繁。林端出綺道，殿頂搖華幡。", "素懷在青山，若值白雲屯。回風城西雨，返景原上村。", "前酌盈尊酒，往往聞清言。黃鸝囀深木，朱槿照中園。", "猶羨松下客，石上聞清猿。"]'),
('yuding-62','自大散以往深林密竹磴道盤曲四五十裏至黃牛嶺見黃花川','王維','唐','御定全唐诗','yuding','','[]','危徑幾萬轉，數裏將三休。回環見徒侶，隱映隔林丘。',84,'御定全唐詩/json/125.json','["危徑幾萬轉，數裏將三休。回環見徒侶，隱映隔林丘。", "颯颯松上雨，潺潺石中流。靜言深溪裏，長嘯高山頭。", "望見南山陽，白露靄悠悠。青皋麗已淨，綠樹鬱如浮。", "曾是厭蒙密，曠然銷人憂。"]'),
('yuding-63','新晴野望','王維','唐','御定全唐诗','yuding','','[]','新晴原野曠，極目無氛垢。郭門臨渡頭，村樹連溪口。',48,'御定全唐詩/json/125.json','["新晴原野曠，極目無氛垢。郭門臨渡頭，村樹連溪口。", "白水明田外，碧峰出山后。農月無閒人，傾家事南畝。"]'),
('yuding-64','宿鄭州','王維','唐','御定全唐诗','yuding','','[]','朝與周人辭，暮投鄭人宿。他鄉絕儔侶，孤客親僮僕。',96,'御定全唐詩/json/125.json','["朝與周人辭，暮投鄭人宿。他鄉絕儔侶，孤客親僮僕。", "宛洛望不見，秋霖晦平陸。田父草際歸，村童雨中牧。", "主人東皋上，時稼繞茅屋。蟲思機杼悲，雀喧禾黍熟。", "明當渡京水，昨晚猶金穀。此去欲何言，窮邊徇微祿。"]'),
('yuding-65','早入滎陽界','王維','唐','御定全唐诗','yuding','','[]','泛舟入滎澤，茲邑乃雄藩。河曲閭閻隘，川中煙火繁。',72,'御定全唐詩/json/125.json','["泛舟入滎澤，茲邑乃雄藩。河曲閭閻隘，川中煙火繁。", "因人見風俗，入境聞方言。秋野田疇盛，朝光市井喧。", "漁商波上客，雞犬岸旁村。前路白雲外，孤帆安可論。"]'),
('yuding-66','渡河到清河作','王維','唐','御定全唐诗','yuding','','[]','泛舟大河裏，積水窮天涯。天波忽開拆，郡邑千萬家。',48,'御定全唐詩/json/125.json','["泛舟大河裏，積水窮天涯。天波忽開拆，郡邑千萬家。", "行複見城市，宛然有桑麻。回瞻舊鄉國，淼漫連雲霞。"]'),
('yuding-67','苦熱','王維','唐','御定全唐诗','yuding','','[]','赤日滿天地，火雲成山嶽。草木盡焦卷，川澤皆竭涸。',96,'御定全唐詩/json/125.json','["赤日滿天地，火雲成山嶽。草木盡焦卷，川澤皆竭涸。", "輕紈覺衣重，密樹苦陰薄。莞簟不可近，絺綌再三濯。", "思出宇宙外，曠然在寥廓。長風萬里來，江海蕩煩濁。", "卻顧身為患，始知心未覺。忽入甘露門，宛然清涼樂。"]'),
('yuding-68','納涼','王維','唐','御定全唐诗','yuding','','[]','喬木萬餘株，清流貫其中。前臨大川口，豁達來長風。',72,'御定全唐詩/json/125.json','["喬木萬餘株，清流貫其中。前臨大川口，豁達來長風。", "漣漪涵白沙，素鮪如遊空。偃臥磐石上，翻濤沃微躬。", "漱流複濯足，前對釣魚翁。貪餌凡幾許，徒思蓮葉東。"]'),
('yuding-69','西施詠','王維','唐','御定全唐诗','yuding','','[]','豔色天下重，西施寧久微。朝仍越溪女，暮作吳宮妃。',84,'御定全唐詩/json/125.json','["豔色天下重，西施寧久微。朝仍越溪女，暮作吳宮妃。", "賤日豈殊眾，貴來方悟稀。邀人傅香粉，不自著羅衣。", "君寵益嬌態，君憐無是非。當時浣紗伴，莫得同車歸。", "持謝鄰家子，效顰安可希。"]'),
('yuding-70','李陵詠','王維','唐','御定全唐诗','yuding','','[]','漢家李將軍，三代將門子。結髮有奇策，少年成壯士。',120,'御定全唐詩/json/125.json','["漢家李將軍，三代將門子。結髮有奇策，少年成壯士。", "長驅塞上兒，深入單于壘。旌旗列相向，簫鼓悲何已。", "日暮沙漠陲，戰聲煙塵裏。將令驕虜滅，豈獨名王侍。", "既失大軍援，遂嬰穹廬恥。少小蒙漢恩，何堪坐思此。", "深衷欲有報，投軀未能死。引領望子卿，非君誰相理。"]'),
('yuding-71','濟上四賢詠：崔錄事','王維','唐','御定全唐诗','yuding','','[]','解印歸田裏，賢哉此丈夫。少年曾任俠，晚節更為儒。',48,'御定全唐詩/json/125.json','["解印歸田裏，賢哉此丈夫。少年曾任俠，晚節更為儒。", "遁跡東山下，因家滄海隅。已聞能狎鳥，餘欲共乘桴。"]'),
('yuding-72','濟上四賢詠：成文學','王維','唐','御定全唐诗','yuding','','[]','寶劍千金裝，登君白玉堂。身為平原客，家有邯鄲娼。',48,'御定全唐詩/json/125.json','["寶劍千金裝，登君白玉堂。身為平原客，家有邯鄲娼。", "使氣公卿坐，論心遊俠場。中年不得意，謝病客游梁。"]'),
('yuding-73','濟上四賢詠：鄭霍二山人','王維','唐','御定全唐诗','yuding','','[]','翩翩繁華子，多出金張門。幸有先人業，早蒙明主恩。',96,'御定全唐詩/json/125.json','["翩翩繁華子，多出金張門。幸有先人業，早蒙明主恩。", "童年且未學，肉食騖華軒。豈乏中林士，無人薦至尊。", "鄭公老泉石，霍子安丘樊。賣藥不二價，著書盈萬言。", "息陰無惡木，飲水必清源。吾賤不及議，斯人竟誰論。"]'),
('yuding-74','過太乙觀賈生房','王維','唐','御定全唐诗','yuding','','[]','昔餘棲遁日，之子煙霞鄰。共攜松葉酒，俱篸竹皮巾。',96,'御定全唐詩/json/125.json','["昔餘棲遁日，之子煙霞鄰。共攜松葉酒，俱篸竹皮巾。", "攀林遍岩洞，采藥無冬春。謬以道門子，征為驂禦臣。", "常恐丹液就，先我紫陽賓。夭促萬塗盡，哀傷百慮新。", "跡峻不容俗，才多反累真。泣對雙泉水，還山無主人。"]'),
('yuding-75','燕子龕禪師','王維','唐','御定全唐诗','yuding','','[]','山中燕子龕，路劇羊腸惡。裂地競盤屈，插天多峭崿。',204,'御定全唐詩/json/125.json','["山中燕子龕，路劇羊腸惡。裂地競盤屈，插天多峭崿。", "瀑泉吼而噴，怪石看欲落。伯禹訪未知，五丁愁不鑿。", "上人無生緣，生長居紫閣。六時自搥磬，一飲常帶索。", "種田燒白雲，斫漆響丹壑。行隨拾栗猿，歸對巢松鶴。", "時許山神請，偶逢洞仙博。救世多慈悲，即心無行作。", "周商倦積阻，蜀物多淹泊。岩腹乍旁穿，澗唇時外拓。", "橋因倒樹架，柵值垂藤縛。鳥道悉已平，龍宮為之涸。", "跳波誰揭厲，絕壁免捫摸。山木日陰陰，結跏歸舊林。", "一向石門裏，任君春草深。"]'),
('yuding-76','羽林騎閨人','王維','唐','御定全唐诗','yuding','','[]','秋月臨高城，城中管弦思。離人堂上愁，稚子階前戲。',60,'御定全唐詩/json/125.json','["秋月臨高城，城中管弦思。離人堂上愁，稚子階前戲。", "出門複映戶，望望青絲騎。行人過欲盡，狂夫終不至。", "左右寂無言，相看共垂淚。"]'),
('yuding-77','偶然作六首','王維','唐','御定全唐诗','yuding','','[]','楚國有狂夫，茫然無心想。散發不冠帶，行歌南陌上。',528,'御定全唐詩/json/125.json','["楚國有狂夫，茫然無心想。散發不冠帶，行歌南陌上。", "孔丘與之言，仁義莫能獎。未嘗肯問天，何事須擊壤。", "複笑采薇人，胡為乃長往。", "田舍有老翁，垂白衡門裏。有時農事閑，鬥酒呼鄰里。", "喧聒茅簷下，或坐或複起。短褐不為薄，園葵固足美。", "動則長子孫，不曾向城市。五帝與三王，古來稱天子。", "干戈將揖讓，畢竟何者是。得意苟為樂，野田安足鄙。", "且當放懷去，行行沒餘齒。", "日夕見太行，沉吟未能去。問君何以然，世網嬰我故。", "小妹日成長，兄弟未有娶。家貧祿既薄，儲蓄非有素。", "幾回欲奮飛，踟躕複相顧。孫登長嘯台，松竹有遺處。", "相去詎幾許，故人在中路。愛染日已薄，禪寂日已固。", "忽乎吾將行，寧俟歲雲暮。", "陶潛任天真，其性頗耽酒。自從棄官來，家貧不能有。", "九月九日時，菊花空滿手。中心竊自思，儻有人送否。", "白衣攜壺觴，果來遺老叟。且喜得斟酌，安問升與鬥。", "奮衣野田中，今日嗟無負。兀傲迷東西，蓑笠不能守。", "傾倒強行行，酣歌歸五柳。生事不曾問，肯愧家中婦。", "趙女彈箜篌，複能邯鄲舞。夫婿輕薄兒，鬥雞事齊主。", "黃金買歌笑，用錢不複數。許史相經過，高門盈四牡。", "客舍有儒生，昂藏出鄒魯。讀書三十年，腰間無尺組。", "被服聖人教，一生自窮苦。", "老來懶賦詩，惟有老相隨。宿世謬詞客，前身應畫師。", "不能舍余習，偶被世人知。名字本皆是，此心還不知。"]'),
('yuding-78','《寓言二首','王維','唐','御定全唐诗','yuding','','[]','朱紱誰家子，無乃金張孫。驪駒從白馬，出入銅龍門。',120,'御定全唐詩/json/125.json','["朱紱誰家子，無乃金張孫。驪駒從白馬，出入銅龍門。", "問爾何功德，多承明主恩。鬥雞平樂館，射雉上林園。", "曲陌車騎盛，高堂珠翠繁。奈何軒冕貴，不與布衣言。", "君家禦溝上，垂柳夾朱門。列鼎會中貴，鳴珂朝至尊。", "生死在八議，窮達由一言。須識苦寒士，莫矜狐白溫。"]'),
('yuding-79','冬夜書懷','王維','唐','御定全唐诗','yuding','','[]','冬宵寒且永，夜漏宮中發。草白靄繁霜，木衰澄清月。',48,'御定全唐詩/json/125.json','["冬宵寒且永，夜漏宮中發。草白靄繁霜，木衰澄清月。", "麗服映頹顏，朱燈照華髮。漢家方尚少，顧影慚朝謁。"]'),
('yuding-80','送康太守','王維','唐','御定全唐诗','yuding','','[]','城下滄江水，江邊黃鶴樓。朱闌將粉堞，江水映悠悠。',60,'御定全唐詩/json/125.json','["城下滄江水，江邊黃鶴樓。朱闌將粉堞，江水映悠悠。", "鐃吹發夏口，使君居上頭。郭門隱楓岸，候吏趨蘆洲。", "何異臨川郡，還勞康樂侯。"]'),
('yuding-81','送權二','王維','唐','御定全唐诗','yuding','','[]','高人不可有，清論複何深。一見如舊識，一言知道心。',72,'御定全唐詩/json/125.json','["高人不可有，清論複何深。一見如舊識，一言知道心。", "明時當薄宦，解薜去中林。芳草空隱處，白雲餘故岑。", "韓侯久攜手，河嶽共幽尋。悵別千餘裏，臨堂鳴素琴。"]'),
('yuding-82','休假還舊業便使','王維','唐','御定全唐诗','yuding','','[]','謝病始告歸，依依入桑梓。家人皆佇立，相候衡門裏。',108,'御定全唐詩/json/125.json','["謝病始告歸，依依入桑梓。家人皆佇立，相候衡門裏。", "時輩皆長年，成人舊童子。上堂嘉慶畢，顧與姻親齒。", "論舊忽餘悲，目存且相喜。田園轉蕪沒，但有寒泉水。", "衰柳日蕭條，秋光清邑裏。入門乍如客，休騎非便止。", "中飲顧王程，離憂從此始。"]'),
('yuding-83','歎白髮','王維','唐','御定全唐诗','yuding','','[]','我年一何長，鬢髮日已白。俯仰天地間，能為幾時客。',48,'御定全唐詩/json/125.json','["我年一何長，鬢髮日已白。俯仰天地間，能為幾時客。", "惆悵故山雲，徘徊空日夕。何事與時人，東城複南陌。"]'),
('yuding-84','別弟妹二首','王維','唐','御定全唐诗','yuding','','[]','兩妹日成長，雙鬟將及人。已能持寶瑟，自解掩羅巾。',96,'御定全唐詩/json/125.json','["兩妹日成長，雙鬟將及人。已能持寶瑟，自解掩羅巾。", "念昔別時小，未知疏與親。今來始離恨，拭淚方殷勤。", "小弟更孩幼，歸來不相識。同居雖漸慣，見人猶未覓。", "宛作越人語，殊甘水鄉食。別此最為難，淚盡有餘憶。"]'),
('yuding-85','哭殷遙','王維','唐','御定全唐诗','yuding','','[]','人生能幾何，畢竟歸無形。念君等為死，萬事傷人情。',120,'御定全唐詩/json/125.json','["人生能幾何，畢竟歸無形。念君等為死，萬事傷人情。", "慈母未及葬，一女才十齡。泱漭寒郊外，蕭條聞哭聲。", "浮雲為蒼茫，飛鳥不能鳴。行人何寂寞，白日自淒清。", "憶昔君在時，問我學無生。勸君苦不早，令君無所成。", "故人各有贈，又不及生平。負爾非一途，慟哭返柴荊。"]'),
('yuding-86','故南陽夫人樊氏挽歌','王維','唐','御定全唐诗','yuding','','[]','石窌恩榮重，金吾車騎盛。將朝每贈言，入室還相敬。',48,'御定全唐詩/json/125.json','["石窌恩榮重，金吾車騎盛。將朝每贈言，入室還相敬。", "疊鼓秋城動，懸旌寒日映。不言長不歸，環佩猶將聽。"]'),
('yuding-87','夷門歌','王維','唐','御定全唐诗','yuding','','[]','七雄雄雌猶未分，攻城殺將何紛紛。秦兵益圍邯鄲急，',48,'御定全唐詩/json/125.json','["七雄雄雌猶未分，攻城殺將何紛紛。秦兵益圍邯鄲急，", "亥為屠肆鼓刀人，嬴乃夷門抱關者。非但慷慨獻良謀，"]'),
('yuding-88','隴頭吟','王維','唐','御定全唐诗','yuding','','[]','長安少年游俠客，夜上戍樓看太白。隴頭明月迥臨關，',48,'御定全唐詩/json/125.json','["長安少年游俠客，夜上戍樓看太白。隴頭明月迥臨關，", "身經大小百餘戰，麾下偏裨萬戶侯。蘇武才為典屬國，"]'),
('yuding-89','老將行','王維','唐','御定全唐诗','yuding','','[]','少年十五二十時，步行奪得胡馬騎。射殺中山白額虎，',120,'御定全唐詩/json/125.json','["少年十五二十時，步行奪得胡馬騎。射殺中山白額虎，", "漢兵奮迅如霹靂，虜騎崩騰畏蒺藜。衛青不敗由天幸，", "昔時飛箭無全目，今日垂楊生左肘。路傍時賣故侯瓜，", "誓令疏勒出飛泉，不似潁川空使酒。賀蘭山下陣如雲，", "試拂鐵衣如雪色，聊持寶劍動星文。願得燕弓射天將，"]'),
('yuding-90','燕支行','王維','唐','御定全唐诗','yuding','','[]','漢家天將才且雄，來時謁帝明光宮。萬乘親推雙闕下，',96,'御定全唐詩/json/125.json','["漢家天將才且雄，來時謁帝明光宮。萬乘親推雙闕下，", "衛霍才堪一騎將，朝廷不數貳師功。趙魏燕韓多勁卒，", "畫戟雕戈百白寒，連旗大旆黃塵沒。疊鼓遙翻瀚海波，", "拔劍已斷天驕臂，歸鞍共飲月支頭。漢兵大呼一當百，"]'),
('yuding-91','桃源行','王維','唐','御定全唐诗','yuding','','[]','漁舟逐水愛山春，兩岸桃花夾去津。坐看紅樹不知遠，',136,'御定全唐詩/json/125.json','["漁舟逐水愛山春，兩岸桃花夾去津。坐看紅樹不知遠，", "遙看一處攢雲樹，近入千家散花竹。樵客初傳漢姓名，", "月明松下房櫳靜，日出雲中雞犬喧。驚聞俗客爭來集，", "初因避地去人間，及至成仙遂不還。峽裏誰知有人事，", "出洞無論隔山水，辭家終擬長遊衍。自謂經過舊不迷，", "春來遍是桃花水，不辨仙源何處尋。"]'),
('yuding-92','洛陽女兒行','王維','唐','御定全唐诗','yuding','','[]','洛陽女兒對門居，才可容顏十五餘。良人玉勒乘驄馬，',88,'御定全唐詩/json/125.json','["洛陽女兒對門居，才可容顏十五餘。良人玉勒乘驄馬，", "羅幃送上七香車，寶扇迎歸九華帳。狂夫富貴在青春，", "春窗曙滅九微火，九微片片飛花瑣。戲罷曾無理曲時，", "誰憐越女顏如玉，貧賤江頭自浣紗。"]'),
('yuding-93','同崔傅答賢弟','王維','唐','御定全唐诗','yuding','','[]','洛陽才子姑蘇客，桂苑殊非故鄉陌。九江楓樹幾回青，',72,'御定全唐詩/json/125.json','["洛陽才子姑蘇客，桂苑殊非故鄉陌。九江楓樹幾回青，", "夜火人歸富春郭，秋風鶴唳石頭城。周郎陸弟為儔侶，", "衣冠若話外台臣，先數夫君席上珍。更聞台閣求三語，"]'),
('yuding-94','贈吳官','王維','唐','御定全唐诗','yuding','','[]','長安客舍熱如煮，無個茗糜難禦暑。空搖白團其諦苦，',40,'御定全唐詩/json/125.json','["長安客舍熱如煮，無個茗糜難禦暑。空搖白團其諦苦，", "不如儂家任挑達，草屩撈蝦富春渚。"]'),
('yuding-95','故人張諲工詩善易蔔兼能丹青草隸頃以詩見贈聊獲酬之','王維','唐','御定全唐诗','yuding','','[]','不逐城東遊俠兒，隱囊紗帽坐彈棋。蜀中夫子時開卦，',48,'御定全唐詩/json/125.json','["不逐城東遊俠兒，隱囊紗帽坐彈棋。蜀中夫子時開卦，", "屏風誤點惑孫郎，團扇草書輕內史。故園高枕度三春，"]'),
('yuding-96','送崔五太守','王維','唐','御定全唐诗','yuding','','[]','長安廄吏來到門，朱文露網動行軒。黃花縣西九折阪，',72,'御定全唐詩/json/125.json','["長安廄吏來到門，朱文露網動行軒。黃花縣西九折阪，", "子午山裏杜鵑啼，嘉陵水頭行客飯。劍門忽斷蜀川開，", "使君年紀三十餘，少年白皙專城居。欲持畫省郎官筆，"]'),
('yuding-97','寒食城東即事','王維','唐','御定全唐诗','yuding','','[]','清溪一道穿桃李，演漾綠蒲涵白芷。溪上人家凡幾家，',40,'御定全唐詩/json/125.json','["清溪一道穿桃李，演漾綠蒲涵白芷。溪上人家凡幾家，", "少年分日作遨遊，不用清明兼上巳。"]'),
('yuding-98','不遇詠','王維','唐','御定全唐诗','yuding','','[]','北闕獻書寢不報，南山種田時不登。百人會中身不預，',48,'御定全唐詩/json/125.json','["北闕獻書寢不報，南山種田時不登。百人會中身不預，", "且此登山複臨水，莫問春風動楊柳。今人昨人多自私，"]'),
('yuding-99','贈裴迪','王維','唐','御定全唐诗','yuding','','[]','不相見，不相見來久。日日泉水頭，常憶同攜手。',46,'御定全唐詩/json/125.json','["不相見，不相見來久。日日泉水頭，常憶同攜手。", "攜手本同心，複歎忽分襟。相憶今如此，相思深不深。"]'),
('yuding-100','青雀歌','王維','唐','御定全唐诗','yuding','','[]','青雀翅羽短，未能遠食玉山禾。',30,'御定全唐詩/json/125.json','["青雀翅羽短，未能遠食玉山禾。", "猶勝黃雀爭上下，唧唧空倉複若何。"]'),
('yuding-101','黃雀癡','王維','唐','御定全唐诗','yuding','','[]','黃雀癡，黃雀癡，謂言青鷇是我兒。一一口銜食，',42,'御定全唐詩/json/125.json','["黃雀癡，黃雀癡，謂言青鷇是我兒。一一口銜食，", "薄暮空巢上，羈雌獨自歸。鳳凰九雛亦如此，"]'),
('yuding-102','新秦郡松樹歌','王維','唐','御定全唐诗','yuding','','[]','青青山上松，數裏不見今更逢。不見君，心相憶，',22,'御定全唐詩/json/125.json','["青青山上松，數裏不見今更逢。不見君，心相憶，"]'),
('yuding-103','榆林郡歌','王維','唐','御定全唐诗','yuding','','[]','山頭松柏林，山下泉聲傷客心。千里萬里春草色，',22,'御定全唐詩/json/125.json','["山頭松柏林，山下泉聲傷客心。千里萬里春草色，"]'),
('yuding-104','問寇校書雙溪','王維','唐','御定全唐诗','yuding','','[]','君家少室西，為複少室東，別來幾日今春風。',36,'御定全唐詩/json/125.json','["君家少室西，為複少室東，別來幾日今春風。", "新買雙溪定何似，餘生欲寄白雲中。"]'),
('yuding-105','寄崇梵僧','王維','唐','御定全唐诗','yuding','','[]','崇梵僧，崇梵僧，秋歸覆釜春不還。落花啼鳥紛紛亂，',24,'御定全唐詩/json/125.json','["崇梵僧，崇梵僧，秋歸覆釜春不還。落花啼鳥紛紛亂，"]'),
('yuding-106','同比部楊員外十五夜遊有懷靜者季','王維','唐','御定全唐诗','yuding','','[]','承明少休沐，建禮省文書。夜漏行人息，歸鞍落日餘。',112,'御定全唐詩/json/125.json','["承明少休沐，建禮省文書。夜漏行人息，歸鞍落日餘。", "懸知三五夕，萬戶千門辟。夜出曙翻歸，傾城滿南陌。", "陌頭馳騁盡繁華，王孫公子五侯家。由來月明如白日，", "香車寶馬共喧闐，個裏多情俠少年。競向長楊柳市北，", "儻覺忘懷共往來，幸沾同舍甘藜藿。"]'),
('yuding-107','答張五弟','王維','唐','御定全唐诗','yuding','','[]','終南有茅屋，前對終南山。終年無客常閉關，',20,'御定全唐詩/json/125.json','["終南有茅屋，前對終南山。終年無客常閉關，"]'),
('yuding-108','雪中憶李楫','王維','唐','御定全唐诗','yuding','','[]','積雪滿阡陌，故人不可期。長安千門複萬戶，',20,'御定全唐詩/json/125.json','["積雪滿阡陌，故人不可期。長安千門複萬戶，"]'),
('yuding-109','送李睢陽','王維','唐','御定全唐诗','yuding','','[]','將置酒，思悲翁。使君去，出城東。麥漸漸，雉子斑。',116,'御定全唐詩/json/125.json','["將置酒，思悲翁。使君去，出城東。麥漸漸，雉子斑。", "槐陰陰，到潼關。騎連連，車遲遲。心中悲，宋又遠。", "周間之，南淮夷。東齊兒，碎碎織練與素絲，", "天子當殿儼衣裳，大官尚食陳羽觴。彤庭散綬垂鳴璫，", "鸞聲噦噦魯侯旗，明年上計朝京師。須憶今日鬥酒別，"]'),
('yuding-110','奉和聖制天長節賜宰臣歌應制','王維','唐','御定全唐诗','yuding','','[]','太陽升兮照萬方，開閶闔兮臨玉堂，儼冕旒兮垂衣裳。',64,'御定全唐詩/json/125.json','["太陽升兮照萬方，開閶闔兮臨玉堂，儼冕旒兮垂衣裳。", "金天淨兮麗三光，彤庭曙兮延八荒。德合天兮禮神遍，", "盡九服兮皆四鄰，幹降瑞兮坤降珍。"]'),
('yuding-111','登樓歌','王維','唐','御定全唐诗','yuding','','[]','聊上君兮高樓，飛甍鱗次兮在下。俯十二兮通衢，',101,'御定全唐詩/json/125.json','["聊上君兮高樓，飛甍鱗次兮在下。俯十二兮通衢，", "王畿鬱兮千里，山河壯兮咸秦。舍人下兮青宮，", "亦幸有張伯英草聖兮龍騰虯躍，擺長雲兮捩回風。", "琥珀酒兮雕胡飯，君不禦兮日將晚。秋風兮吹衣，", "時不可兮再得，君何為兮偃蹇。"]'),
('yuding-112','雙黃鵠歌送別','王維','唐','御定全唐诗','yuding','','[]','天路來兮雙黃鵠，雲上飛兮水上宿，撫翼和鳴整羽族。',87,'御定全唐詩/json/125.json','["天路來兮雙黃鵠，雲上飛兮水上宿，撫翼和鳴整羽族。", "不得已，忽分飛，家在玉京朝紫微，主人臨水送將歸。", "悲笳嘹唳垂舞衣，賓欲散兮複相依。幾往返兮極浦，", "鞍馬歸兮佳人散，悵離憂兮獨含情。"]'),
('yuding-113','贈徐中書望終南山歌','王維','唐','御定全唐诗','yuding','','[]','晚下兮紫微，悵塵事兮多違。',26,'御定全唐詩/json/125.json','["晚下兮紫微，悵塵事兮多違。", "駐馬兮雙樹，望青山兮不歸。"]'),
('yuding-114','送友人歸山歌二首','王維','唐','御定全唐诗','yuding','','[]','山寂寂兮無人，又蒼蒼兮多木。群龍兮滿朝，',106,'御定全唐詩/json/125.json','["山寂寂兮無人，又蒼蒼兮多木。群龍兮滿朝，", "悅石上兮流泉，與松間兮草屋。入雲中兮養雞，", "愧不才兮妨賢，嫌既老兮貪祿。誓解印兮相從，", "山中人兮欲歸，雲冥冥兮雨霏霏。水驚波兮翠菅蘼，", "忽山西兮夕陽，見東皋兮遠村。平蕪綠兮千里，"]'),
('yuding-115','魚山神女祠歌：迎神','王維','唐','御定全唐诗','yuding','','[]','坎坎擊鼓，魚山之下。吹洞簫，望極浦。女巫進，',22,'御定全唐詩/json/125.json','["坎坎擊鼓，魚山之下。吹洞簫，望極浦。女巫進，"]'),
('yuding-116','魚山神女祠歌：送神','王維','唐','御定全唐诗','yuding','','[]','紛進舞兮堂前，目眷眷兮瓊筵。來不言兮意不傳，',37,'御定全唐詩/json/125.json','["紛進舞兮堂前，目眷眷兮瓊筵。來不言兮意不傳，", "倏雲收兮雨歇，山青青兮水潺湲。"]'),
('yuding-117','白黿渦','王維','唐','御定全唐诗','yuding','','[]','南山之瀑水兮，激石滈瀑似雷驚，人相對兮不聞語聲。',65,'御定全唐詩/json/125.json','["南山之瀑水兮，激石滈瀑似雷驚，人相對兮不聞語聲。", "翻渦跳沫兮蒼苔濕，蘚老且厚，春草為之不生。", "獸不敢驚動，鳥不敢飛鳴。白黿渦濤戲瀨兮，"]'),
('yuding-118','宋進馬哀詞','王維','唐','御定全唐诗','yuding','','[]','背春涉夏兮，眾木藹以繁陰。連金華與玉堂兮，',154,'御定全唐詩/json/125.json','["背春涉夏兮，眾木藹以繁陰。連金華與玉堂兮，", "僕夫命駕兮，出閶闔，曆通逵。陌上人兮如故，", "低光垂彩兮，怳不知其所之。辟朱戶兮望華軒，", "仰訴天之不仁兮，家唯一身，身止一子，何胤嗣之不繁，", "哀從中兮不可勝，豈暇料餘年兮複幾。日黯黯兮頹曄，", "靜言思兮永絕，複驚叫兮沾衣。客有吊之者曰：", "觀未始兮有物，同委蛻兮胡悲？且延陵兮未至，"]'),
('yuding-0','奉和聖制賜史供奉曲江宴應制','王維','唐','御定全唐诗','yuding','','[]','侍從有鄒枚，瓊筵就水開。言陪柏梁宴，新下建章來。',48,'御定全唐詩/json/126.json','["侍從有鄒枚，瓊筵就水開。言陪柏梁宴，新下建章來。", "對酒山河滿，移舟草樹回。天文同麗日，駐景惜行杯。"]'),
('yuding-1','從岐王過楊氏別業應教','王維','唐','御定全唐诗','yuding','','[]','楊子談經所，淮王載酒過。興闌啼鳥換，坐久落花多。',48,'御定全唐詩/json/126.json','["楊子談經所，淮王載酒過。興闌啼鳥換，坐久落花多。", "徑轉回銀燭，林開散玉珂。嚴城時未啟，前路擁笙歌。"]'),
('yuding-2','從岐王夜宴衛家山池應教','王維','唐','御定全唐诗','yuding','','[]','座客香貂滿，宮娃綺幔張。澗花輕粉色，山月少燈光。',48,'御定全唐詩/json/126.json','["座客香貂滿，宮娃綺幔張。澗花輕粉色，山月少燈光。", "積翠紗窗暗，飛泉繡戶涼。還將歌舞出，歸路莫愁長。"]'),
('yuding-3','早朝','王維','唐','御定全唐诗','yuding','','[]','柳暗百花明，春深五鳳城。城烏睥睨曉，宮井轆轤聲。',48,'御定全唐詩/json/126.json','["柳暗百花明，春深五鳳城。城烏睥睨曉，宮井轆轤聲。", "方朔金門侍，班姬玉輦迎。仍聞遣方士，東海訪蓬瀛。"]'),
('yuding-4','同崔員外秋宵寓直','王維','唐','御定全唐诗','yuding','','[]','建禮高秋夜，承明候曉過。九門寒漏徹，萬井曙鐘多。',48,'御定全唐詩/json/126.json','["建禮高秋夜，承明候曉過。九門寒漏徹，萬井曙鐘多。", "月迥藏珠鬥，雲消出絳河。更慚衰朽質，南陌共鳴珂。"]'),
('yuding-5','輞川閒居贈裴秀才迪','王維','唐','御定全唐诗','yuding','','[]','寒山轉蒼翠，秋水日潺湲。倚杖柴門外，臨風聽暮蟬。',48,'御定全唐詩/json/126.json','["寒山轉蒼翠，秋水日潺湲。倚杖柴門外，臨風聽暮蟬。", "渡頭餘落日，墟裏上孤煙。複值接輿醉，狂歌五柳前。"]'),
('yuding-6','寄荊州張丞相','王維','唐','御定全唐诗','yuding','','[]','所思竟何在，悵望深荊門。舉世無相識，終身思舊恩。',48,'御定全唐詩/json/126.json','["所思竟何在，悵望深荊門。舉世無相識，終身思舊恩。", "方將與農圃，藝植老丘園。目盡南飛雁，何由寄一言。"]'),
('yuding-7','冬晚對雪憶胡居士家','王維','唐','御定全唐诗','yuding','','[]','寒更傳曉箭，清鏡覽衰顏。隔牖風驚竹，開門雪滿山。',48,'御定全唐詩/json/126.json','["寒更傳曉箭，清鏡覽衰顏。隔牖風驚竹，開門雪滿山。", "灑空深巷靜，積素廣庭閑。借問袁安舍，翛然尚閉關。"]'),
('yuding-8','和尹諫議史館山池','王維','唐','御定全唐诗','yuding','','[]','雲館接天居，霓裳侍玉除。春池百子外，芳樹萬年餘。',48,'御定全唐詩/json/126.json','["雲館接天居，霓裳侍玉除。春池百子外，芳樹萬年餘。", "洞有仙人籙，山藏太史書。君恩深漢帝，且莫上空虛。"]'),
('yuding-9','奉和楊駙馬六郎秋夜即事','王維','唐','御定全唐诗','yuding','','[]','高樓月似霜，秋夜郁金堂。對坐彈盧女，同看舞鳳凰。',48,'御定全唐詩/json/126.json','["高樓月似霜，秋夜郁金堂。對坐彈盧女，同看舞鳳凰。", "少兒多送酒，小玉更焚香。結束平陽騎，明朝入建章。"]'),
('yuding-10','酬虞部蘇員外過藍田別業不見留之作','王維','唐','御定全唐诗','yuding','','[]','貧居依谷口，喬木帶荒村。石路枉回駕，山家誰候門。',48,'御定全唐詩/json/126.json','["貧居依谷口，喬木帶荒村。石路枉回駕，山家誰候門。", "漁舟膠凍浦，獵火燒寒原。唯有白雲外，疏鐘聞夜猿。"]'),
('yuding-11','酬比部楊員外暮宿琴台朝躋書閣率爾見贈之作','王維','唐','御定全唐诗','yuding','','[]','舊簡拂塵看，鳴琴候月彈。桃源迷漢姓，松樹有秦官。',48,'御定全唐詩/json/126.json','["舊簡拂塵看，鳴琴候月彈。桃源迷漢姓，松樹有秦官。", "空穀歸人少，青山背日寒。羨君棲隱處，遙望白雲端。"]'),
('yuding-12','酬嚴少尹徐舍人見過不遇','王維','唐','御定全唐诗','yuding','','[]','公門暇日少，窮巷故人稀。偶值乘籃輿，非關避白衣。',48,'御定全唐詩/json/126.json','["公門暇日少，窮巷故人稀。偶值乘籃輿，非關避白衣。", "不知炊黍谷，誰解掃荊扉。君但傾茶碗，無妨騎馬歸。"]'),
('yuding-13','酬張少府','王維','唐','御定全唐诗','yuding','','[]','晚年唯好靜，萬事不關心。自顧無長策，空知返舊林。',48,'御定全唐詩/json/126.json','["晚年唯好靜，萬事不關心。自顧無長策，空知返舊林。", "松風吹解帶，山月照彈琴。君問窮通理，漁歌入浦深。"]'),
('yuding-14','酬賀四贈葛巾之作','王維','唐','御定全唐诗','yuding','','[]','野巾傳惠好，茲貺重兼金。嘉此幽棲物，能齊隱吏心。',48,'御定全唐詩/json/126.json','["野巾傳惠好，茲貺重兼金。嘉此幽棲物，能齊隱吏心。", "早朝方暫掛，晚沐複來簪。坐覺囂塵遠，思君共入林。"]'),
('yuding-15','送丘為落第歸江東','王維','唐','御定全唐诗','yuding','','[]','憐君不得意，況複柳條春。為客黃金盡，還家白髮新。',48,'御定全唐詩/json/126.json','["憐君不得意，況複柳條春。為客黃金盡，還家白髮新。", "五湖三畝宅，萬里一歸人。知爾不能薦，羞稱獻納臣。"]'),
('yuding-16','送李判官赴東江','王維','唐','御定全唐诗','yuding','','[]','聞道皇華使，方隨皂蓋臣。封章通左語，冠冕化文身。',48,'御定全唐詩/json/126.json','["聞道皇華使，方隨皂蓋臣。封章通左語，冠冕化文身。", "樹色分揚子，潮聲滿富春。遙知辨璧吏，恩到泣珠人。"]'),
('yuding-17','送封太守','王維','唐','御定全唐诗','yuding','','[]','忽解羊頭削，聊馳熊首轓。揚舲發夏口，按節向吳門。',48,'御定全唐詩/json/126.json','["忽解羊頭削，聊馳熊首轓。揚舲發夏口，按節向吳門。", "帆映丹陽郭，楓攢赤岸村。百城多候吏，露冕一何尊。"]'),
('yuding-18','送嚴秀才還蜀','王維','唐','御定全唐诗','yuding','','[]','寧親為令子，似舅即賢甥。別路經花縣，還鄉入錦城。',48,'御定全唐詩/json/126.json','["寧親為令子，似舅即賢甥。別路經花縣，還鄉入錦城。", "山臨青塞斷，江向白雲平。獻賦何時至，明君憶長卿。"]'),
('yuding-19','送張判官赴河西','王維','唐','御定全唐诗','yuding','','[]','單車曾出塞，報國敢邀勳。見逐張征虜，今思霍冠軍。',48,'御定全唐詩/json/126.json','["單車曾出塞，報國敢邀勳。見逐張征虜，今思霍冠軍。", "沙平連白雲，蓬捲入黃雲。慷慨倚長劍，高歌一送君。"]'),
('yuding-20','送岐州源長史歸','王維','唐','御定全唐诗','yuding','','[]','握手一相送，心悲安可論。秋風正蕭索，客散孟嘗門。',48,'御定全唐詩/json/126.json','["握手一相送，心悲安可論。秋風正蕭索，客散孟嘗門。", "故驛通槐裏，長亭下槿原。征西舊旌節，從此向河源。"]'),
('yuding-21','送張道士歸山','王維','唐','御定全唐诗','yuding','','[]','先生何處去，王屋訪茅君。別婦留丹訣，驅雞入白雲。',48,'御定全唐詩/json/126.json','["先生何處去，王屋訪茅君。別婦留丹訣，驅雞入白雲。", "人間若剩住，天上複離群。當作遼城鶴，仙歌使爾聞。"]'),
('yuding-22','同崔興宗送衡岳瑗公南歸','王維','唐','御定全唐诗','yuding','','[]','言從石菌閣，新下穆陵關。獨向池陽去，白雲留故山。',48,'御定全唐詩/json/126.json','["言從石菌閣，新下穆陵關。獨向池陽去，白雲留故山。", "綻衣秋日裏，洗缽古松間。一施傳心法，唯將戒定還。"]'),
('yuding-23','送錢少府還藍田','王維','唐','御定全唐诗','yuding','','[]','草色日向好，桃源人去稀。手持平子賦，目送老萊衣。',48,'御定全唐詩/json/126.json','["草色日向好，桃源人去稀。手持平子賦，目送老萊衣。", "每候山櫻發，時同海燕歸。今年寒食酒，應是返柴扉。"]'),
('yuding-24','送丘為往唐州','王維','唐','御定全唐诗','yuding','','[]','宛洛有風塵，君行多苦辛。四愁連漢水，百口寄隨人。',48,'御定全唐詩/json/126.json','["宛洛有風塵，君行多苦辛。四愁連漢水，百口寄隨人。", "槐色陰清晝，楊花惹暮春。朝端肯相送，天子繡衣臣。"]'),
('yuding-25','送元中丞轉運江淮','王維','唐','御定全唐诗','yuding','','[]','薄賦歸天府，輕徭賴使臣。歡沾賜帛老，恩及卷綃人。',48,'御定全唐詩/json/126.json','["薄賦歸天府，輕徭賴使臣。歡沾賜帛老，恩及卷綃人。", "去問珠官俗，來經石砝春。東南禦亭上，莫使有風塵。"]'),
('yuding-26','送崔九興宗游蜀','王維','唐','御定全唐诗','yuding','','[]','送君從此去，轉覺故人稀。徒禦猶回首，田園方掩扉。',48,'御定全唐詩/json/126.json','["送君從此去，轉覺故人稀。徒禦猶回首，田園方掩扉。", "出門當旅食，中路授寒衣。江漢風流地，遊人何歲歸。"]'),
('yuding-27','送崔興宗','王維','唐','御定全唐诗','yuding','','[]','已恨親皆遠，誰憐友複稀。君王未西顧，遊宦盡東歸。',48,'御定全唐詩/json/126.json','["已恨親皆遠，誰憐友複稀。君王未西顧，遊宦盡東歸。", "塞迥山河淨，天長雲樹微。方同菊花節，相待洛陽扉。"]'),
('yuding-28','送平澹然判官','王維','唐','御定全唐诗','yuding','','[]','不識陽關路，新從定遠侯。黃雲斷春色，畫角起邊愁。',48,'御定全唐詩/json/126.json','["不識陽關路，新從定遠侯。黃雲斷春色，畫角起邊愁。", "瀚海經年到，交河出塞流。須令外國使，知飲月氏頭。"]'),
('yuding-29','送劉司直赴安西','王維','唐','御定全唐诗','yuding','','[]','絕域陽關道，胡沙與塞塵。三春時有雁，萬里少行人。',48,'御定全唐詩/json/126.json','["絕域陽關道，胡沙與塞塵。三春時有雁，萬里少行人。", "苜蓿隨天馬，葡萄逐漢臣。當令外國懼，不敢覓和親。"]'),
('yuding-30','送趙都督赴代州得青字','王維','唐','御定全唐诗','yuding','','[]','天官動將星，漢上柳條青。萬里鳴刁鬥，三軍出井陘。',48,'御定全唐詩/json/126.json','["天官動將星，漢上柳條青。萬里鳴刁鬥，三軍出井陘。", "忘身辭鳳闕，報國取龍庭。豈學書生輩，窗間老一經。"]'),
('yuding-31','送方城韋明府','王維','唐','御定全唐诗','yuding','','[]','遙思葭菼際，寥落楚人行。高鳥長淮水，平蕪故郢城。',48,'御定全唐詩/json/126.json','["遙思葭菼際，寥落楚人行。高鳥長淮水，平蕪故郢城。", "使車聽雉乳，縣鼓應雞鳴。若見州從事，無嫌手板迎。"]'),
('yuding-32','送李員外賢郎','王維','唐','御定全唐诗','yuding','','[]','少年何處去，負米上銅梁。借問阿戎父，知為童子郎。',48,'御定全唐詩/json/126.json','["少年何處去，負米上銅梁。借問阿戎父，知為童子郎。", "魚箋請詩賦，橦布作衣裳。薏苡扶衰病，歸來幸可將。"]'),
('yuding-33','送梓州李使君','王維','唐','御定全唐诗','yuding','','[]','萬壑樹參天，千山響杜鵑。山中一夜雨，樹杪百重泉。',48,'御定全唐詩/json/126.json','["萬壑樹參天，千山響杜鵑。山中一夜雨，樹杪百重泉。", "漢女輸橦布，巴人訟芋田。文翁翻教授，不敢依先賢。"]'),
('yuding-34','送張五諲歸宣城','王維','唐','御定全唐诗','yuding','','[]','五湖千萬里，況複五湖西。漁浦南陵郭，人家春穀溪。',48,'御定全唐詩/json/126.json','["五湖千萬里，況複五湖西。漁浦南陵郭，人家春穀溪。", "欲歸江淼淼，未到草萋萋。憶想蘭陵鎮，可宜猿更啼。"]'),
('yuding-35','送友人南歸','王維','唐','御定全唐诗','yuding','','[]','萬里春應盡，三江雁亦稀。連天漢水廣，孤客郢城歸。',48,'御定全唐詩/json/126.json','["萬里春應盡，三江雁亦稀。連天漢水廣，孤客郢城歸。", "鄖國稻苗秀，楚人菰米肥。懸知倚門望，遙識老萊衣。"]'),
('yuding-36','送賀遂員外外甥','王維','唐','御定全唐诗','yuding','','[]','南國有歸舟，荊門溯上流。蒼茫葭菼外，雲水與昭丘。',48,'御定全唐詩/json/126.json','["南國有歸舟，荊門溯上流。蒼茫葭菼外，雲水與昭丘。", "檣帶城烏去，江連暮雨愁。猿聲不可聽，莫待楚山秋。"]'),
('yuding-37','送楊長史赴果州','王維','唐','御定全唐诗','yuding','','[]','褒斜不容幰，之子去何之。鳥道一千里，猿聲十二時。',48,'御定全唐詩/json/126.json','["褒斜不容幰，之子去何之。鳥道一千里，猿聲十二時。", "官橋祭酒客，山木女郎祠。別後同明月，君應聽子規。"]'),
('yuding-38','送邢桂州','王維','唐','御定全唐诗','yuding','','[]','鐃吹喧京口，風波下洞庭。赭圻將赤岸，擊汰複揚舲。',48,'御定全唐詩/json/126.json','["鐃吹喧京口，風波下洞庭。赭圻將赤岸，擊汰複揚舲。", "日落江湖白，潮來天地青。明珠歸合浦，應逐使臣星。"]'),
('yuding-39','送宇文三赴河西充行軍司馬','王維','唐','御定全唐诗','yuding','','[]','橫吹雜繁笳，邊風卷塞沙。還聞田司馬，更逐李輕車。',48,'御定全唐詩/json/126.json','["橫吹雜繁笳，邊風卷塞沙。還聞田司馬，更逐李輕車。", "蒲類成秦地，莎車屬漢家。當令犬戎國，朝聘學昆邪。"]'),
('yuding-40','送孫二','王維','唐','御定全唐诗','yuding','','[]','郊外誰相送，夫君道術親。書生鄒魯客，才子洛陽人。',48,'御定全唐詩/json/126.json','["郊外誰相送，夫君道術親。書生鄒魯客，才子洛陽人。", "祖席依寒草，行車起暮塵。山川何寂寞，長望淚沾巾。"]'),
('yuding-41','送崔三往密州覲省','王維','唐','御定全唐诗','yuding','','[]','南陌去悠悠，東郊不少留。同懷扇枕戀，獨念倚門愁。',48,'御定全唐詩/json/126.json','["南陌去悠悠，東郊不少留。同懷扇枕戀，獨念倚門愁。", "路繞天山雪，家臨海樹秋。魯連功未報，且莫蹈滄洲。"]'),
('yuding-42','送孟六歸襄陽','王維','唐','御定全唐诗','yuding','','[]','杜門不復出，久與世情疏。以此為良策，勸君歸舊廬。',48,'御定全唐詩/json/126.json','["杜門不復出，久與世情疏。以此為良策，勸君歸舊廬。", "醉歌田舍酒，笑讀古人書。好是一生事，無勞獻子虛。"]'),
('yuding-43','初出濟州別城中故人','王維','唐','御定全唐诗','yuding','','[]','微官易得罪，謫去濟川陰。執政方持法，明君照此心。',48,'御定全唐詩/json/126.json','["微官易得罪，謫去濟川陰。執政方持法，明君照此心。", "閭閻河潤上，井邑海雲深。縱有歸來日，各愁年鬢侵。"]'),
('yuding-44','與盧象集朱家','王維','唐','御定全唐诗','yuding','','[]','主人能愛客，終日有逢迎。貰得新豐酒，複聞秦女箏。',48,'御定全唐詩/json/126.json','["主人能愛客，終日有逢迎。貰得新豐酒，複聞秦女箏。", "柳條疏客舍，槐葉下秋城。語笑且為樂，吾將達此生。"]'),
('yuding-45','登裴秀才迪小台','王維','唐','御定全唐诗','yuding','','[]','端居不出戶，滿目望雲山。落日鳥邊下，秋原人外閑。',48,'御定全唐詩/json/126.json','["端居不出戶，滿目望雲山。落日鳥邊下，秋原人外閑。", "遙知遠林際，不見此簷間。好客多乘月，應門莫上關。"]'),
('yuding-46','游李山人所居因題屋壁','王維','唐','御定全唐诗','yuding','','[]','世上皆如夢，狂來止自歌。問年松樹老，有地竹林多。',48,'御定全唐詩/json/126.json','["世上皆如夢，狂來止自歌。問年松樹老，有地竹林多。", "藥倩韓康賣，門容尚子過。翻嫌枕席上，無那白雲何。"]'),
('yuding-47','過崔駙馬山池','王維','唐','御定全唐诗','yuding','','[]','畫樓吹笛妓，金碗酒家胡。錦石稱貞女，青松學大夫。',48,'御定全唐詩/json/126.json','["畫樓吹笛妓，金碗酒家胡。錦石稱貞女，青松學大夫。", "脫貂貰桂醑，射雁與山廚。聞道高陽會，愚公穀正愚。"]'),
('yuding-48','過福禪師蘭若','王維','唐','御定全唐诗','yuding','','[]','岩壑轉微徑，雲林隱法堂。羽人飛奏樂，天女跪焚香。',48,'御定全唐詩/json/126.json','["岩壑轉微徑，雲林隱法堂。羽人飛奏樂，天女跪焚香。", "竹外峰偏曙，藤陰水更涼。欲知禪坐久，行路長春芳。"]'),
('yuding-49','過香積寺','王維','唐','御定全唐诗','yuding','','[]','不知香積寺，數裏入雲峰。古木無人徑，深山何處鐘。',48,'御定全唐詩/json/126.json','["不知香積寺，數裏入雲峰。古木無人徑，深山何處鐘。", "泉聲咽危石，日色冷青松。薄暮空潭曲，安禪制毒龍。"]'),
('yuding-50','過感化寺曇興上人山院','王維','唐','御定全唐诗','yuding','','[]','暮持筇竹杖，相待虎溪頭。催客聞山響，歸房逐水流。',48,'御定全唐詩/json/126.json','["暮持筇竹杖，相待虎溪頭。催客聞山響，歸房逐水流。", "野花叢發好，穀鳥一聲幽。夜坐空林寂，松風直似秋。"]'),
('yuding-51','夏日過青龍寺謁操禪師','王維','唐','御定全唐诗','yuding','','[]','龍鍾一老翁，徐步謁禪宮。欲問義心義，遙知空病空。',48,'御定全唐詩/json/126.json','["龍鍾一老翁，徐步謁禪宮。欲問義心義，遙知空病空。", "山河天眼裏，世界法身中。莫怪銷炎熱，能生大地風。"]'),
('yuding-52','登辨覺寺','王維','唐','御定全唐诗','yuding','','[]','竹徑從初地，蓮峰出化城。窗中三楚盡，林上九江平。',48,'御定全唐詩/json/126.json','["竹徑從初地，蓮峰出化城。窗中三楚盡，林上九江平。", "軟草承趺坐，長松響梵聲。空居法雲外，觀世得無生。"]'),
('yuding-53','喜祖三至留宿','王維','唐','御定全唐诗','yuding','','[]','門前洛陽客，下馬拂征衣。不枉故人駕，平生多掩扉。',48,'御定全唐詩/json/126.json','["門前洛陽客，下馬拂征衣。不枉故人駕，平生多掩扉。", "行人返深巷，積雪帶餘暉。早歲同袍者，高車何處歸。"]'),
('yuding-54','黎拾遺昕裴秀才迪見過秋夜對雨之作','王維','唐','御定全唐诗','yuding','','[]','促織鳴已急，輕衣行向重。寒燈坐高館，秋雨聞疏鐘。',48,'御定全唐詩/json/126.json','["促織鳴已急，輕衣行向重。寒燈坐高館，秋雨聞疏鐘。", "白法調狂象，玄言問老龍。何人顧蓬徑，空愧求羊蹤。"]'),
('yuding-55','慕容承攜素饌見過','王維','唐','御定全唐诗','yuding','','[]','紗帽烏皮幾，閒居懶賦詩。門看五柳識，年算六身知。',48,'御定全唐詩/json/126.json','["紗帽烏皮幾，閒居懶賦詩。門看五柳識，年算六身知。", "靈壽君王賜，雕胡弟子炊。空勞酒食饌，持底解人頤。"]'),
('yuding-56','晚春嚴少尹與諸公見過','王維','唐','御定全唐诗','yuding','','[]','松菊荒三徑，圖書共五車。烹葵邀上客，看竹到貧家。',48,'御定全唐詩/json/126.json','["松菊荒三徑，圖書共五車。烹葵邀上客，看竹到貧家。", "鵲乳先春草，鶯啼過落花。自憐黃發暮，一倍惜年華。"]'),
('yuding-57','鄭果州相過','王維','唐','御定全唐诗','yuding','','[]','麗日照殘春，初晴草木新。床前磨鏡客，樹下灌園人。',48,'御定全唐詩/json/126.json','["麗日照殘春，初晴草木新。床前磨鏡客，樹下灌園人。", "五馬驚窮巷，雙童逐老身。中廚辦粗飯，當恕阮家貧。"]'),
('yuding-58','山居秋暝','王維','唐','御定全唐诗','yuding','','[]','空山新雨後，天氣晚來秋。明月松間照，清泉石上流。',48,'御定全唐詩/json/126.json','["空山新雨後，天氣晚來秋。明月松間照，清泉石上流。", "竹喧歸浣女，蓮動下漁舟。隨意春芳歇，王孫自可留。"]'),
('yuding-59','終南別業','王維','唐','御定全唐诗','yuding','','[]','中歲頗好道，晚家南山陲。興來每獨往，勝事空自知。',48,'御定全唐詩/json/126.json','["中歲頗好道，晚家南山陲。興來每獨往，勝事空自知。", "行到水窮處，坐看雲起時。偶然值林叟，談笑無還期。"]'),
('yuding-60','歸嵩山作','王維','唐','御定全唐诗','yuding','','[]','清川帶長薄，車馬去閑閑。流水如有意，暮禽相與還。',48,'御定全唐詩/json/126.json','["清川帶長薄，車馬去閑閑。流水如有意，暮禽相與還。", "荒城臨古渡，落日滿秋山。迢遞嵩高下，歸來且閉關。"]'),
('yuding-61','歸輞川作','王維','唐','御定全唐诗','yuding','','[]','谷口疏鐘動，漁樵稍欲稀。悠然遠山暮，獨向白雲歸。',48,'御定全唐詩/json/126.json','["谷口疏鐘動，漁樵稍欲稀。悠然遠山暮，獨向白雲歸。", "菱蔓弱難定，楊花輕易飛。東皋春草色，惆悵掩柴扉。"]'),
('yuding-62','韋給事山居','王維','唐','御定全唐诗','yuding','','[]','幽尋得此地，詎有一人曾。大壑隨階轉，群山入戶登。',48,'御定全唐詩/json/126.json','["幽尋得此地，詎有一人曾。大壑隨階轉，群山入戶登。", "庖廚出深竹，印綬隔垂藤。即事辭軒冕，誰雲病未能。"]'),
('yuding-63','山居即事','王維','唐','御定全唐诗','yuding','','[]','寂寞掩柴扉，蒼茫對落暉。鶴巢松樹遍，人訪蓽門稀。',48,'御定全唐詩/json/126.json','["寂寞掩柴扉，蒼茫對落暉。鶴巢松樹遍，人訪蓽門稀。", "綠竹含新粉，紅蓮落故衣。渡頭煙火起，處處采菱歸。"]'),
('yuding-64','終南山','王維','唐','御定全唐诗','yuding','','[]','太乙近天都，連山接海隅。白雲回望合，青靄入看無。',48,'御定全唐詩/json/126.json','["太乙近天都，連山接海隅。白雲回望合，青靄入看無。", "分野中峰變，陰晴眾壑殊。欲投人處宿，隔水問樵夫。"]'),
('yuding-65','輞川閒居','王維','唐','御定全唐诗','yuding','','[]','一從歸白社，不復到青門。時倚簷前樹，遠看原上村。',48,'御定全唐詩/json/126.json','["一從歸白社，不復到青門。時倚簷前樹，遠看原上村。", "青菰臨水拔，白鳥向山翻。寂寞於陵子，桔槔方灌園。"]'),
('yuding-66','春園即事','王維','唐','御定全唐诗','yuding','','[]','宿雨乘輕屐，春寒著弊袍。開畦分白水，間柳發紅桃。',48,'御定全唐詩/json/126.json','["宿雨乘輕屐，春寒著弊袍。開畦分白水，間柳發紅桃。", "草際成棋局，林端舉桔槔。還持鹿皮幾，日暮隱蓬蒿。"]'),
('yuding-67','淇上田園即事','王維','唐','御定全唐诗','yuding','','[]','屏居淇水上，東野曠無山。日隱桑柘外，河明閭井間。',48,'御定全唐詩/json/126.json','["屏居淇水上，東野曠無山。日隱桑柘外，河明閭井間。", "牧童望村去，獵犬隨人還。靜者亦何事，荊扉乘晝關。"]'),
('yuding-68','涼州郊外游望','王維','唐','御定全唐诗','yuding','','[]','野老才三戶，邊村少四鄰。婆娑依裏社，簫鼓賽田神。',48,'御定全唐詩/json/126.json','["野老才三戶，邊村少四鄰。婆娑依裏社，簫鼓賽田神。", "灑酒澆芻狗，焚香拜木人。女巫紛屢舞，羅襪自生塵。"]'),
('yuding-69','觀獵','王維','唐','御定全唐诗','yuding','','[]','風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。',48,'御定全唐詩/json/126.json','["風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。", "忽過新豐市，還歸細柳營。回看射雕處，千里暮雲平。"]'),
('yuding-70','春日上方即事','王維','唐','御定全唐诗','yuding','','[]','好讀高僧傳，時看辟谷方。鳩形將刻仗，龜殼用支床。',48,'御定全唐詩/json/126.json','["好讀高僧傳，時看辟谷方。鳩形將刻仗，龜殼用支床。", "柳色青山映，梨花夕鳥藏。北窗桃李下，閑坐但焚香。"]'),
('yuding-71','漢江臨泛','王維','唐','御定全唐诗','yuding','','[]','楚塞三湘接，荊門九派通。江流天地外，山色有無中。',48,'御定全唐詩/json/126.json','["楚塞三湘接，荊門九派通。江流天地外，山色有無中。", "郡邑浮前浦，波瀾動遠空。襄陽好風日，留醉與山翁。"]'),
('yuding-72','泛前陂','王維','唐','御定全唐诗','yuding','','[]','秋空自明迥，況複遠人間。暢以沙際鶴，兼之雲外山。',48,'御定全唐詩/json/126.json','["秋空自明迥，況複遠人間。暢以沙際鶴，兼之雲外山。", "澄波澹將夕，清月皓方閑。此夜任孤棹，夷猶殊未還。"]'),
('yuding-73','登河北城樓作','王維','唐','御定全唐诗','yuding','','[]','井邑傅岩上，客亭雲霧間。高城眺落日，極浦映蒼山。',48,'御定全唐詩/json/126.json','["井邑傅岩上，客亭雲霧間。高城眺落日，極浦映蒼山。", "岸火孤舟宿，漁家夕鳥還。寂寥天地暮，心與廣川閑。"]'),
('yuding-74','千塔主人','王維','唐','御定全唐诗','yuding','','[]','逆旅逢佳節，征帆未可前。窗臨汴河水，門渡楚人船。',48,'御定全唐詩/json/126.json','["逆旅逢佳節，征帆未可前。窗臨汴河水，門渡楚人船。", "雞犬散墟落，桑榆蔭遠田。所居人不見，枕席生雲煙。"]'),
('yuding-75','使至塞上','王維','唐','御定全唐诗','yuding','','[]','單車欲問邊，屬國過居延。征蓬出漢塞，歸雁入胡天。',48,'御定全唐詩/json/126.json','["單車欲問邊，屬國過居延。征蓬出漢塞，歸雁入胡天。", "大漠孤煙直，長河落日圓。蕭關逢候吏，都護在燕然。"]'),
('yuding-76','晚春歸思','王維','唐','御定全唐诗','yuding','','[]','新妝可憐色，落日卷羅帷。爐氣清珍簟，牆陰上玉墀。',48,'御定全唐詩/json/126.json','["新妝可憐色，落日卷羅帷。爐氣清珍簟，牆陰上玉墀。", "春蟲飛網戶，暮雀隱花枝。向晚多愁思，閑窗桃李時。"]'),
('yuding-77','戲題示蕭氏甥','王維','唐','御定全唐诗','yuding','','[]','憐爾解臨池，渠爺未學詩。老夫何足似，弊宅倘因之。',48,'御定全唐詩/json/126.json','["憐爾解臨池，渠爺未學詩。老夫何足似，弊宅倘因之。", "蘆筍穿荷葉，菱花罥雁兒。郗公不易勝，莫著外家欺。"]'),
('yuding-78','秋夜獨坐','王維','唐','御定全唐诗','yuding','','[]','獨坐悲雙鬢，空堂欲二更。雨中山果落，燈下草蟲鳴。',48,'御定全唐詩/json/126.json','["獨坐悲雙鬢，空堂欲二更。雨中山果落，燈下草蟲鳴。", "白髮終難變，黃金不可成。欲知除老病，唯有學無生。"]'),
('yuding-79','待儲光羲不至','王維','唐','御定全唐诗','yuding','','[]','重門朝已啟，起坐聽車聲。要欲聞清佩，方將出戶迎。',48,'御定全唐詩/json/126.json','["重門朝已啟，起坐聽車聲。要欲聞清佩，方將出戶迎。", "晚鐘鳴上苑，疏雨過春城。了自不相顧，臨堂空複情。"]'),
('yuding-80','聽宮鶯','王維','唐','御定全唐诗','yuding','','[]','春樹繞宮牆，宮鶯囀曙光。忽驚啼暫斷，移處弄還長。',48,'御定全唐詩/json/126.json','["春樹繞宮牆，宮鶯囀曙光。忽驚啼暫斷，移處弄還長。", "隱葉棲承露，攀花出未央。遊人未應返，為此始思鄉。"]'),
('yuding-81','雜詩','王維','唐','御定全唐诗','yuding','','[]','雙燕初命子，五桃新作花。王昌是東舍，宋玉次西家。',48,'御定全唐詩/json/126.json','["雙燕初命子，五桃新作花。王昌是東舍，宋玉次西家。", "小小能織綺，時時出浣紗。親勞使君問，南陌駐香車。"]'),
('yuding-82','留別錢起','王維','唐','御定全唐诗','yuding','','[]','卑棲卻得性，每與白雲歸。徇祿仍懷橘，看山免采薇。',48,'御定全唐詩/json/126.json','["卑棲卻得性，每與白雲歸。徇祿仍懷橘，看山免采薇。", "暮禽先去馬，新月待開扉。霄漢時回首，知音青瑣闈。"]'),
('yuding-83','留別丘為','王維','唐','御定全唐诗','yuding','','[]','歸鞍白雲外，繚繞出前山。今日又明日，自知心不閑。',48,'御定全唐詩/json/126.json','["歸鞍白雲外，繚繞出前山。今日又明日，自知心不閑。", "親勞簪組送，欲趁鶯花還。一步一回首，遲遲向近關。"]'),
('yuding-84','愚公穀三首','王維','唐','御定全唐诗','yuding','','[]','愚穀與誰去，唯將黎子同。非須一處住，不那兩心空。',144,'御定全唐詩/json/126.json','["愚穀與誰去，唯將黎子同。非須一處住，不那兩心空。", "甯問春將夏，誰論西複東。不知吾與子，若個是愚公。", "吾家愚穀裏，此谷本來平。雖則行無跡，還能回應聲。", "不隨雲色暗，只待日光明。緣底名愚穀，都由愚所成。", "借問愚公穀，與君聊一尋。不尋翻到谷，此穀不離心。", "行處曾無險，看時豈有深。寄言塵世客，何處欲歸臨。"]'),
('yuding-85','酬慕容十一','王維','唐','御定全唐诗','yuding','','[]','行行西陌返，駐幰問車公。挾轂雙官騎，應門五尺僮。',48,'御定全唐詩/json/126.json','["行行西陌返，駐幰問車公。挾轂雙官騎，應門五尺僮。", "老年如塞北，強起離牆東。為報壺丘子，來人道姓蒙。"]'),
('yuding-86','過始皇墓','王維','唐','御定全唐诗','yuding','','[]','古墓成蒼嶺，幽宮象紫台。星辰七曜隔，河漢九泉開。',48,'御定全唐詩/json/126.json','["古墓成蒼嶺，幽宮象紫台。星辰七曜隔，河漢九泉開。", "有海人寧渡，無春雁不回。更聞松韻切，疑是大夫哀。"]'),
('yuding-87','恭懿太子挽歌五首','王維','唐','御定全唐诗','yuding','','[]','何悟藏環早，才知拜璧年。翀天王子去，對日聖君憐。',240,'御定全唐詩/json/126.json','["何悟藏環早，才知拜璧年。翀天王子去，對日聖君憐。", "樹轉宮猶出，笳悲馬不前。雖蒙絕馳道，京兆別開阡。", "蘭殿新恩切，椒宮夕臨幽。白雲隨鳳管，明月在龍樓。", "人向青山哭，天臨渭水愁。雞鳴常問膳，今恨玉京留。", "騎吹淩霜發，旌旗夾路陳。凱容金節護，冊命玉符新。", "傅母悲香褓，君家擁畫輪。射熊今夢帝，秤象問何人。", "蒼舒留帝寵，子晉有仙才。五歲過人智，三天使鶴催。", "心悲陽祿館，目斷望思台。若道長安近，何為更不來。", "西望昆池闊，東瞻下杜平。山朝豫章館，樹轉鳳凰城。", "五校連旗色，千門疊鼓聲。金環如有驗，還向畫堂生。"]'),
('yuding-88','故太子太師徐公挽歌四首','王維','唐','御定全唐诗','yuding','','[]','功德冠群英，彌綸有大名。軒皇用風後，傅說是星精。',192,'御定全唐詩/json/126.json','["功德冠群英，彌綸有大名。軒皇用風後，傅說是星精。", "就第優遺老，來朝詔不名。留侯常辟穀，何苦不長生。", "謀猷為相國，翊戴奉宸輿。劍履升前殿，貂蟬托後車。", "齊侯疏土宇，漢室賴圖書。僻處留田宅，仍才十頃餘。", "舊裏趨庭日，新年置酒辰。聞詩鸞渚客，獻賦鳳樓人。", "北首辭明主，東堂哭大臣。猶思禦朱輅，不惜汙車茵。", "久踐中台座，終登上將壇。誰言斷車騎，空憶盛衣冠。", "風日咸陽慘，笳簫渭水寒。無人當便闕，應罷太師官。"]'),
('yuding-89','故西河郡杜太守挽歌三首','王維','唐','御定全唐诗','yuding','','[]','天上去西征，雲中護北平。生擒白馬將，連破黑雕城。',144,'御定全唐詩/json/126.json','["天上去西征，雲中護北平。生擒白馬將，連破黑雕城。", "忽見芻靈苦，徒聞竹使榮。空留左氏傳，誰繼卜商名。", "返葬金符守，同歸石窌妻。卷衣悲畫翟，持翣待鳴雞。", "容衛都人慘，山川駟馬嘶。猶聞隴上客，相對哭征西。", "塗芻去國門，秘器出東園。太守留金印，夫人罷錦軒。", "旌旗轉衰木，簫鼓上寒原。墳樹應西靡，長思魏闕恩。"]'),
('yuding-90','故南陽夫人樊氏挽歌','王維','唐','御定全唐诗','yuding','','[]','錦衣餘翟茀，繡轂罷魚軒。淑女詩長在，夫人法尚存。',48,'御定全唐詩/json/126.json','["錦衣餘翟茀，繡轂罷魚軒。淑女詩長在，夫人法尚存。", "凝笳隨曉旆，行哭向秋原。歸去將何見，誰能返戟門。"]'),
('yuding-91','達奚侍郎夫人寇氏挽詞二首','王維','唐','御定全唐诗','yuding','','[]','束帶將朝日，鳴環映牖辰。能令諫明主，相勸識賢人。',96,'御定全唐詩/json/126.json','["束帶將朝日，鳴環映牖辰。能令諫明主，相勸識賢人。", "遺掛空留壁，回文日覆塵。金蠶將畫柳，何處更知春。", "女史悲彤管，夫人罷錦軒。蔔塋占二室，行哭度千門。", "秋日光能淡，寒川波自翻。一朝成萬古，松柏暗平原。"]'),
('yuding-92','《送孫秀才','王維','唐','御定全唐诗','yuding','','[]','帝城風日好，況複建平家。玉枕雙文簟，金盤五色瓜。',48,'御定全唐詩/json/126.json','["帝城風日好，況複建平家。玉枕雙文簟，金盤五色瓜。", "山中無魯酒，松下飯胡麻。莫厭田家苦，歸期遠複賒。"]'),
('yuding-0','奉和聖制慶玄元皇帝玉像之作應制','王維','唐','御定全唐诗','yuding','','[]','明君夢帝先，寶命上齊天。秦後徒聞樂，周王恥蔔年。',72,'御定全唐詩/json/127.json','["明君夢帝先，寶命上齊天。秦後徒聞樂，周王恥蔔年。", "玉京移大像，金籙會群仙。承露調天供，臨空敞禦筵。", "鬥回迎壽酒，山近起爐煙。願奉無為化，齋心學自然。"]'),
('yuding-1','奉和聖制與太子諸王三月三日龍池春禊應制','王維','唐','御定全唐诗','yuding','','[]','故事修春禊，新宮展豫遊。明君移鳳輦，太子出龍樓。',72,'御定全唐詩/json/127.json','["故事修春禊，新宮展豫遊。明君移鳳輦，太子出龍樓。", "賦掩陳王作，杯如洛水流。金人來捧劍，畫鷁去回舟。", "苑樹浮宮闕，天池照冕旒。宸章在雲表，垂象滿皇州。"]'),
('yuding-2','奉和聖制上巳於望春亭觀禊飲應制','王維','唐','御定全唐诗','yuding','','[]','長樂青門外，宜春小苑東。樓開萬井上，輦過百花中。',72,'御定全唐詩/json/127.json','["長樂青門外，宜春小苑東。樓開萬井上，輦過百花中。", "畫鷁移仙妓，金貂列上公。清歌邀落日，妙舞向春風。", "渭水明秦甸，黃山入漢宮。君王來祓禊，灞滻亦朝宗。"]'),
('yuding-3','奉和聖制暮春送朝集使歸郡應制','王維','唐','御定全唐诗','yuding','','[]','萬國仰宗周，衣冠拜冕旒。玉乘迎大客，金節送諸侯。',72,'御定全唐詩/json/127.json','["萬國仰宗周，衣冠拜冕旒。玉乘迎大客，金節送諸侯。", "祖席傾三省，褰帷向九州。楊花飛上路，槐色蔭通溝。", "來預鈞天樂，歸分漢主憂。宸章類河漢，垂象滿中州。"]'),
('yuding-4','三月三日曲江侍宴應制','王維','唐','御定全唐诗','yuding','','[]','萬乘親齋祭，千官喜豫遊。奉迎從上苑，祓禊向中流。',72,'御定全唐詩/json/127.json','["萬乘親齋祭，千官喜豫遊。奉迎從上苑，祓禊向中流。", "草樹連容衛，山河對冕旒。畫旗搖浦漵，春服滿汀洲。", "仙籞龍媒下，神皋鳳蹕留。從今億萬歲，天寶紀春秋。"]'),
('yuding-5','奉和聖制重陽節宰臣及群官上壽應制','王維','唐','御定全唐诗','yuding','','[]','四海方無事，三秋大有年。百生無此日，萬壽願齊天。',72,'御定全唐詩/json/127.json','["四海方無事，三秋大有年。百生無此日，萬壽願齊天。", "芍藥和金鼎，茱萸插玳筵。玉堂開右個，天樂動宮懸。", "禦柳疏秋景，城鴉拂曙煙。無窮菊花節，長奉柏梁篇。"]'),
('yuding-6','三月三日勤政樓侍宴應制','王維','唐','御定全唐诗','yuding','','[]','彩仗連宵合，瓊樓拂曙通。年光三月裏，宮殿百花中。',72,'御定全唐詩/json/127.json','["彩仗連宵合，瓊樓拂曙通。年光三月裏，宮殿百花中。", "不數秦王日，誰將洛水同。酒筵嫌落絮，舞袖怯春風。", "天保無為德，人歡不戰功。仍臨九衢宴，更達四門聰。"]'),
('yuding-7','奉和聖制十五夜然燈繼以酺宴應制','王維','唐','御定全唐诗','yuding','','[]','上路笙歌滿，春城漏刻長。遊人多晝日，明月讓燈光。',96,'御定全唐詩/json/127.json','["上路笙歌滿，春城漏刻長。遊人多晝日，明月讓燈光。", "魚鑰通翔鳳，龍輿出建章。九衢陳廣樂，百福透名香。", "仙伎來金殿，都人繞玉堂。定應偷妙舞，從此學新妝。", "奉引迎三事，司儀列萬方。願將天地壽，同以獻君王。"]'),
('yuding-8','奉和聖制幸玉真公主山莊因題石壁十韻之作應制','王維','唐','御定全唐诗','yuding','','[]','碧落風煙外，瑤台道路賒。如何連帝苑，別自有仙家。',120,'御定全唐詩/json/127.json','["碧落風煙外，瑤台道路賒。如何連帝苑，別自有仙家。", "此地回鸞駕，緣溪轉翠華。洞中開日月，窗裏發雲霞。", "庭養沖天鶴，溪流上漢查。種田生白玉，泥灶化丹砂。", "穀靜泉逾響，山深日易斜。禦羹和石髓，香飯進胡麻。", "大道今無外，長生詎有涯。還瞻九霄上，來往五雲車。"]'),
('yuding-9','春日直門下省早朝','王維','唐','御定全唐诗','yuding','','[]','騎省直明光，雞鳴謁建章。遙聞侍中佩，闇識令君香。',72,'御定全唐詩/json/127.json','["騎省直明光，雞鳴謁建章。遙聞侍中佩，闇識令君香。", "玉漏隨銅史，天書拜夕郎。旌旗映閶闔，歌吹滿昭陽。", "官舍梅初紫，宮門柳欲黃。願將遲日意，同與聖恩長。"]'),
('yuding-10','和僕射晉公扈從溫湯','王維','唐','御定全唐诗','yuding','','[]','天子幸新豐，旌旗渭水東。寒山天仗外，溫穀幔城中。',120,'御定全唐詩/json/127.json','["天子幸新豐，旌旗渭水東。寒山天仗外，溫穀幔城中。", "奠玉群仙座，焚香太乙宮。出遊逢牧馬，罷獵見非熊。", "上宰無為化，明時太古同。靈芝三秀紫，陳粟萬箱紅。", "王禮尊儒教，天兵小戰功。謀猶歸哲匠，詞賦屬文宗。", "司諫方無闕，陳詩且未工。長吟吉甫頌，朝夕仰清風。"]'),
('yuding-11','和宋中丞夏日遊福賢觀天長寺寺即陳左相宅所施之作','王維','唐','御定全唐诗','yuding','','[]','已相殷王國，空餘尚父溪。釣磯開月殿，築道出雲梯。',72,'御定全唐詩/json/127.json','["已相殷王國，空餘尚父溪。釣磯開月殿，築道出雲梯。", "積水浮香象，深山鳴白雞。虛空陳伎樂，衣服制虹霓。", "墨點三千界，丹飛六一泥。桃源勿遽返，再訪恐君迷。"]'),
('yuding-12','和陳監四郎秋雨中思從弟據','王維','唐','御定全唐诗','yuding','','[]','嫋嫋秋風動，淒淒煙雨繁。聲連鳷鵲觀，色暗鳳凰原。',96,'御定全唐詩/json/127.json','["嫋嫋秋風動，淒淒煙雨繁。聲連鳷鵲觀，色暗鳳凰原。", "細柳疏高閣，輕槐落洞門。九衢行欲斷，萬井寂無喧。", "忽有愁霖唱，更陳多露言。平原思令弟，康樂謝賢昆。", "逸興方三接，衰顏強七奔。相如今老病，歸守茂陵園。"]'),
('yuding-13','上張令公','王維','唐','御定全唐诗','yuding','','[]','珥筆趨丹陛，垂璫上玉除。步簷青瑣闥，方幰畫輪車。',132,'御定全唐詩/json/127.json','["珥筆趨丹陛，垂璫上玉除。步簷青瑣闥，方幰畫輪車。", "市閱千金字，朝聞五色書。致君光帝典，薦士滿公車。", "伏奏回金駕，橫經重石渠。從茲罷角抵，且複幸儲胥。", "天統知堯後，王章笑魯初。匈奴遙俯伏，漢相儼簪裾。", "賈生非不遇，汲黯自堪疏。學易思求我，言詩或起予。", "當從大夫後，何惜隸人餘。"]'),
('yuding-14','贈焦道士','王維','唐','御定全唐诗','yuding','','[]','海上游三島，淮南預八公。坐知千裏外，跳向一壺中。',72,'御定全唐詩/json/127.json','["海上游三島，淮南預八公。坐知千裏外，跳向一壺中。", "縮地朝珠闕，行天使玉童。飲人聊割酒，送客乍分風。", "天老能行氣，吾師不養空。謝君徒雀躍，無可問鴻蒙。"]'),
('yuding-15','贈東嶽焦煉師','王維','唐','御定全唐诗','yuding','','[]','先生千歲餘，五嶽遍曾居。遙識齊侯鼎，新過王母廬。',108,'御定全唐詩/json/127.json','["先生千歲餘，五嶽遍曾居。遙識齊侯鼎，新過王母廬。", "不能師孔墨，何事問長沮。玉管時來鳳，銅盤即釣魚。", "竦身空裏語，明目夜中書。自有還丹術，時論太素初。", "頻蒙露版詔，時降軟輪車。山靜泉逾響，松高枝轉疏。", "支頤問樵客，世上複何如。"]'),
('yuding-16','送秘書晁監還日本國','王維','唐','御定全唐诗','yuding','','[]','積水不可極，安知滄海東。九州何處遠，萬里若乘空。',72,'御定全唐詩/json/127.json','["積水不可極，安知滄海東。九州何處遠，萬里若乘空。", "向國唯看日，歸帆但信風。鼇身映天黑，魚眼射波紅。", "鄉樹扶桑外，主人孤島中。別離方異域，音信若為通。"]'),
('yuding-17','送禰郎中','王維','唐','御定全唐诗','yuding','','[]','東郊春草色，驅馬去悠悠。況複鄉山外，猿啼湘水流。',72,'御定全唐詩/json/127.json','["東郊春草色，驅馬去悠悠。況複鄉山外，猿啼湘水流。", "島夷傳露版，江館候鳴騶。卉服為諸吏，珠官拜本州。", "孤鶯吟遠墅，野杏發山郵。早晚方歸奏，南中才忌秋。"]'),
('yuding-18','送李太守赴上洛','王維','唐','御定全唐诗','yuding','','[]','商山包楚鄧，積翠藹沉沉。驛路飛泉灑，關門落照深。',72,'御定全唐詩/json/127.json','["商山包楚鄧，積翠藹沉沉。驛路飛泉灑，關門落照深。", "野花開古戍，行客響空林。板屋春多雨，山城晝欲陰。", "丹泉通虢略，白羽抵荊岑。若見西山爽，應知黃綺心。"]'),
('yuding-19','送熊九赴任安陽','王維','唐','御定全唐诗','yuding','','[]','魏國應劉後，寂寥文雅空。漳河如舊日，之子繼清風。',60,'御定全唐詩/json/127.json','["魏國應劉後，寂寥文雅空。漳河如舊日，之子繼清風。", "阡陌銅台下，閭閻金虎中。送車盈灞上，輕騎出關東。", "相去千餘裏，西園明月同。"]'),
('yuding-20','山中示弟','王維','唐','御定全唐诗','yuding','','[]','山林吾喪我，冠帶爾成人。莫學嵇康懶，且安原憲貧。',60,'御定全唐詩/json/127.json','["山林吾喪我，冠帶爾成人。莫學嵇康懶，且安原憲貧。", "山陰多北戶，泉水在東鄰。緣合妄相有，性空無所親。", "安知廣成子，不是老夫身。"]'),
('yuding-21','青龍寺曇璧上人兄院集','王維','唐','御定全唐诗','yuding','','[]','高處敞招提，虛空詎有倪。坐看南陌騎，下聽秦城雞。',60,'御定全唐詩/json/127.json','["高處敞招提，虛空詎有倪。坐看南陌騎，下聽秦城雞。", "眇眇孤煙起，芊芊遠樹齊。青山萬井外，落日五陵西。", "眼界今無染，心空安可迷。"]'),
('yuding-22','濟州過趙叟家宴','王維','唐','御定全唐诗','yuding','','[]','雖與人境接，閉門成隱居。道言莊叟事，儒行魯人餘。',72,'御定全唐詩/json/127.json','["雖與人境接，閉門成隱居。道言莊叟事，儒行魯人餘。", "深巷斜暉靜，閑門高柳疏。荷鋤修藥圃，散帙曝農書。", "上客搖芳翰，中廚饋野蔬。夫君第高飲，景晏出林閭。"]'),
('yuding-23','春過賀遂員外藥園','王維','唐','御定全唐诗','yuding','','[]','前年槿籬故，新作藥欄成。香草為君子，名花是長卿。',72,'御定全唐詩/json/127.json','["前年槿籬故，新作藥欄成。香草為君子，名花是長卿。", "水穿磐石透，藤系古松生。畫畏開廚走，來蒙倒屣迎。", "蔗漿菰米飯，蒟醬露葵羹。頗識灌園意，於陵不自輕。"]'),
('yuding-24','過盧四員外宅看飯僧共題七韻','王維','唐','御定全唐诗','yuding','','[]','三賢異七賢，青眼慕青蓮。乞飯從香積，裁衣學水田。',84,'御定全唐詩/json/127.json','["三賢異七賢，青眼慕青蓮。乞飯從香積，裁衣學水田。", "上人飛錫杖，檀越施金錢。趺坐簷前日，焚香竹下煙。", "寒空法雲地，秋色淨居天。身逐因緣法，心過次第禪。", "不須愁日暮，自有一燈然。"]'),
('yuding-25','河南嚴尹弟見宿弊廬訪別人賦十韻','王維','唐','御定全唐诗','yuding','','[]','上客能論道，吾生學養蒙。貧交世情外，才子古人中。',120,'御定全唐詩/json/127.json','["上客能論道，吾生學養蒙。貧交世情外，才子古人中。", "冠上方簪豸，車邊已畫熊。拂衣迎五馬，垂手憑雙童。", "花醥和松屑，茶香透竹叢。薄霜澄夜月，殘雪帶春風。", "古壁蒼苔黑，寒山遠燒紅。眼看東候別，心事北川同。", "為學輕先輩，何能訪老翁。欲知今日後，不樂為車公。"]'),
('yuding-26','投道一師蘭若宿','王維','唐','御定全唐诗','yuding','','[]','一公棲太白，高頂出風煙。梵流諸壑遍，花雨一峰偏。',96,'御定全唐詩/json/127.json','["一公棲太白，高頂出風煙。梵流諸壑遍，花雨一峰偏。", "跡為無心隱，名因立教傳。鳥來遠語法，客去更安禪。", "晝涉松路盡，暮投蘭若邊。洞房隱深竹，清夜聞遙泉。", "向是雲霞裏，今成枕席前。豈唯暫留宿，服事將窮年。"]'),
('yuding-27','遊化感寺','王維','唐','御定全唐诗','yuding','','[]','翡翠香煙合，琉璃寶地平。龍宮連棟宇，虎穴傍簷楹。',120,'御定全唐詩/json/127.json','["翡翠香煙合，琉璃寶地平。龍宮連棟宇，虎穴傍簷楹。", "穀靜唯松響，山深無鳥聲。瓊峰當戶拆，金澗透林明。", "郢路雲端迥，秦川雨外晴。雁王銜果獻，鹿女踏花行。", "抖擻辭貧裏，歸依宿化城。繞籬生野蕨，空館發山櫻。", "香飯青菰米，嘉蔬綠筍莖。誓陪清梵末，端坐學無生。"]'),
('yuding-28','遊悟真寺','王維','唐','御定全唐诗','yuding','','[]','聞道黃金地，仍開白玉田。擲山移巨石，咒嶺出飛泉。',144,'御定全唐詩/json/127.json','["聞道黃金地，仍開白玉田。擲山移巨石，咒嶺出飛泉。", "猛虎同三徑，愁猿學四禪。買香然綠桂，乞火踏紅蓮。", "草色搖霞上，松聲泛月邊。山河窮百二，世界接三千。", "梵宇聊憑視，王城遂渺然。灞陵才出樹，渭水欲連天。", "遠縣分諸郭，孤村起白煙。望雲思聖主，披霧隱群賢。", "薄宦慚屍素，終身擬尚玄。誰知草庵客，曾和柏梁篇。"]'),
('yuding-29','與蘇盧二員外期游方丈寺而蘇不至，因有是作','王維','唐','御定全唐诗','yuding','','[]','共仰頭陀行，能忘世諦情。回看雙鳳闕，相去一牛鳴。',72,'御定全唐詩/json/127.json','["共仰頭陀行，能忘世諦情。回看雙鳳闕，相去一牛鳴。", "法向空林說，心隨寶地平。手巾花氎淨，香帔稻畦成。", "聞道邀同舍，相期宿化城。安知不來往，翻得似無生。"]'),
('yuding-30','曉行巴峽','王維','唐','御定全唐诗','yuding','','[]','際曉投巴峽，餘春憶帝京。晴江一女浣，朝日眾雞鳴。',72,'御定全唐詩/json/127.json','["際曉投巴峽，餘春憶帝京。晴江一女浣，朝日眾雞鳴。", "水國舟中市，山橋樹杪行。登高萬井出，眺迥二流明。", "人作殊方語，鶯為故國聲。賴多山水趣，稍解別離情。"]'),
('yuding-31','清如玉壺冰','王維','唐','御定全唐诗','yuding','','[]','玉壺何用好，偏許素冰居。未共銷丹日，還同照綺疏。',72,'御定全唐詩/json/127.json','["玉壺何用好，偏許素冰居。未共銷丹日，還同照綺疏。", "抱明中不隱，含淨外疑虛。氣似庭霜積，光言砌月餘。", "曉淩飛鵲鏡，宵映聚螢書。若向夫君比，清心尚不如。"]'),
('yuding-32','賦得秋日懸清光','王維','唐','御定全唐诗','yuding','','[]','寥廓涼天靜，晶明白日秋。圓光含萬象，碎影入閑流。',72,'御定全唐詩/json/127.json','["寥廓涼天靜，晶明白日秋。圓光含萬象，碎影入閑流。", "迥與青冥合，遙同江甸浮。晝陰殊眾木，斜影下危樓。", "宋玉登高怨，張衡望遠愁。餘輝如可托，雲路豈悠悠。"]'),
('yuding-33','東溪玩月','王維','唐','御定全唐诗','yuding','','[]','月從斷山口，遙吐柴門端。萬木分空霽，流陰中夜攢。',72,'御定全唐詩/json/127.json','["月從斷山口，遙吐柴門端。萬木分空霽，流陰中夜攢。", "光連虛象白，氣與風露寒。穀靜秋泉響，岩深青靄殘。", "清燈入幽夢，破影抱空巒。恍惚琴窗裏，松溪曉思難。"]'),
('yuding-34','田家','王維','唐','御定全唐诗','yuding','','[]','舊穀行將盡，良苗未可希。老年方愛粥，卒歲且無衣。',84,'御定全唐詩/json/127.json','["舊穀行將盡，良苗未可希。老年方愛粥，卒歲且無衣。", "雀乳青苔井，雞鳴白板扉。柴車駕羸牸，草屩牧豪豨。", "夕雨紅榴拆，新秋綠芋肥。餉田桑下憩，旁舍草中歸。", "住處名愚谷，何煩問是非。"]'),
('yuding-35','沈十四拾遺新竹生讀經處同諸公之作','王維','唐','御定全唐诗','yuding','','[]','閒居日清靜，修竹自檀欒。嫩節留餘籜，新業出舊闌。',60,'御定全唐詩/json/127.json','["閒居日清靜，修竹自檀欒。嫩節留餘籜，新業出舊闌。", "細枝風響亂，疏影月光寒。樂府裁龍笛，漁家伐釣竿。", "何如道門裏，青翠拂仙壇。"]'),
('yuding-36','雜詩','王維','唐','御定全唐诗','yuding','','[]','朝因折楊柳，相見洛陽隅。楚國無如妾，秦家自有夫。',60,'御定全唐詩/json/127.json','["朝因折楊柳，相見洛陽隅。楚國無如妾，秦家自有夫。", "對人傳玉腕，映燭解羅襦。人見東方騎，皆言夫婿殊。", "持謝金吾子，煩君提玉壺。"]'),
('yuding-37','哭褚司馬','王維','唐','御定全唐诗','yuding','','[]','妄識皆心累，浮生定死媒。誰言老龍吉，未免伯牛災。',72,'御定全唐詩/json/127.json','["妄識皆心累，浮生定死媒。誰言老龍吉，未免伯牛災。", "故有求仙藥，仍餘遁俗杯。山川秋樹苦，窗戶夜泉哀。", "尚憶青騾去，甯知白馬來。漢臣修史記，莫蔽褚生才。"]'),
('yuding-38','過沈居士山居哭之','王維','唐','御定全唐诗','yuding','','[]','楊朱來此哭，桑扈返於真。獨自成千古，依然舊四鄰。',96,'御定全唐詩/json/127.json','["楊朱來此哭，桑扈返於真。獨自成千古，依然舊四鄰。", "閑簷喧鳥鵲，故榻滿埃塵。曙月孤鶯囀，空山五柳春。", "野花愁對客，泉水咽迎人。善卷明時隱，黔婁在日貧。", "逝川嗟爾命，丘井歎吾身。前後徒言隔，相悲詎幾晨。"]'),
('yuding-39','哭祖六自虛','王維','唐','御定全唐诗','yuding','','[]','否極嘗聞泰，嗟君獨不然。憫凶才稚齒，羸疾主中年。',384,'御定全唐詩/json/127.json','["否極嘗聞泰，嗟君獨不然。憫凶才稚齒，羸疾主中年。", "餘力文章秀，生知禮樂全。翰留天帳覽，詞入帝宮傳。", "國訝終軍少，人知賈誼賢。公卿盡虛左，朋識共推先。", "不恨依窮轍，終期濟巨川。才雄望羔雁，壽促背貂蟬。", "福善聞前錄，殲良昧上玄。何辜鎩鸞翮，底事碎龍泉。", "鵩起長沙賦，麟終曲阜編。域中君道廣，海內我情偏。", "乍失疑猶見，沉思悟絕緣。生前不忍別，死後向誰宣。", "為此情難盡，彌令憶更纏。本家清渭曲，歸葬舊塋邊。", "永去長安道，徒聞京兆阡。旌車出郊甸，鄉國隱雲天。", "定作無期別，寧同舊日旋。候門家屬苦，行路國人憐。", "送客哀難進，征途泥複前。贈言為挽曲，奠席是離筵。", "念昔同攜手，風期不暫捐。南山俱隱逸，東洛類神仙。", "未省音容間，那堪生死遷。花時金穀飲，月夜竹林眠。", "滿地傳都賦，傾朝看藥船。群公咸屬目，微物敢齊肩。", "謬合同人旨，而將玉樹連。不期先掛劍，長恐後施鞭。", "為善吾無矣，知音子絕焉。琴聲縱不沒，終亦繼悲弦。"]'),
('yuding-0','奉和聖制從蓬萊向興慶閣道中留春雨中春望之作應制','王維','唐','御定全唐诗','yuding','','[]','渭水自縈秦塞曲，黃山舊繞漢宮斜。鑾輿迥出千門柳，',40,'御定全唐詩/json/128.json','["渭水自縈秦塞曲，黃山舊繞漢宮斜。鑾輿迥出千門柳，", "為乘陽氣行時令，不是宸遊玩物華。"]'),
('yuding-1','大同殿柱產玉芝龍池上有慶雲神光照殿百官共覩聖恩便賜宴樂敢書即事','王維','唐','御定全唐诗','yuding','','[]','欲笑周文歌宴鎬，遙輕漢武樂橫汾。豈知玉殿生三秀，',40,'御定全唐詩/json/128.json','["欲笑周文歌宴鎬，遙輕漢武樂橫汾。豈知玉殿生三秀，", "共歡天意同人意，萬歲千秋奉聖君。"]'),
('yuding-2','敕賜百官櫻桃','王維','唐','御定全唐诗','yuding','','[]','芙蓉闕下會千官，紫禁朱櫻出上闌。才是寢園春薦後，',40,'御定全唐詩/json/128.json','["芙蓉闕下會千官，紫禁朱櫻出上闌。才是寢園春薦後，", "飽食不須愁內熱，大官還有蔗漿寒。"]'),
('yuding-3','敕借岐王九成宮避暑應教','王維','唐','御定全唐诗','yuding','','[]','帝子遠辭丹鳳闕，天書遙借翠微宮。隔窗雲霧生衣上，',40,'御定全唐詩/json/128.json','["帝子遠辭丹鳳闕，天書遙借翠微宮。隔窗雲霧生衣上，", "仙家未必能勝此，何事吹笙向碧空。"]'),
('yuding-4','和賈舍人早朝大明宮之作','王維','唐','御定全唐诗','yuding','','[]','絳幘雞人送曉籌，尚衣方進翠雲裘。九天閶闔開宮殿，',40,'御定全唐詩/json/128.json','["絳幘雞人送曉籌，尚衣方進翠雲裘。九天閶闔開宮殿，", "朝罷須裁五色詔，佩聲歸向鳳池頭。"]'),
('yuding-5','和太常韋主簿五郎溫湯寓目之作','王維','唐','御定全唐诗','yuding','','[]','漢主離宮接露臺，秦川一半夕陽開。青山儘是朱旗繞，',40,'御定全唐詩/json/128.json','["漢主離宮接露臺，秦川一半夕陽開。青山儘是朱旗繞，", "聞道甘泉能獻賦，懸知獨有子雲才。"]'),
('yuding-6','苑舍人能書梵字兼達梵音，皆曲盡其妙，戲為之贈','王維','唐','御定全唐诗','yuding','','[]','名儒待詔滿公車。才子為郎典石渠。蓮花法藏心懸悟，',40,'御定全唐詩/json/128.json','["名儒待詔滿公車。才子為郎典石渠。蓮花法藏心懸悟，", "故舊相望在三事，願君莫厭承明廬。"]'),
('yuding-7','重酬苑郎中','王維','唐','御定全唐诗','yuding','','[]','何幸含香奉至尊，多慚未報主人恩。草木盡能酬雨露，',40,'御定全唐詩/json/128.json','["何幸含香奉至尊，多慚未報主人恩。草木盡能酬雨露，", "揚子解嘲徒自遣，馮唐已老複何論。"]'),
('yuding-8','酬郭給事','王維','唐','御定全唐诗','yuding','','[]','洞門高閣靄餘輝，桃李陰陰柳絮飛。禁裏疏鐘官舍晚，',40,'御定全唐詩/json/128.json','["洞門高閣靄餘輝，桃李陰陰柳絮飛。禁裏疏鐘官舍晚，", "強欲從君無那老，將因臥病解朝衣。"]'),
('yuding-9','出塞','王維','唐','御定全唐诗','yuding','','[]','居延城外獵天驕，白草連山野火燒。暮雲空磧時驅馬，',40,'御定全唐詩/json/128.json','["居延城外獵天驕，白草連山野火燒。暮雲空磧時驅馬，", "玉靶角弓珠勒馬，漢家將賜霍嫖姚。"]'),
('yuding-10','既蒙宥罪旋復拜官伏感聖恩竊書鄙意兼奉簡新除使君等諸公','王維','唐','御定全唐诗','yuding','','[]','忽蒙漢詔還冠冕，始覺殷王解網羅。日比皇明猶自暗，',40,'御定全唐詩/json/128.json','["忽蒙漢詔還冠冕，始覺殷王解網羅。日比皇明猶自暗，", "聞道百城新佩印，還來雙闕共鳴珂。"]'),
('yuding-11','送方尊師歸嵩山','王維','唐','御定全唐诗','yuding','','[]','仙官欲往九龍潭，旄節朱幡倚石龕。山壓天中半天上，',40,'御定全唐詩/json/128.json','["仙官欲往九龍潭，旄節朱幡倚石龕。山壓天中半天上，", "借問迎來雙白鶴，已曾衡岳送蘇耽。"]'),
('yuding-12','送楊少府貶郴州','王維','唐','御定全唐诗','yuding','','[]','明到衡山與洞庭，若為秋月聽猿聲。愁看北渚三湘遠，',40,'御定全唐詩/json/128.json','["明到衡山與洞庭，若為秋月聽猿聲。愁看北渚三湘遠，", "長沙不久留才子，賈誼何須吊屈平。"]'),
('yuding-13','過乘如禪師蕭居士嵩丘蘭若','王維','唐','御定全唐诗','yuding','','[]','無著天親弟與兄，嵩丘蘭若一峰晴。食隨鳴磬巢烏下，',40,'御定全唐詩/json/128.json','["無著天親弟與兄，嵩丘蘭若一峰晴。食隨鳴磬巢烏下，", "深洞長松何所有，儼然天竺古先生。"]'),
('yuding-14','春日與裴迪過新昌裏訪呂逸人不遇','王維','唐','御定全唐诗','yuding','','[]','桃源一向絕風塵，柳市南頭訪隱淪。到門不敢題凡鳥，',40,'御定全唐詩/json/128.json','["桃源一向絕風塵，柳市南頭訪隱淪。到門不敢題凡鳥，", "閉戶著書多歲月，種松皆老作龍鱗。"]'),
('yuding-15','酌酒與裴迪','王維','唐','御定全唐诗','yuding','','[]','酌酒與君君自寬，人情翻覆似波瀾。白首相知猶按劍，',40,'御定全唐詩/json/128.json','["酌酒與君君自寬，人情翻覆似波瀾。白首相知猶按劍，", "世事浮雲何足問，不如高臥且加餐。"]'),
('yuding-16','輞川別業','王維','唐','御定全唐诗','yuding','','[]','不到東山向一年，歸來才及種春田。雨中草色綠堪染，',40,'御定全唐詩/json/128.json','["不到東山向一年，歸來才及種春田。雨中草色綠堪染，", "披衣倒屣且相見，相歡語笑衡門前。"]'),
('yuding-17','早秋山中作','王維','唐','御定全唐诗','yuding','','[]','無才不敢累明時，思向東溪守故籬。豈厭尚平婚嫁早，',40,'御定全唐詩/json/128.json','["無才不敢累明時，思向東溪守故籬。豈厭尚平婚嫁早，", "寂寞柴門人不到，空林獨與白雲期。"]'),
('yuding-18','積雨輞川莊作','王維','唐','御定全唐诗','yuding','','[]','積雨空林煙火遲，蒸藜炊黍餉東菑。漠漠水田飛白鷺，',40,'御定全唐詩/json/128.json','["積雨空林煙火遲，蒸藜炊黍餉東菑。漠漠水田飛白鷺，", "野老與人爭席罷，海鷗何事更相疑。"]'),
('yuding-19','聽百舌鳥','王維','唐','御定全唐诗','yuding','','[]','上蘭門外草萋萋，未央宮中花裏棲。亦有相隨過御苑，',40,'御定全唐詩/json/128.json','["上蘭門外草萋萋，未央宮中花裏棲。亦有相隨過御苑，", "萬戶千門應覺曉，建章何必聽鳴雞。"]'),
('yuding-20','息夫人','王維','唐','御定全唐诗','yuding','','[]','莫以今時寵，難忘舊日恩。看花滿眼淚，不共楚王言。',24,'御定全唐詩/json/128.json','["莫以今時寵，難忘舊日恩。看花滿眼淚，不共楚王言。"]'),
('yuding-21','班婕妤三首','王維','唐','御定全唐诗','yuding','','[]','玉窗螢影度，金殿人聲絕。秋夜守羅帷，孤燈耿不滅。',72,'御定全唐詩/json/128.json','["玉窗螢影度，金殿人聲絕。秋夜守羅帷，孤燈耿不滅。", "宮殿生秋草，君王恩幸疏。那堪聞鳳吹，門外度金輿。", "怪來妝閣閉，朝下不相迎。總向春園裏，花間笑語聲。"]'),
('yuding-22','輞川集：孟城坳','王維','唐','御定全唐诗','yuding','','[]','新家孟城口，古木餘衰柳。來者複為誰，空悲昔人有。',24,'御定全唐詩/json/128.json','["新家孟城口，古木餘衰柳。來者複為誰，空悲昔人有。"]'),
('yuding-23','輞川集：華子岡','王維','唐','御定全唐诗','yuding','','[]','飛鳥去不窮，連山複秋色。上下華子岡，惆悵情何極。',24,'御定全唐詩/json/128.json','["飛鳥去不窮，連山複秋色。上下華子岡，惆悵情何極。"]'),
('yuding-24','輞川集：文杏館','王維','唐','御定全唐诗','yuding','','[]','文杏裁為梁，香茅結為宇。不知棟裏雲，去作人間雨。',24,'御定全唐詩/json/128.json','["文杏裁為梁，香茅結為宇。不知棟裏雲，去作人間雨。"]'),
('yuding-25','輞川集：斤竹嶺','王維','唐','御定全唐诗','yuding','','[]','檀欒映空曲，青翠漾漣漪。暗入商山路，樵人不可知。',24,'御定全唐詩/json/128.json','["檀欒映空曲，青翠漾漣漪。暗入商山路，樵人不可知。"]'),
('yuding-26','輞川集：鹿柴','王維','唐','御定全唐诗','yuding','','[]','空山不見人，但聞人語響。返景入深林，複照青苔上。',24,'御定全唐詩/json/128.json','["空山不見人，但聞人語響。返景入深林，複照青苔上。"]'),
('yuding-27','輞川集：木蘭柴','王維','唐','御定全唐诗','yuding','','[]','秋山斂餘照，飛鳥逐前侶。彩翠時分明，夕嵐無處所。',24,'御定全唐詩/json/128.json','["秋山斂餘照，飛鳥逐前侶。彩翠時分明，夕嵐無處所。"]'),
('yuding-28','輞川集：茱萸沜','王維','唐','御定全唐诗','yuding','','[]','結實紅且綠，複如花更開。山中儻留客，置此芙蓉杯。',24,'御定全唐詩/json/128.json','["結實紅且綠，複如花更開。山中儻留客，置此芙蓉杯。"]'),
('yuding-29','輞川集：宮槐陌','王維','唐','御定全唐诗','yuding','','[]','仄徑蔭宮槐，幽陰多綠苔。應門但迎掃，畏有山僧來。',24,'御定全唐詩/json/128.json','["仄徑蔭宮槐，幽陰多綠苔。應門但迎掃，畏有山僧來。"]'),
('yuding-30','輞川集：臨湖亭','王維','唐','御定全唐诗','yuding','','[]','輕舸迎上客，悠悠湖上來。當軒對尊酒，四面芙蓉開。',24,'御定全唐詩/json/128.json','["輕舸迎上客，悠悠湖上來。當軒對尊酒，四面芙蓉開。"]'),
('yuding-31','輞川集：南垞','王維','唐','御定全唐诗','yuding','','[]','輕舟南垞去，北垞淼難即。隔浦望人家，遙遙不相識。',24,'御定全唐詩/json/128.json','["輕舟南垞去，北垞淼難即。隔浦望人家，遙遙不相識。"]'),
('yuding-32','輞川集：欹湖','王維','唐','御定全唐诗','yuding','','[]','吹簫淩極浦，日暮送夫君。湖上一回首，青山卷白雲。',24,'御定全唐詩/json/128.json','["吹簫淩極浦，日暮送夫君。湖上一回首，青山卷白雲。"]'),
('yuding-33','輞川集：柳浪','王維','唐','御定全唐诗','yuding','','[]','分行接綺樹，倒影入清漪。不學禦溝上，春風傷別離。',24,'御定全唐詩/json/128.json','["分行接綺樹，倒影入清漪。不學禦溝上，春風傷別離。"]'),
('yuding-34','輞川集：欒家瀨','王維','唐','御定全唐诗','yuding','','[]','颯颯秋雨中，淺淺石溜瀉。跳波自相濺，白鷺驚複下。',24,'御定全唐詩/json/128.json','["颯颯秋雨中，淺淺石溜瀉。跳波自相濺，白鷺驚複下。"]'),
('yuding-35','輞川集：金屑泉','王維','唐','御定全唐诗','yuding','','[]','日飲金屑泉，少當千餘歲。翠鳳翊文螭，羽節朝玉帝。',24,'御定全唐詩/json/128.json','["日飲金屑泉，少當千餘歲。翠鳳翊文螭，羽節朝玉帝。"]'),
('yuding-36','輞川集：白石灘','王維','唐','御定全唐诗','yuding','','[]','清淺白石灘，綠蒲向堪把。家住水東西，浣紗明月下。',24,'御定全唐詩/json/128.json','["清淺白石灘，綠蒲向堪把。家住水東西，浣紗明月下。"]'),
('yuding-37','輞川集：北垞','王維','唐','御定全唐诗','yuding','','[]','北垞湖水北，雜樹映朱闌。逶迤南川水，明滅青林端。',24,'御定全唐詩/json/128.json','["北垞湖水北，雜樹映朱闌。逶迤南川水，明滅青林端。"]'),
('yuding-38','輞川集：竹裏館','王維','唐','御定全唐诗','yuding','','[]','獨坐幽篁裏，彈琴複長嘯。深林人不知，明月來相照。',24,'御定全唐詩/json/128.json','["獨坐幽篁裏，彈琴複長嘯。深林人不知，明月來相照。"]'),
('yuding-39','輞川集：辛夷塢','王維','唐','御定全唐诗','yuding','','[]','木末芙蓉花，山中發紅萼。澗戶寂無人，紛紛開且落。',24,'御定全唐詩/json/128.json','["木末芙蓉花，山中發紅萼。澗戶寂無人，紛紛開且落。"]'),
('yuding-40','輞川集：漆園','王維','唐','御定全唐诗','yuding','','[]','古人非傲吏，自闕經世務。偶寄一微官，婆娑數株樹。',24,'御定全唐詩/json/128.json','["古人非傲吏，自闕經世務。偶寄一微官，婆娑數株樹。"]'),
('yuding-41','輞川集：椒園','王維','唐','御定全唐诗','yuding','','[]','桂尊迎帝子，杜若贈佳人。椒漿奠瑤席，欲下雲中君。',24,'御定全唐詩/json/128.json','["桂尊迎帝子，杜若贈佳人。椒漿奠瑤席，欲下雲中君。"]'),
('yuding-42','皇甫嶽雲溪雜題五首：鳥鳴澗','王維','唐','御定全唐诗','yuding','','[]','人閑桂花落，夜靜春山空。月出驚山鳥，時鳴春澗中。',24,'御定全唐詩/json/128.json','["人閑桂花落，夜靜春山空。月出驚山鳥，時鳴春澗中。"]'),
('yuding-43','皇甫嶽雲溪雜題五首：蓮花塢','王維','唐','御定全唐诗','yuding','','[]','日日採蓮去，洲長多暮歸。弄篙莫濺水，畏濕紅蓮衣。',24,'御定全唐詩/json/128.json','["日日採蓮去，洲長多暮歸。弄篙莫濺水，畏濕紅蓮衣。"]'),
('yuding-44','皇甫嶽雲溪雜題五首：鸕鷀堰','王維','唐','御定全唐诗','yuding','','[]','乍向紅蓮沒，複出清蒲颺。獨立何褵褷，銜魚古查上。',24,'御定全唐詩/json/128.json','["乍向紅蓮沒，複出清蒲颺。獨立何褵褷，銜魚古查上。"]'),
('yuding-45','皇甫嶽雲溪雜題五首：上平田','王維','唐','御定全唐诗','yuding','','[]','朝耕上平田，暮耕上平田。借問問津者，寧知沮溺賢。',24,'御定全唐詩/json/128.json','["朝耕上平田，暮耕上平田。借問問津者，寧知沮溺賢。"]'),
('yuding-46','皇甫嶽雲溪雜題五首：萍池','王維','唐','御定全唐诗','yuding','','[]','春池深且廣，會待輕舟回。靡靡綠萍合，垂楊掃複開。',24,'御定全唐詩/json/128.json','["春池深且廣，會待輕舟回。靡靡綠萍合，垂楊掃複開。"]'),
('yuding-47','答裴迪輞口遇雨憶終南山之作','王維','唐','御定全唐诗','yuding','','[]','淼淼寒流廣，蒼蒼秋雨晦。君問終南山，心知白雲外。',24,'御定全唐詩/json/128.json','["淼淼寒流廣，蒼蒼秋雨晦。君問終南山，心知白雲外。"]'),
('yuding-48','山中寄諸弟妹','王維','唐','御定全唐诗','yuding','','[]','山中多法侶，禪誦自為群。城郭遙相望，唯應見白雲。',24,'御定全唐詩/json/128.json','["山中多法侶，禪誦自為群。城郭遙相望，唯應見白雲。"]'),
('yuding-49','聞裴秀才迪吟詩因戲贈','王維','唐','御定全唐诗','yuding','','[]','猿吟一何苦，愁朝複悲夕。莫作巫峽聲，腸斷秋江客。',24,'御定全唐詩/json/128.json','["猿吟一何苦，愁朝複悲夕。莫作巫峽聲，腸斷秋江客。"]'),
('yuding-50','贈韋穆十八','王維','唐','御定全唐诗','yuding','','[]','與君青眼客，共有白雲心。不向東山去，日令春草深。',24,'御定全唐詩/json/128.json','["與君青眼客，共有白雲心。不向東山去，日令春草深。"]'),
('yuding-51','送別','王維','唐','御定全唐诗','yuding','','[]','山中相送罷，日暮掩柴扉。春草明年綠，王孫歸不歸。',24,'御定全唐詩/json/128.json','["山中相送罷，日暮掩柴扉。春草明年綠，王孫歸不歸。"]'),
('yuding-52','臨高臺送黎拾遺','王維','唐','御定全唐诗','yuding','','[]','相送臨高臺，川原杳何極。日暮飛鳥還，行人去不息。',24,'御定全唐詩/json/128.json','["相送臨高臺，川原杳何極。日暮飛鳥還，行人去不息。"]'),
('yuding-53','別輞川別業','王維','唐','御定全唐诗','yuding','','[]','依遲動車馬，惆悵出松蘿。忍別青山去，其如綠水何。',24,'御定全唐詩/json/128.json','["依遲動車馬，惆悵出松蘿。忍別青山去，其如綠水何。"]'),
('yuding-54','崔九弟欲往南山馬上口號與別','王維','唐','御定全唐诗','yuding','','[]','城隅一分手，幾日還相見。山中有桂花，莫待花如霰。',24,'御定全唐詩/json/128.json','["城隅一分手，幾日還相見。山中有桂花，莫待花如霰。"]'),
('yuding-55','題友人雲母障子','王維','唐','御定全唐诗','yuding','','[]','君家雲母障，時向野庭開。自有山泉入，非因采畫來。',24,'御定全唐詩/json/128.json','["君家雲母障，時向野庭開。自有山泉入，非因采畫來。"]'),
('yuding-56','紅牡丹','王維','唐','御定全唐诗','yuding','','[]','綠豔閑且靜，紅衣淺複深。花心愁欲斷，春色豈知心。',24,'御定全唐詩/json/128.json','["綠豔閑且靜，紅衣淺複深。花心愁欲斷，春色豈知心。"]'),
('yuding-57','左掖梨花','王維','唐','御定全唐诗','yuding','','[]','閑灑階邊草，輕隨箔外風。黃鶯弄不足，銜入未央宮。',24,'御定全唐詩/json/128.json','["閑灑階邊草，輕隨箔外風。黃鶯弄不足，銜入未央宮。"]'),
('yuding-58','菩提寺禁口號又示裴迪','王維','唐','御定全唐诗','yuding','','[]','安得舍羅網，拂衣辭世喧。悠然策藜杖，歸向桃花源。',24,'御定全唐詩/json/128.json','["安得舍羅網，拂衣辭世喧。悠然策藜杖，歸向桃花源。"]'),
('yuding-59','雜詩三首','王維','唐','御定全唐诗','yuding','','[]','家住孟津河，門對孟津口。常有江南船，寄書家中否。',72,'御定全唐詩/json/128.json','["家住孟津河，門對孟津口。常有江南船，寄書家中否。", "君自故鄉來，應知故鄉事。來日綺窗前，寒梅著花未。", "已見寒梅發，複聞啼鳥聲。心心視春草，畏向階前生。"]'),
('yuding-60','崔興宗寫真詠','王維','唐','御定全唐诗','yuding','','[]','畫君年少時，如今君已老。今時新識人，知君舊時好。',24,'御定全唐詩/json/128.json','["畫君年少時，如今君已老。今時新識人，知君舊時好。"]'),
('yuding-61','山茱萸','王維','唐','御定全唐诗','yuding','','[]','朱實山下開，清香寒更發。幸與叢桂花，窗前向秋月。',24,'御定全唐詩/json/128.json','["朱實山下開，清香寒更發。幸與叢桂花，窗前向秋月。"]'),
('yuding-62','相思','王維','唐','御定全唐诗','yuding','','[]','紅豆生南國，秋來發故枝。願君多採擷，此物最相思。',24,'御定全唐詩/json/128.json','["紅豆生南國，秋來發故枝。願君多採擷，此物最相思。"]'),
('yuding-63','書事','王維','唐','御定全唐诗','yuding','','[]','輕陰閣小雨，深院晝慵開。坐看蒼苔色，欲上人衣來。',24,'御定全唐詩/json/128.json','["輕陰閣小雨，深院晝慵開。坐看蒼苔色，欲上人衣來。"]'),
('yuding-64','哭孟浩然','王維','唐','御定全唐诗','yuding','','[]','故人不可見，漢水日東流。借問襄陽老，江山空蔡州。',24,'御定全唐詩/json/128.json','["故人不可見，漢水日東流。借問襄陽老，江山空蔡州。"]'),
('yuding-65','闕題二首','王維','唐','御定全唐诗','yuding','','[]','荊溪白石出，天寒紅葉稀。山路元無雨，空翠濕人衣。',48,'御定全唐詩/json/128.json','["荊溪白石出，天寒紅葉稀。山路元無雨，空翠濕人衣。", "相看不忍發，慘澹暮潮平。語罷更攜手，月明洲渚生。"]'),
('yuding-66','田園樂七首','王維','唐','御定全唐诗','yuding','','[]','厭見千門萬戶，經過北裏南鄰。',196,'御定全唐詩/json/128.json','["厭見千門萬戶，經過北裏南鄰。", "官府鳴珂有底，崆峒散發何人。", "再見封侯萬戶，立談賜璧一雙。", "詎勝耦耕南畝，何如高臥東窗。", "采菱渡頭風急，策杖林西日斜。", "杏樹壇邊漁父，桃花源裏人家。", "萋萋春草秋綠，落落長松夏寒。", "牛羊自歸村巷，童稚不識衣冠。", "山下孤煙遠村，天邊獨樹高原。", "一瓢顏回陋巷，五柳先生對門。", "桃紅複含宿雨，柳綠更帶朝煙。", "花落家童未掃，鶯啼山客猶眠。", "酌酒會臨泉水，抱琴好倚長松。", "南園露葵朝折，東谷黃粱夜舂。"]'),
('yuding-67','少年行四首','王維','唐','御定全唐诗','yuding','','[]','新豐美酒鬥十千，咸陽遊俠多少年。',128,'御定全唐詩/json/128.json','["新豐美酒鬥十千，咸陽遊俠多少年。", "相逢意氣為君飲，系馬高樓垂柳邊。", "出身仕漢羽林郎，初隨驃騎戰漁陽。", "孰知不向邊庭苦，縱死猶聞俠骨香。", "一身能擘兩雕弧，虜騎千重只似無。", "偏坐金鞍調白羽，紛紛射殺五單于。", "漢家君臣歡宴終，高議雲台論戰功。", "天子臨軒賜侯印，將軍佩出明光宮。"]'),
('yuding-68','贈裴旻將軍','王維','唐','御定全唐诗','yuding','','[]','腰間寶劍七星文，臂上雕弓百戰勳。',32,'御定全唐詩/json/128.json','["腰間寶劍七星文，臂上雕弓百戰勳。", "見說雲中擒黠虜，始知天上有將軍。"]'),
('yuding-69','九月九日憶山東兄弟','王維','唐','御定全唐诗','yuding','','[]','獨在異鄉為異客，每逢佳節倍思親。',32,'御定全唐詩/json/128.json','["獨在異鄉為異客，每逢佳節倍思親。", "遙知兄弟登高處，遍插茱萸少一人。"]'),
('yuding-70','送王尊師歸蜀中拜掃','王維','唐','御定全唐诗','yuding','','[]','大羅天上神仙客，濯錦江頭花柳春。',32,'御定全唐詩/json/128.json','["大羅天上神仙客，濯錦江頭花柳春。", "不為碧雞稱使者，唯令白鶴報鄉人。"]'),
('yuding-71','渭城曲','王維','唐','御定全唐诗','yuding','','[]','渭城朝雨浥輕塵，客舍青青楊柳春。',32,'御定全唐詩/json/128.json','["渭城朝雨浥輕塵，客舍青青楊柳春。", "勸君更盡一杯酒，西出陽關無故人。"]'),
('yuding-72','齊州送祖二','王維','唐','御定全唐诗','yuding','','[]','送君南浦淚如絲，君向東州使我悲。',32,'御定全唐詩/json/128.json','["送君南浦淚如絲，君向東州使我悲。", "為報故人憔悴盡，如今不似洛陽時。"]'),
('yuding-73','送韋評事','王維','唐','御定全唐诗','yuding','','[]','欲逐將軍取右賢，沙場走馬向居延。',32,'御定全唐詩/json/128.json','["欲逐將軍取右賢，沙場走馬向居延。", "遙知漢使蕭關外，愁見孤城落日邊。"]'),
('yuding-74','靈雲池送從弟','王維','唐','御定全唐诗','yuding','','[]','金杯緩酌清歌轉，畫舸輕移豔舞回。',32,'御定全唐詩/json/128.json','["金杯緩酌清歌轉，畫舸輕移豔舞回。", "自歎鶺鴒臨水別，不同鴻雁向池來。"]'),
('yuding-75','送沈子歸江東','王維','唐','御定全唐诗','yuding','','[]','楊柳渡頭行客稀，罟師蕩槳向臨圻。',32,'御定全唐詩/json/128.json','["楊柳渡頭行客稀，罟師蕩槳向臨圻。", "唯有相思似春色，江南江北送君歸。"]'),
('yuding-76','與盧員外象過崔處士興宗林亭','王維','唐','御定全唐诗','yuding','','[]','綠樹重陰蓋四鄰，青苔日厚自無塵。',32,'御定全唐詩/json/128.json','["綠樹重陰蓋四鄰，青苔日厚自無塵。", "科頭箕踞長松下，白眼看他世上人。"]'),
('yuding-77','寒食汜上作','王維','唐','御定全唐诗','yuding','','[]','廣武城邊逢暮春，汶陽歸客淚沾巾。',32,'御定全唐詩/json/128.json','["廣武城邊逢暮春，汶陽歸客淚沾巾。", "落花寂寂啼山鳥，楊柳青青渡水人。"]'),
('yuding-78','戲題輞川別業','王維','唐','御定全唐诗','yuding','','[]','柳條拂地不須折，松樹披雲從更長。',32,'御定全唐詩/json/128.json','["柳條拂地不須折，松樹披雲從更長。", "藤花欲暗藏猱子，柏葉初齊養麝香。"]'),
('yuding-79','戲題磐石','王維','唐','御定全唐诗','yuding','','[]','可憐磐石臨泉水，複有垂楊拂酒杯。',32,'御定全唐詩/json/128.json','["可憐磐石臨泉水，複有垂楊拂酒杯。", "若道春風不解意，何因吹送落花來。"]'),
('yuding-80','寄河上段十六','王維','唐','御定全唐诗','yuding','','[]','與君相見即相親，聞道君家在孟津。',32,'御定全唐詩/json/128.json','["與君相見即相親，聞道君家在孟津。", "為見行舟試借問，客中時有洛陽人。"]'),
('yuding-81','菩提寺禁裴迪來相看說逆賊等凝碧池上作音樂供奉人等舉聲便一時淚下私成口號誦示裴迪','王維','唐','御定全唐诗','yuding','','[]','萬戶傷心生野煙，百僚何日更朝天。',32,'御定全唐詩/json/128.json','["萬戶傷心生野煙，百僚何日更朝天。", "秋槐葉落空宮裏，凝碧池頭奏管弦。"]'),
('yuding-82','涼州賽神','王維','唐','御定全唐诗','yuding','','[]','涼州城外少行人，百尺峰頭望虜塵。',32,'御定全唐詩/json/128.json','["涼州城外少行人，百尺峰頭望虜塵。", "健兒擊鼓吹羌笛，共賽城東越騎神。"]'),
('yuding-83','戲嘲史寰','王維','唐','御定全唐诗','yuding','','[]','清風細雨濕梅花，驟馬先過碧玉家。',32,'御定全唐詩/json/128.json','["清風細雨濕梅花，驟馬先過碧玉家。", "正值楚王宮裏至，門前初下七香車。"]'),
('yuding-84','歎白髮','王維','唐','御定全唐诗','yuding','','[]','宿昔朱顏成暮齒，須臾白髮變垂髫。',32,'御定全唐詩/json/128.json','["宿昔朱顏成暮齒，須臾白髮變垂髫。", "一生幾許傷心事，不向空門何處銷。"]'),
('yuding-85','伊州歌','王維','唐','御定全唐诗','yuding','','[]','清風明月苦相思，蕩子從戎十載餘。',32,'御定全唐詩/json/128.json','["清風明月苦相思，蕩子從戎十載餘。", "征人去日殷勤囑，歸雁來時數附書。"]'),
('yuding-86','送殷四葬','王維','唐','御定全唐诗','yuding','','[]','送君返葬石樓山，松柏蒼蒼賓馭還。',32,'御定全唐詩/json/128.json','["送君返葬石樓山，松柏蒼蒼賓馭還。", "埋骨白雲長已矣，空餘流水向人間。"]'),
('yuding-87','疑夢','王維','唐','御定全唐诗','yuding','','[]','莫驚寵辱空憂喜，莫計恩讎浪苦辛。',32,'御定全唐詩/json/128.json','["莫驚寵辱空憂喜，莫計恩讎浪苦辛。", "黃帝孔丘何處問，安知不是夢中身。"]'),
('yuding-88','句','王維','唐','御定全唐诗','yuding','','[]','人家在仙掌，雲氣欲生衣。',29,'御定全唐詩/json/128.json','["人家在仙掌，雲氣欲生衣。", "知古齋主精校2000。01。22。"]'),
('yuding-0','古離別','王縉','唐','御定全唐诗','yuding','','[]','下階欲離別，相對映蘭叢。含辭未及吐，淚落蘭叢中。',48,'御定全唐詩/json/129.json','["下階欲離別，相對映蘭叢。含辭未及吐，淚落蘭叢中。", "高堂靜秋日，羅衣飄暮風。誰能待明月，回首見床空。"]'),
('yuding-1','青雀歌','王縉','唐','御定全唐诗','yuding','','[]','林間青雀兒，來往翩翩繞一枝。',30,'御定全唐詩/json/129.json','["林間青雀兒，來往翩翩繞一枝。", "莫言不解銜環報，但問君恩今若為。"]'),
('yuding-2','同王昌齡裴迪遊青龍寺曇壁上人兄院集和兄維','王縉','唐','御定全唐诗','yuding','','[]','林中空寂舍，階下終南山。高臥一床上，回看六合間。',60,'御定全唐詩/json/129.json','["林中空寂舍，階下終南山。高臥一床上，回看六合間。", "浮雲幾處滅，飛鳥何時還。問義天人接，無心世界閑。", "誰知大隱者，兄弟自追攀。"]'),
('yuding-3','別輞川別業','王縉','唐','御定全唐诗','yuding','','[]','山月曉仍在，林風涼不絕。殷勤如有情，惆悵令人別。',24,'御定全唐詩/json/129.json','["山月曉仍在，林風涼不絕。殷勤如有情，惆悵令人別。"]'),
('yuding-4','與盧員外象過崔處士興宗林亭','王縉','唐','御定全唐诗','yuding','','[]','身名不問十年餘，老大誰能更讀書。',32,'御定全唐詩/json/129.json','["身名不問十年餘，老大誰能更讀書。", "林中獨酌鄰家酒，門外時聞長者車。"]'),
('yuding-5','九日作','王縉','唐','御定全唐诗','yuding','','[]','莫將邊地比京都，八月嚴霜草已枯。',32,'御定全唐詩/json/129.json','["莫將邊地比京都，八月嚴霜草已枯。", "今日登高樽酒裏，不知能有菊花無。"]'),
('yuding-6','送孫秀才','王縉','唐','御定全唐诗','yuding','','[]','帝城風日好，況複建平家。玉枕雙紋簟，金盤五色瓜。',48,'御定全唐詩/json/129.json','["帝城風日好，況複建平家。玉枕雙紋簟，金盤五色瓜。", "山中無魯酒，松下飯胡麻。莫厭田家苦，歸期遠複賒。"]'),
('yuding-7','遊悟真寺','王縉','唐','御定全唐诗','yuding','','[]','聞道黃金地，仍開白玉田。擲山移巨石，咒嶺出飛泉。',144,'御定全唐詩/json/129.json','["聞道黃金地，仍開白玉田。擲山移巨石，咒嶺出飛泉。", "猛虎同三徑，愁猿學四禪。買香然綠桂，乞火蹈紅蓮。", "草色搖霞上，松聲泛月邊。山河窮百二，世界接三千。", "梵宇聊憑視，王城遂渺然。灞陵才出樹，渭水欲連天。", "遠縣分朱郭，孤村起白煙。望雲思聖主，披霧憶群賢。", "薄宦慚屍素，終身擬尚玄。誰知草庵客，曾和柏梁篇。"]'),
('yuding-8','青龍寺曇壁上人院集','裴迪','唐','御定全唐诗','yuding','','[]','靈境信為絕，法堂出塵氛。自然成高致，向下看浮雲。',60,'御定全唐詩/json/129.json','["靈境信為絕，法堂出塵氛。自然成高致，向下看浮雲。", "迤邐峰岫列，參差閭井分。林端遠堞見，風末疏鐘聞。", "吾師久禪寂，在世超人群。"]'),
('yuding-9','青雀歌','裴迪','唐','御定全唐诗','yuding','','[]','動息自適性，不曾妄與燕雀群。幸忝鵷鸞早相識，',22,'御定全唐詩/json/129.json','["動息自適性，不曾妄與燕雀群。幸忝鵷鸞早相識，"]'),
('yuding-10','遊感化寺曇興上人山院','裴迪','唐','御定全唐诗','yuding','','[]','不遠灞陵邊，安居向十年。入門穿竹徑，留客聽山泉。',48,'御定全唐詩/json/129.json','["不遠灞陵邊，安居向十年。入門穿竹徑，留客聽山泉。", "鳥囀深林裏，心閑落照前。浮名竟何益，從此願棲禪。"]'),
('yuding-11','夏日過青龍寺謁操禪師','裴迪','唐','御定全唐诗','yuding','','[]','安禪一室內，左右竹亭幽。有法知不染，無言誰敢酬。',48,'御定全唐詩/json/129.json','["安禪一室內，左右竹亭幽。有法知不染，無言誰敢酬。", "鳥飛爭向夕，蟬噪已先秋。煩暑自茲適，清涼何所求。"]'),
('yuding-12','春日與王右丞過新昌裏訪呂逸人不遇','裴迪','唐','御定全唐诗','yuding','','[]','恨不逢君出荷蓑，青松白屋更無他。陶令五男曾不有，',40,'御定全唐詩/json/129.json','["恨不逢君出荷蓑，青松白屋更無他。陶令五男曾不有，", "聞說桃源好迷客，不如高臥眄庭柯。"]'),
('yuding-13','輞川集二十首：孟城坳','裴迪','唐','御定全唐诗','yuding','','[]','結廬古城下，時登古城上。古城非疇昔，今人自來往。',24,'御定全唐詩/json/129.json','["結廬古城下，時登古城上。古城非疇昔，今人自來往。"]'),
('yuding-14','輞川集二十首：華子岡','裴迪','唐','御定全唐诗','yuding','','[]','落日松風起，還家草露晞。雲光侵履跡，山翠拂人衣。',24,'御定全唐詩/json/129.json','["落日松風起，還家草露晞。雲光侵履跡，山翠拂人衣。"]'),
('yuding-15','輞川集二十首：文杏館','裴迪','唐','御定全唐诗','yuding','','[]','迢迢文杏館，躋攀日已屢。南嶺與北湖，前看複回顧。',24,'御定全唐詩/json/129.json','["迢迢文杏館，躋攀日已屢。南嶺與北湖，前看複回顧。"]'),
('yuding-16','輞川集二十首：斤竹嶺','裴迪','唐','御定全唐诗','yuding','','[]','明流紆且直，綠筱密複深。一徑通山路，行歌望舊岑。',24,'御定全唐詩/json/129.json','["明流紆且直，綠筱密複深。一徑通山路，行歌望舊岑。"]'),
('yuding-17','輞川集二十首：鹿柴','裴迪','唐','御定全唐诗','yuding','','[]','日夕見寒山，便為獨往客。不知深林事，但有麏麚跡。',24,'御定全唐詩/json/129.json','["日夕見寒山，便為獨往客。不知深林事，但有麏麚跡。"]'),
('yuding-18','輞川集二十首：木蘭柴','裴迪','唐','御定全唐诗','yuding','','[]','蒼蒼落日時，鳥聲亂溪水。緣溪路轉深，幽興何時已。',24,'御定全唐詩/json/129.json','["蒼蒼落日時，鳥聲亂溪水。緣溪路轉深，幽興何時已。"]'),
('yuding-19','輞川集二十首：茱萸沜','裴迪','唐','御定全唐诗','yuding','','[]','飄香亂椒桂，布葉間檀欒。雲日雖回照，森沉猶自寒。',24,'御定全唐詩/json/129.json','["飄香亂椒桂，布葉間檀欒。雲日雖回照，森沉猶自寒。"]'),
('yuding-20','輞川集二十首：宮槐陌','裴迪','唐','御定全唐诗','yuding','','[]','門前宮槐陌，是向欹湖道。秋來山雨多，落葉無人掃。',24,'御定全唐詩/json/129.json','["門前宮槐陌，是向欹湖道。秋來山雨多，落葉無人掃。"]'),
('yuding-21','輞川集二十首：臨湖亭','裴迪','唐','御定全唐诗','yuding','','[]','當軒彌滉漾，孤月正裴回。穀口猿聲發，風傳入戶來。',24,'御定全唐詩/json/129.json','["當軒彌滉漾，孤月正裴回。穀口猿聲發，風傳入戶來。"]'),
('yuding-22','輞川集二十首：南垞','裴迪','唐','御定全唐诗','yuding','','[]','孤舟信一泊，南垞湖水岸。落日下崦嵫，清波殊淼漫。',24,'御定全唐詩/json/129.json','["孤舟信一泊，南垞湖水岸。落日下崦嵫，清波殊淼漫。"]'),
('yuding-23','輞川集二十首：欹湖','裴迪','唐','御定全唐诗','yuding','','[]','空闊湖水廣，青熒天色同。艤舟一長嘯，四面來清風。',24,'御定全唐詩/json/129.json','["空闊湖水廣，青熒天色同。艤舟一長嘯，四面來清風。"]'),
('yuding-24','輞川集二十首：柳浪','裴迪','唐','御定全唐诗','yuding','','[]','映池同一色，逐吹散如絲。結陰既得地，何謝陶家時。',24,'御定全唐詩/json/129.json','["映池同一色，逐吹散如絲。結陰既得地，何謝陶家時。"]'),
('yuding-25','輞川集二十首：欒家瀨','裴迪','唐','御定全唐诗','yuding','','[]','瀨聲喧極浦，沿涉向南津。泛泛鷗鳧渡，時時欲近人。',24,'御定全唐詩/json/129.json','["瀨聲喧極浦，沿涉向南津。泛泛鷗鳧渡，時時欲近人。"]'),
('yuding-26','輞川集二十首：金屑泉','裴迪','唐','御定全唐诗','yuding','','[]','縈渟澹不流，金碧如可拾。迎晨含素華，獨往事朝汲。',24,'御定全唐詩/json/129.json','["縈渟澹不流，金碧如可拾。迎晨含素華，獨往事朝汲。"]'),
('yuding-27','輞川集二十首：白石灘','裴迪','唐','御定全唐诗','yuding','','[]','跂石複臨水，弄波情未極。日下川上寒，浮雲澹無色。',24,'御定全唐詩/json/129.json','["跂石複臨水，弄波情未極。日下川上寒，浮雲澹無色。"]'),
('yuding-28','輞川集二十首：北垞','裴迪','唐','御定全唐诗','yuding','','[]','南山北垞下，結宇臨欹湖。每欲采樵去，扁舟出菰蒲。',24,'御定全唐詩/json/129.json','["南山北垞下，結宇臨欹湖。每欲采樵去，扁舟出菰蒲。"]'),
('yuding-29','輞川集二十首：竹裏館','裴迪','唐','御定全唐诗','yuding','','[]','來過竹裏館，日與道相親。出入唯山鳥，幽深無世人。',24,'御定全唐詩/json/129.json','["來過竹裏館，日與道相親。出入唯山鳥，幽深無世人。"]'),
('yuding-30','輞川集二十首：辛夷塢','裴迪','唐','御定全唐诗','yuding','','[]','綠堤春草合，王孫自留玩。況有辛夷花，色與芙蓉亂。',24,'御定全唐詩/json/129.json','["綠堤春草合，王孫自留玩。況有辛夷花，色與芙蓉亂。"]'),
('yuding-31','輞川集二十首：漆園','裴迪','唐','御定全唐诗','yuding','','[]','好閑早成性，果此諧宿諾。今日漆園遊，還同莊叟樂。',24,'御定全唐詩/json/129.json','["好閑早成性，果此諧宿諾。今日漆園遊，還同莊叟樂。"]'),
('yuding-32','輞川集二十首：椒園','裴迪','唐','御定全唐诗','yuding','','[]','丹刺罥人衣，芳香留過客。幸堪調鼎用，願君垂採摘。',24,'御定全唐詩/json/129.json','["丹刺罥人衣，芳香留過客。幸堪調鼎用，願君垂採摘。"]'),
('yuding-33','輞口遇雨憶終南山因獻王維','裴迪','唐','御定全唐诗','yuding','','[]','積雨晦空曲，平沙滅浮彩。輞水去悠悠，南山複何在。',24,'御定全唐詩/json/129.json','["積雨晦空曲，平沙滅浮彩。輞水去悠悠，南山複何在。"]'),
('yuding-34','崔九欲往南山馬上口號與別','裴迪','唐','御定全唐诗','yuding','','[]','歸山深淺去，須盡丘壑美。莫學武陵人，暫遊桃源裏。',24,'御定全唐詩/json/129.json','["歸山深淺去，須盡丘壑美。莫學武陵人，暫遊桃源裏。"]'),
('yuding-35','與盧員外象過崔處士興宗林亭','裴迪','唐','御定全唐诗','yuding','','[]','喬柯門裏自成陰，散發窗中曾不簪。',32,'御定全唐詩/json/129.json','["喬柯門裏自成陰，散發窗中曾不簪。", "逍遙且喜從吾事，榮寵從來非我心。"]'),
('yuding-36','西塔寺陸羽茶泉','裴迪','唐','御定全唐诗','yuding','','[]','竟陵西塔寺，蹤跡尚空虛。不獨支公住，曾經陸羽居。',48,'御定全唐詩/json/129.json','["竟陵西塔寺，蹤跡尚空虛。不獨支公住，曾經陸羽居。", "草堂荒產蛤，茶井冷生魚。一汲清泠水，高風味有餘。"]'),
('yuding-37','同王右丞送瑗公南歸','崔興宗','唐','御定全唐诗','yuding','','[]','行苦神亦秀，泠然溪上松。銅瓶與竹杖，來自祝融峰。',48,'御定全唐詩/json/129.json','["行苦神亦秀，泠然溪上松。銅瓶與竹杖，來自祝融峰。", "常願入靈岳，藏經訪遺蹤。南歸見長老，且為說心胸。"]'),
('yuding-38','青雀歌','崔興宗','唐','御定全唐诗','yuding','','[]','青扈繞青林，翩翾陋體一微禽。',30,'御定全唐詩/json/129.json','["青扈繞青林，翩翾陋體一微禽。", "不應常在藩籬下，他日淩雲誰見心。"]'),
('yuding-39','和王維敕賜百官櫻桃','崔興宗','唐','御定全唐诗','yuding','','[]','未央朝謁正逶迤，天上櫻桃錫此時。朱實初傳九華殿，',40,'御定全唐詩/json/129.json','["未央朝謁正逶迤，天上櫻桃錫此時。朱實初傳九華殿，", "聞道令人好顏色，神農本草自應知。"]'),
('yuding-40','留別王維','崔興宗','唐','御定全唐诗','yuding','','[]','駐馬欲分襟，清寒禦溝上。前山景氣佳，獨往還惆悵。',24,'御定全唐詩/json/129.json','["駐馬欲分襟，清寒禦溝上。前山景氣佳，獨往還惆悵。"]'),
('yuding-41','酬王維盧象見過林亭','崔興宗','唐','御定全唐诗','yuding','','[]','窮巷空林常閉關，悠然獨臥對前山。',32,'御定全唐詩/json/129.json','["窮巷空林常閉關，悠然獨臥對前山。", "今朝忽枉嵇生駕，倒屣開門遙解顏。"]'),
('yuding-42','送大理正攝禦史判涼州別駕','苑咸','唐','御定全唐诗','yuding','','[]','天子念西疆，咨君去不遑。垂銀棘庭印，持斧柏台綱。',48,'御定全唐詩/json/129.json','["天子念西疆，咨君去不遑。垂銀棘庭印，持斧柏台綱。", "雪下天山白，泉枯塞草黃。佇聞河隴外，還繼海沂康。"]'),
('yuding-43','酬王維','苑鹹','唐','御定全唐诗','yuding','','[]','蓮花梵字本從天，華省仙郎早悟禪。三點成伊猶有想，',40,'御定全唐詩/json/129.json','["蓮花梵字本從天，華省仙郎早悟禪。三點成伊猶有想，", "應同羅漢無名欲，故作馮唐老歲年。"]'),
('yuding-44','尋西山隱者不遇','丘為','唐','御定全唐诗','yuding','','[]','絕頂一茅茨，直上三十裏。扣關無僮僕，窺室唯案幾。',96,'御定全唐詩/json/129.json','["絕頂一茅茨，直上三十裏。扣關無僮僕，窺室唯案幾。", "若非巾柴車，應是釣秋水。差池不相見，黽勉空仰止。", "草色新雨中，松聲晚窗裏。及茲契幽絕，自足蕩心耳。", "雖無賓主意，頗得清淨理。興盡方下山，何必待之子。"]'),
('yuding-45','題農父廬舍','丘為','唐','御定全唐诗','yuding','','[]','東風何時至，已綠湖上山。湖上春已早，田家日不閑。',48,'御定全唐詩/json/129.json','["東風何時至，已綠湖上山。湖上春已早，田家日不閑。", "溝塍流水處，耒耜平蕪間。薄暮飯牛罷，歸來還閉關。"]'),
('yuding-46','泛若耶溪','丘為','唐','御定全唐诗','yuding','','[]','結廬若耶裏，左右若耶水。無日不釣魚，有時向城市。',96,'御定全唐詩/json/129.json','["結廬若耶裏，左右若耶水。無日不釣魚，有時向城市。", "溪中水流急，渡口水流寬。每得樵風便，往來殊不難。", "一川草長綠，四時那得辨。短褐衣妻兒，餘糧及雞犬。", "日暮鳥雀稀，稚子呼牛歸。住處無鄰里，柴門獨掩扉。"]'),
('yuding-47','湖中寄王侍禦','丘為','唐','御定全唐诗','yuding','','[]','日日湖水上，好登湖上樓。終年不向郭，過午始梳頭。',120,'御定全唐詩/json/129.json','["日日湖水上，好登湖上樓。終年不向郭，過午始梳頭。", "嘗自愛杯酒，得無相獻酬。小僮能膾鯉，少妾事蓮舟。", "每有南浦信，仍期後月遊。方春轉搖盪，孤興時淹留。", "驄馬真傲吏，翛然無所求。晨趨玉階下，心許滄江流。", "少別如昨日，何言經數秋。應知方外事，獨往非悠悠。"]'),
('yuding-48','登潤州城','丘為','唐','御定全唐诗','yuding','','[]','天末江城晚，登臨客望迷。春潮平島嶼，殘雨隔虹蜺。',48,'御定全唐詩/json/129.json','["天末江城晚，登臨客望迷。春潮平島嶼，殘雨隔虹蜺。", "鳥與孤帆遠，煙和獨樹低。鄉山何處是，目斷廣陵西。"]'),
('yuding-49','尋廬山崔征君','丘為','唐','御定全唐诗','yuding','','[]','日高雞犬靜，門掩向寒塘。夜竹深茅宇，秋亭冷石床。',48,'御定全唐詩/json/129.json','["日高雞犬靜，門掩向寒塘。夜竹深茅宇，秋亭冷石床。", "住山年已遠，服藥壽偏長。虛棄浮生者，相逢益自傷。"]'),
('yuding-50','留別王維','丘為','唐','御定全唐诗','yuding','','[]','歸鞍白雲外，繚繞出前山。今日又明日，自知心不閑。',48,'御定全唐詩/json/129.json','["歸鞍白雲外，繚繞出前山。今日又明日，自知心不閑。", "親勞簪組送，欲趁鶯花還。一步一回首，遲遲向近關。"]'),
('yuding-51','竹下殘雪','丘為','唐','御定全唐诗','yuding','','[]','一點消未盡，孤月在竹陰。晴光夜轉瑩，寒氣曉仍深。',48,'御定全唐詩/json/129.json','["一點消未盡，孤月在竹陰。晴光夜轉瑩，寒氣曉仍深。", "還對讀書牖，且關乘興心。已能依此地，終不傍瑤琴。"]'),
('yuding-52','送閻校書之越','丘為','唐','御定全唐诗','yuding','','[]','南入剡中路，草雲應轉微。湖邊好花照，山口細泉飛。',60,'御定全唐詩/json/129.json','["南入剡中路，草雲應轉微。湖邊好花照，山口細泉飛。", "此地饒古跡，世人多忘歸。經年松雪在，永日世情稀。", "芸閣應相望，芳時不可違。"]'),
('yuding-53','省試夏日可畏','丘為','唐','御定全唐诗','yuding','','[]','赫赫溫風扇，炎炎夏日徂。火威馳迥野，畏景爍遙途。',72,'御定全唐詩/json/129.json','["赫赫溫風扇，炎炎夏日徂。火威馳迥野，畏景爍遙途。", "勢矯翔陽翰，功分造化爐。禁城千品燭，黃道一輪孤。", "落照頻空簟，餘暉卷夕梧。如何倦遊子，中路獨踟躕。"]'),
('yuding-54','左掖梨花','丘為','唐','御定全唐诗','yuding','','[]','冷豔全欺雪，餘香乍入衣。春風且莫定，吹向玉階飛。',24,'御定全唐詩/json/129.json','["冷豔全欺雪，餘香乍入衣。春風且莫定，吹向玉階飛。"]'),
('yuding-55','渡漢江','丘為','唐','御定全唐诗','yuding','','[]','漾舟漢江上，掛席候風生。臨泛何容與，愛此江水清。',72,'御定全唐詩/json/129.json','["漾舟漢江上，掛席候風生。臨泛何容與，愛此江水清。", "蘆洲隱遙嶂，露日映孤城。自顧疏野性，難忘鷗鳥情。", "聊複與時顧，暫欲解塵纓。跋涉非吾願，虛懷浩已盈。"]'),
('yuding-56','冬至下寄舍弟時應赴入京','丘為','唐','御定全唐诗','yuding','','[]','去去知未遠，依依甚初別。他鄉至下心，昨夜階前雪。',70,'御定全唐詩/json/129.json','["去去知未遠，依依甚初別。他鄉至下心，昨夜階前雪。", "終日讀書仍少孤，家貧兄弟未當途。適遠才過宿舂料，", "莫漫憶柴扉，駟馬高車朝紫微。江南驛使不曾斷，"]'),
('yuding-57','送晁補闕歸日本國','趙驊','唐','御定全唐诗','yuding','','[]','西掖承休浣，東隅返故林。來稱郯子學，歸是越人吟。',48,'御定全唐詩/json/129.json','["西掖承休浣，東隅返故林。來稱郯子學，歸是越人吟。", "馬上秋郊遠，舟中曙海陰。知君懷魏闕，萬里獨搖心。"]'),
('yuding-0','古遊俠呈軍中諸將','崔顥','唐','御定全唐诗','yuding','','[]','少年負膽氣，好勇複知機。仗劍出門去，孤城逢合圍。',96,'御定全唐詩/json/130.json','["少年負膽氣，好勇複知機。仗劍出門去，孤城逢合圍。", "殺人遼水上，走馬漁陽歸。錯落金鎖甲，蒙茸貂鼠衣。", "還家行且獵，弓矢速如飛。地迥鷹犬疾，草深狐兔肥。", "腰間帶兩綬，轉盼生光輝。顧謂今日戰，何如隨建威。"]'),
('yuding-1','贈輕車','崔顥','唐','御定全唐诗','yuding','','[]','悠悠遠行歸，經春涉長道。幽冀桑始青，洛陽蠶欲老。',72,'御定全唐詩/json/130.json','["悠悠遠行歸，經春涉長道。幽冀桑始青，洛陽蠶欲老。", "憶昨戎馬地，別時心草草。烽火從北來，邊城閉常早。", "平生少相遇，未得展懷抱。今日杯酒間，見君交情好。"]'),
('yuding-2','贈王威古','崔顥','唐','御定全唐诗','yuding','','[]','三十羽林將，出身常事邊。春風吹淺草，獵騎何翩翩。',108,'御定全唐詩/json/130.json','["三十羽林將，出身常事邊。春風吹淺草，獵騎何翩翩。", "插羽兩相顧，鳴弓新上弦。射麋入深谷，飲馬投荒泉。", "馬上共傾酒，野中聊割鮮。相看未及飲，雜虜寇幽燕。", "烽火去不息，胡塵高際天。長驅救東北，戰解城亦全。", "報國行赴難，古來皆共然。"]'),
('yuding-3','贈懷一上人','崔顥','唐','御定全唐诗','yuding','','[]','法師東南秀，世實豪家子。削髮十二年，誦經峨眉裏。',384,'御定全唐詩/json/130.json','["法師東南秀，世實豪家子。削髮十二年，誦經峨眉裏。", "自此照群蒙，卓然為道雄。觀生盡入妄，悟有皆成空。", "淨體無眾染，苦心歸妙宗。一朝敕書至，召入承明宮。", "說法金殿裏，焚香清禁中。傳燈遍都邑，杖錫游王公。", "天子揖妙道，群僚趨下風。我法本無著，時來出林壑。", "因心得化城，隨病皆與藥。上啟黃屋心，下除蒼生縛。", "一從入君門，說法無朝昏。帝作轉輪王，師為持戒尊。", "軒風灑甘露，佛雨生慈根。但有滅度理，而生開濟恩。", "複聞江海曲，好殺成風俗。帝曰我上人，為除膻腥欲。", "是日發西秦，東南至蘄春。風將衡桂接，地與吳楚鄰。", "舊少清信士，實多漁獵人。一聞吾師至，舍網江湖濱。", "作禮懺前惡，潔誠期後因。因成日既久，事濟身不守。", "更出淮楚間，複來荊河口。荊河馬卿岑，茲地近道林。", "入講鳥常狎，坐禪獸不侵。都非緣未盡，曾是教所任。", "故我一來事，永承微妙音。竹房見衣缽，松宇清身心。", "早悔業至淺，晚成計可尋。善哉遠公義，清淨如黃金。"]'),
('yuding-4','遊天竺寺','崔顥','唐','御定全唐诗','yuding','','[]','晨登天竺山，山殿朝陽曉。厓泉爭噴薄，江岫相縈繞。',108,'御定全唐詩/json/130.json','["晨登天竺山，山殿朝陽曉。厓泉爭噴薄，江岫相縈繞。", "直上孤頂高，平看眾峰小。南州十二月，地暖冰雪少。", "青翠滿寒山，藤蘿覆冬沼。花龕瀑布側，青壁石林杪。", "鳴鐘集人天，施飯聚猿鳥。洗意歸清淨，澄心悟空了。", "始知世上人，萬物一何擾。"]'),
('yuding-5','入若耶溪','崔顥','唐','御定全唐诗','yuding','','[]','輕舟去何疾，已到雲林境。起坐魚鳥間，動搖山水影。',48,'御定全唐詩/json/130.json','["輕舟去何疾，已到雲林境。起坐魚鳥間，動搖山水影。", "岩中響自答，溪裏言彌靜。事事令人幽，停橈向餘景。"]'),
('yuding-6','雜詩','崔顥','唐','御定全唐诗','yuding','','[]','可憐青銅鏡，掛在白玉堂。玉堂有美女，嬌弄明月光。',48,'御定全唐詩/json/130.json','["可憐青銅鏡，掛在白玉堂。玉堂有美女，嬌弄明月光。", "羅袖拂金鵲，彩屏點紅妝。妝罷含情坐，春風桃李香。"]'),
('yuding-7','結定襄郡獄效陶體','崔顥','唐','御定全唐诗','yuding','','[]','我在河東時，使往定襄裏。定襄諸小兒，爭訟紛城市。',132,'御定全唐詩/json/130.json','["我在河東時，使往定襄裏。定襄諸小兒，爭訟紛城市。", "長老莫敢言，太守不能理。謗書盈幾案，文墨相填委。", "牽引肆中翁，追呼田家子。我來折此獄，五聽辨疑似。", "小大必以情，未嘗施鞭棰。是時三月暮，遍野農桑起。", "裏巷鳴春鳩，田園引流水。此鄉多雜俗，戎夏殊音旨。", "顧問邊塞人，勞情曷雲已。"]'),
('yuding-8','長安道','崔顥','唐','御定全唐诗','yuding','','[]','長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，',48,'御定全唐詩/json/130.json','["長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，", "莫言貧賤即可欺，人生富貴自有時。一朝天子賜顏色，"]'),
('yuding-9','行路難','崔顥','唐','御定全唐诗','yuding','','[]','君不見建章宮中金明枝，萬萬長條拂地垂。',91,'御定全唐詩/json/130.json','["君不見建章宮中金明枝，萬萬長條拂地垂。", "二月三月花如霰，九重幽深君不見。豔彩朝含四寶宮，", "看來看去心不忘，攀折將安鏡臺上。雙雙素手剪不成，", "長信麗人見花泣，憶此珍樹何嗟及。我昔初在昭陽時，"]'),
('yuding-10','孟門行','崔顥','唐','御定全唐诗','yuding','','[]','黃雀銜黃花，翩翩傍簷隙。本擬報君恩，如何反彈射。',72,'御定全唐詩/json/130.json','["黃雀銜黃花，翩翩傍簷隙。本擬報君恩，如何反彈射。", "金罍美酒滿座春，平原愛才多眾賓。滿堂儘是忠義士，", "北園新栽桃李枝，根株未固何轉移。成陰結實君自取，"]'),
('yuding-11','渭城少年行','崔顥','唐','御定全唐诗','yuding','','[]','洛陽三月梨花飛，秦地行人春憶歸。揚鞭走馬城南陌，',120,'御定全唐詩/json/130.json','["洛陽三月梨花飛，秦地行人春憶歸。揚鞭走馬城南陌，", "棠梨宮中燕初至，葡萄館裏花正開。念此使人歸更早，", "萬戶樓臺臨渭水，五陵花柳滿秦川。秦川寒食盛繁華，", "章台帝城稱貴裏，青樓日晚歌鐘起。貴裏豪家白馬驕，", "渭城橋頭酒新熟，金鞍白馬誰家宿。可憐錦瑟箏琵琶，"]'),
('yuding-12','盧姬篇','崔顥','唐','御定全唐诗','yuding','','[]','盧姬少小魏王家，綠鬢紅唇桃李花。魏王綺樓十二重，',64,'御定全唐詩/json/130.json','["盧姬少小魏王家，綠鬢紅唇桃李花。魏王綺樓十二重，", "前堂後堂羅袖人，南窗北窗花發春。翠幌珠簾鬥絲管，", "人生今日得嬌貴，誰道盧姬身細微。"]'),
('yuding-13','江畔老人愁','崔顥','唐','御定全唐诗','yuding','','[]','江南年少十八九，乘舟欲渡青溪口。青溪口邊一老翁，',160,'御定全唐詩/json/130.json','["江南年少十八九，乘舟欲渡青溪口。青溪口邊一老翁，", "兩朝出將複入相，五世疊鼓乘朱輪。父兄三葉皆尚主，", "直言榮華未休歇，不覺山崩海將竭。兵戈亂入建康城，", "山川改易失市朝，衢路縱橫填白骨。老人此時尚少年，", "蓬蒿忘卻五城宅，草木不識青溪田。雖然得歸到鄉土，", "少年欲知老人歲，豈知今年一百五。君今少壯我已衰，", "感君相問為君說，說罷不覺令人悲。"]'),
('yuding-14','邯鄲宮人怨','崔顥','唐','御定全唐诗','yuding','','[]','邯鄲陌上三月春，暮行逢見一婦人。自言鄉里本燕趙，',216,'御定全唐詩/json/130.json','["邯鄲陌上三月春，暮行逢見一婦人。自言鄉里本燕趙，", "七歲豐茸好顏色，八歲黠惠能言語。十三兄弟教詩書，", "日暮笙歌君駐馬，春日妝梳妾斷腸。不用城南使君婿，", "建章宮殿不知數，萬戶千門深且長。百堵塗椒接青瑣，", "歲歲年年奉歡宴，嬌貴榮華誰不羨。恩情莫比陳皇后，", "誰言一朝複一日，君王棄世市朝變。宮車出葬茂陵田，", "同時侍女見讒毀，後來新人莫敢言。兄弟印綬皆被奪，", "父母湣我曾富貴，嫁與西舍金王孫。念此翻覆複何道，", "少年去去莫停鞭，人生萬事由上天。非我今日獨如此，"]'),
('yuding-15','川上女','崔顥','唐','御定全唐诗','yuding','','[]','川上女，晚妝鮮，日落青渚試輕楫。汀長花滿正回船，',24,'御定全唐詩/json/130.json','["川上女，晚妝鮮，日落青渚試輕楫。汀長花滿正回船，"]'),
('yuding-16','雁門胡人歌','崔顥','唐','御定全唐诗','yuding','','[]','高山代郡東接燕，雁門胡人家近邊。解放胡鷹逐塞鳥，',40,'御定全唐詩/json/130.json','["高山代郡東接燕，雁門胡人家近邊。解放胡鷹逐塞鳥，", "聞道遼西無鬥戰，時時醉向酒家眠。"]'),
('yuding-17','代閨人答輕薄少年','崔顥','唐','御定全唐诗','yuding','','[]','妾家近隔鳳凰池，粉壁紗窗楊柳垂。本期漢代金吾婿，',88,'御定全唐詩/json/130.json','["妾家近隔鳳凰池，粉壁紗窗楊柳垂。本期漢代金吾婿，", "平明挾彈入新豐，日晚揮鞭出長樂。青絲白馬冶遊園，", "花間陌上春將晚，走馬鬥雞猶未返。三時出望無消息，", "愁來欲奏相思曲，抱得秦箏不忍彈。"]'),
('yuding-18','七夕','崔顥','唐','御定全唐诗','yuding','','[]','長安城中月如練，家家此夜持針線。仙裙玉佩空自知，',40,'御定全唐詩/json/130.json','["長安城中月如練，家家此夜持針線。仙裙玉佩空自知，", "班姬此夕愁無限，河漢三更看鬥牛。"]'),
('yuding-19','長門怨','崔顥','唐','御定全唐诗','yuding','','[]','君王寵初歇，棄妾長門宮。紫殿青苔滿，高樓明月空。',48,'御定全唐詩/json/130.json','["君王寵初歇，棄妾長門宮。紫殿青苔滿，高樓明月空。", "夜愁生枕席，春意罷簾櫳。泣盡無人問，容華落鏡中。"]'),
('yuding-20','王家少婦','崔顥','唐','御定全唐诗','yuding','','[]','十五嫁王昌，盈盈入畫堂。自矜年最少，複倚婿為郎。',48,'御定全唐詩/json/130.json','["十五嫁王昌，盈盈入畫堂。自矜年最少，複倚婿為郎。", "舞愛前溪綠，歌憐子夜長。閑來鬥百草，度日不成妝。"]'),
('yuding-21','岐王席觀妓','崔顥','唐','御定全唐诗','yuding','','[]','二月春來半，宮中日漸長。柳垂金屋暖，花發玉樓香。',48,'御定全唐詩/json/130.json','["二月春來半，宮中日漸長。柳垂金屋暖，花發玉樓香。", "拂匣先臨鏡，調笙更炙簧。還將歌舞態，只擬奉君王。"]'),
('yuding-22','上巳','崔顥','唐','御定全唐诗','yuding','','[]','巳日帝城春，傾都祓禊晨。停車須傍水，奏樂要驚塵。',48,'御定全唐詩/json/130.json','["巳日帝城春，傾都祓禊晨。停車須傍水，奏樂要驚塵。", "弱柳障行騎，浮橋擁看人。猶言日尚早，更向九龍津。"]'),
('yuding-23','贈梁州張都督','崔顥','唐','御定全唐诗','yuding','','[]','聞君為漢將，虜騎罷南侵。出塞清沙漠，還家拜羽林。',48,'御定全唐詩/json/130.json','["聞君為漢將，虜騎罷南侵。出塞清沙漠，還家拜羽林。", "風霜臣節苦，歲月主恩深。為語西河使，知余報國心。"]'),
('yuding-24','贈盧八象','崔顥','唐','御定全唐诗','yuding','','[]','客從巴水渡，傳爾溯行舟。是日風波霽，高堂雨半收。',48,'御定全唐詩/json/130.json','["客從巴水渡，傳爾溯行舟。是日風波霽，高堂雨半收。", "青山滿蜀道，綠水向荊州。不作書相問，誰能慰別愁。"]'),
('yuding-25','題潼關樓','崔顥','唐','御定全唐诗','yuding','','[]','客行逢雨霽，歇馬上津樓。山勢雄三輔，關門扼九州。',48,'御定全唐詩/json/130.json','["客行逢雨霽，歇馬上津樓。山勢雄三輔，關門扼九州。", "川從陝路去，河繞華陰流。向晚登臨處，風煙萬里愁。"]'),
('yuding-26','題沈隱侯八詠樓','崔顥','唐','御定全唐诗','yuding','','[]','梁日東陽守，為樓望越中。綠窗明月在，青史古人空。',48,'御定全唐詩/json/130.json','["梁日東陽守，為樓望越中。綠窗明月在，青史古人空。", "江靜聞山狖，川長數塞鴻。登臨白雲晚，流恨此遺風。"]'),
('yuding-27','晚入汴水','崔顥','唐','御定全唐诗','yuding','','[]','昨晚南行楚，今朝北溯河。客愁能幾日，鄉路漸無多。',48,'御定全唐詩/json/130.json','["昨晚南行楚，今朝北溯河。客愁能幾日，鄉路漸無多。", "晴景搖津樹，春風起棹歌。長淮亦已盡，寧複畏潮波。"]'),
('yuding-28','發錦沙村','崔顥','唐','御定全唐诗','yuding','','[]','北上途未半，南行歲已闌。孤舟下建德，江水入新安。',48,'御定全唐詩/json/130.json','["北上途未半，南行歲已闌。孤舟下建德，江水入新安。", "海近山常雨，溪深地早寒。行行泊不可，須及子陵灘。"]'),
('yuding-29','送單于裴都護赴西河','崔顥','唐','御定全唐诗','yuding','','[]','征馬去翩翩，城秋月正圓。單于莫近塞，都護欲臨邊。',48,'御定全唐詩/json/130.json','["征馬去翩翩，城秋月正圓。單于莫近塞，都護欲臨邊。", "漢驛通煙火，胡沙乏井泉。功成須獻捷，未必去經年。"]'),
('yuding-30','黃鶴樓','崔顥','唐','御定全唐诗','yuding','','[]','昔人已乘白雲去，此地空餘黃鶴樓。黃鶴一去不復返，',40,'御定全唐詩/json/130.json','["昔人已乘白雲去，此地空餘黃鶴樓。黃鶴一去不復返，", "日暮鄉關何處是，煙波江上使人愁。"]'),
('yuding-31','行經華陰','崔顥','唐','御定全唐诗','yuding','','[]','岧嶢太華俯咸京，天外三峰削不成。武帝祠前雲欲散，',40,'御定全唐詩/json/130.json','["岧嶢太華俯咸京，天外三峰削不成。武帝祠前雲欲散，", "借問路傍名利客，無如此處學長生。"]'),
('yuding-32','相逢行','崔顥','唐','御定全唐诗','yuding','','[]','妾年初二八，家住洛橋頭。玉戶臨馳道，朱門近禦溝。',72,'御定全唐詩/json/130.json','["妾年初二八，家住洛橋頭。玉戶臨馳道，朱門近禦溝。", "使君何假問，夫婿大長秋。女弟新承寵，諸兄近拜侯。", "春生百子殿，花發五城樓。出入千門裏，年年樂未休。"]'),
('yuding-33','遼西作','崔顥','唐','御定全唐诗','yuding','','[]','燕郊芳歲晚，殘雪凍邊城。四月青草合，遼陽春水生。',72,'御定全唐詩/json/130.json','["燕郊芳歲晚，殘雪凍邊城。四月青草合，遼陽春水生。", "胡人正牧馬，漢將日徵兵。露重寶刀濕，沙虛金鼓鳴。", "寒衣著已盡，春服與誰成。寄語洛陽使，為傳邊塞情。"]'),
('yuding-34','奉和許給事夜直簡諸公','崔顥','唐','御定全唐诗','yuding','','[]','西掖黃樞近，東曹紫禁連。地因才子拜，人用省郎遷。',96,'御定全唐詩/json/130.json','["西掖黃樞近，東曹紫禁連。地因才子拜，人用省郎遷。", "夜直千門靜，河明萬象懸。建章宵漏急，閶闔曉鐘傳。", "寵列貂蟬位，恩深侍從年。九重初起草，五夜即成篇。", "顧己無官次，循涯但自憐。遠陪蘭署作，空此仰神仙。"]'),
('yuding-35','舟行入剡','崔顥','唐','御定全唐诗','yuding','','[]','鳴棹下東陽，回舟入剡鄉。青山行不盡，綠水去何長。',72,'御定全唐詩/json/130.json','["鳴棹下東陽，回舟入剡鄉。青山行不盡，綠水去何長。", "地氣秋仍濕，江風晚漸涼。山梅猶作雨，溪橘未知霜。", "謝客文逾盛，林公未可忘。多慚越中好，流恨閱時芳。"]'),
('yuding-36','澄水如鑒','崔顥','唐','御定全唐诗','yuding','','[]','聖賢將立喻，上善貯情深。潔白依全德，澄清有片心。',72,'御定全唐詩/json/130.json','["聖賢將立喻，上善貯情深。潔白依全德，澄清有片心。", "澆浮知不撓，濫濁固難侵。方寸懸高鑒，生涯詎陸沉。", "對泉能自誡，如鏡靜相臨。廉慎傳家政，流芳合古今。"]'),
('yuding-37','長幹曲四首','崔顥','唐','御定全唐诗','yuding','','[]','君家何處住，妾住在橫塘。停船暫借問，或恐是同鄉。',96,'御定全唐詩/json/130.json','["君家何處住，妾住在橫塘。停船暫借問，或恐是同鄉。", "家臨九江水，來去九江側。同是長幹人，自小不相識。", "下渚多風浪，蓮舟漸覺稀。那能不相待，獨自逆潮歸。", "三江潮水急，五湖風浪湧。由來花性輕，莫畏蓮舟重。"]'),
('yuding-38','維揚送友還蘇州','崔顥','唐','御定全唐诗','yuding','','[]','長安南下幾程途，得到邗溝吊綠蕪。',32,'御定全唐詩/json/130.json','["長安南下幾程途，得到邗溝吊綠蕪。", "渚畔鱸魚舟上釣，羨君歸老向東吳。"]'),
('yuding-0','古意二首','祖詠','唐','御定全唐诗','yuding','','[]','夫差日淫放，舉國求妃嬪。自謂得王寵，代間無美人。',168,'御定全唐詩/json/131.json','["夫差日淫放，舉國求妃嬪。自謂得王寵，代間無美人。", "碧羅象天閣，坐輦乘芳春。宮女數千騎，常遊江水濱。", "年深玉顏老，時薄花妝新。拭淚下金殿，嬌多不顧身。", "生前妒歌舞，死後同灰塵。塚墓令人哀，哀於銅雀台。", "楚王竟何去，獨自留巫山。偏使世人見，迢迢江漢間。", "駐舟春溪裏，誓願拜靈顏。夢寐睹神女，金沙鳴佩環。", "閑豔絕世姿，令人氣力微。含笑默不語，化作朝雲飛。"]'),
('yuding-1','渡淮河寄平一','祖詠','唐','御定全唐诗','yuding','','[]','天色混波濤，岸陰匝村墅。微微漢祖廟，隱隱江陵渚。',36,'御定全唐詩/json/131.json','["天色混波濤，岸陰匝村墅。微微漢祖廟，隱隱江陵渚。", "雲樹森已重，時明鬱相拒。"]'),
('yuding-2','歸汝墳山莊留別盧象','祖詠','唐','御定全唐诗','yuding','','[]','淹留歲將晏，久廢南山期。舊業不見棄，還山從此辭。',60,'御定全唐詩/json/131.json','["淹留歲將晏，久廢南山期。舊業不見棄，還山從此辭。", "漚麻入南澗，刈麥向東菑。對酒雞黍熟，閉門風雪時。", "非君一延首，誰慰遙相思。"]'),
('yuding-3','夕次圃田店','祖詠','唐','御定全唐诗','yuding','','[]','前路入鄭郊，尚經百餘裏。馬煩時欲歇，客歸程未已。',48,'御定全唐詩/json/131.json','["前路入鄭郊，尚經百餘裏。馬煩時欲歇，客歸程未已。", "落日桑柘陰，遙村煙火起。西還不遑宿，中夜渡涇水。"]'),
('yuding-4','田家即事','祖詠','唐','御定全唐诗','yuding','','[]','舊居東皋上，左右俯荒村。樵路前傍嶺，田家遙對門。',96,'御定全唐詩/json/131.json','["舊居東皋上，左右俯荒村。樵路前傍嶺，田家遙對門。", "歡娛始披拂，愜意在郊原。餘霽蕩川霧，新秋仍晝昏。", "攀條憩林麓，引水開泉源。稼穡豈雲倦，桑麻今正繁。", "方求靜者賞，偶與潛夫論。雞黍何必具，吾心知道尊。"]'),
('yuding-5','扈從禦宿池','祖詠','唐','御定全唐诗','yuding','','[]','君王既巡狩，輦道入秦京。遠樹低槍壘，孤峰入幔城。',48,'御定全唐詩/json/131.json','["君王既巡狩，輦道入秦京。遠樹低槍壘，孤峰入幔城。", "寒疏清禁漏，夜警羽林兵。誰念迷方客，長懷魏闕情。"]'),
('yuding-6','贈苗發員外','祖詠','唐','御定全唐诗','yuding','','[]','宿雨朝來歇，空山天氣清。盤雲雙鶴下，隔水一蟬鳴。',48,'御定全唐詩/json/131.json','["宿雨朝來歇，空山天氣清。盤雲雙鶴下，隔水一蟬鳴。", "古道黃花落，平蕪赤燒生。茂陵雖有病，猶得伴君行。"]'),
('yuding-7','答王維留宿','祖詠','唐','御定全唐诗','yuding','','[]','四年不相見，相見複何為。握手言未畢，卻令傷別離。',48,'御定全唐詩/json/131.json','["四年不相見，相見複何為。握手言未畢，卻令傷別離。", "升堂還駐馬，酌醴便呼兒。語嘿自相對，安用傍人知。"]'),
('yuding-8','長樂驛留別盧象裴總','祖詠','唐','御定全唐诗','yuding','','[]','朝來已握手，宿別更傷心。灞水行人渡，商山驛路深。',48,'御定全唐詩/json/131.json','["朝來已握手，宿別更傷心。灞水行人渡，商山驛路深。", "故情君且足，謫宦我難任。直道皆如此，誰能淚滿襟。"]'),
('yuding-9','送劉高郵棁使入都','祖詠','唐','御定全唐诗','yuding','','[]','常聞積歸思，昨夜又兼秋。鄉路京華遠，王程江水流。',48,'御定全唐詩/json/131.json','["常聞積歸思，昨夜又兼秋。鄉路京華遠，王程江水流。", "吳歌喧兩岸，楚客醉孤舟。漸覺潮初上，淒然多暮愁。"]'),
('yuding-10','宴吳王宅','祖詠','唐','御定全唐诗','yuding','','[]','吳王承國寵，列第禁城東。連夜征詞客，當春試舞童。',48,'御定全唐詩/json/131.json','["吳王承國寵，列第禁城東。連夜征詞客，當春試舞童。", "砌分池水岸，窗度竹林風。更待西園月，金尊樂未終。"]'),
('yuding-11','觀華岳','祖詠','唐','御定全唐诗','yuding','','[]','西入秦關口，南瞻驛路連。彩雲生闕下，松樹到祠邊。',48,'御定全唐詩/json/131.json','["西入秦關口，南瞻驛路連。彩雲生闕下，松樹到祠邊。", "作鎮當官道，雄都俯大川。蓮峰徑上處，仿佛有神仙。"]'),
('yuding-12','泗上馮使君南樓作','祖詠','唐','御定全唐诗','yuding','','[]','井邑連淮泗，南樓向晚過。望灘沙鷺起，尋岸浴童歌。',48,'御定全唐詩/json/131.json','["井邑連淮泗，南樓向晚過。望灘沙鷺起，尋岸浴童歌。", "近海雲偏出，兼秋雨更多。明晨擬回棹，鄉思恨風波。"]'),
('yuding-13','蘇氏別業','祖詠','唐','御定全唐诗','yuding','','[]','別業居幽處，到來生隱心。南山當戶牖，灃水映園林。',48,'御定全唐詩/json/131.json','["別業居幽處，到來生隱心。南山當戶牖，灃水映園林。", "屋覆經冬雪，庭昏未夕陰。寥寥人境外，閑坐聽春禽。"]'),
('yuding-14','汝墳別業','祖詠','唐','御定全唐诗','yuding','','[]','失路農為業，移家到汝墳。獨愁常廢卷，多病久離群。',48,'御定全唐詩/json/131.json','["失路農為業，移家到汝墳。獨愁常廢卷，多病久離群。", "鳥雀垂窗柳，虹霓出澗雲。山中無外事，樵唱有時聞。"]'),
('yuding-15','陸渾水亭','祖詠','唐','御定全唐诗','yuding','','[]','晝眺伊川曲，岩間霽色明。淺沙平有路，流水漫無聲。',48,'御定全唐詩/json/131.json','["晝眺伊川曲，岩間霽色明。淺沙平有路，流水漫無聲。", "浴鳥沿波聚，潛魚觸釣驚。更憐春岸綠，幽意滿前楹。"]'),
('yuding-16','過鄭曲','祖詠','唐','御定全唐诗','yuding','','[]','路向榮川穀，晴來望盡通。細煙生水上，圓月在舟中。',48,'御定全唐詩/json/131.json','["路向榮川穀，晴來望盡通。細煙生水上，圓月在舟中。", "岸勢迷行客，秋聲亂草蟲。旅懷勞自慰，淅淅有涼風。"]'),
('yuding-17','宿陳留李少府揆廳','祖詠','唐','御定全唐诗','yuding','','[]','相知有叔卿，訟簡夜彌清。旅泊倦愁臥，堂空聞曙更。',48,'御定全唐詩/json/131.json','["相知有叔卿，訟簡夜彌清。旅泊倦愁臥，堂空聞曙更。", "風簾搖燭影，秋雨帶蟲聲。歸思那堪說，悠悠限洛城。"]'),
('yuding-18','題韓少府水亭','祖詠','唐','御定全唐诗','yuding','','[]','梅福幽棲處，佳期不忘還。鳥吟當戶竹，花繞傍池山。',48,'御定全唐詩/json/131.json','["梅福幽棲處，佳期不忘還。鳥吟當戶竹，花繞傍池山。", "水氣侵階冷，松陰覆座閑。甯知武陵趣，宛在市朝間。"]'),
('yuding-19','題遠公經台','祖詠','唐','御定全唐诗','yuding','','[]','蘭若無人到，真僧出複稀。苔侵行道席，雲濕坐禪衣。',48,'御定全唐詩/json/131.json','["蘭若無人到，真僧出複稀。苔侵行道席，雲濕坐禪衣。", "澗鼠緣香案，山蟬噪竹扉。世間長不見，寧止暫忘歸。"]'),
('yuding-20','中峰居喜見苗發','祖詠','唐','御定全唐诗','yuding','','[]','自得中峰住，深林亦閉關。經秋無客到，入夜有僧還。',48,'御定全唐詩/json/131.json','["自得中峰住，深林亦閉關。經秋無客到，入夜有僧還。", "暗澗泉聲小，荒岡樹影閑。高窗不可望，星月滿空山。"]'),
('yuding-21','江南旅情','祖詠','唐','御定全唐诗','yuding','','[]','楚山不可極，歸路但蕭條。海色晴看雨，江聲夜聽潮。',48,'御定全唐詩/json/131.json','["楚山不可極，歸路但蕭條。海色晴看雨，江聲夜聽潮。", "劍留南斗近，書寄北風遙。為報空潭橘，無媒寄洛橋。"]'),
('yuding-22','泊揚子津','祖詠','唐','御定全唐诗','yuding','','[]','才入維揚郡，鄉關此路遙。林藏初過雨，風退欲歸潮。',48,'御定全唐詩/json/131.json','["才入維揚郡，鄉關此路遙。林藏初過雨，風退欲歸潮。", "江火明沙岸，雲帆礙浦橋。客衣今日薄，寒氣近來饒。"]'),
('yuding-23','晚泊金陵水亭','祖詠','唐','御定全唐诗','yuding','','[]','江亭當廢國，秋景倍蕭騷。夕照明殘壘，寒潮漲古濠。',48,'御定全唐詩/json/131.json','["江亭當廢國，秋景倍蕭騷。夕照明殘壘，寒潮漲古濠。", "就田看鶴大，隔水見僧高。無限前朝事，醒吟易覺勞。"]'),
('yuding-24','七夕','祖詠','唐','御定全唐诗','yuding','','[]','閨女求天女，更闌意未闌。玉庭開粉席，羅袖捧金盤。',48,'御定全唐詩/json/131.json','["閨女求天女，更闌意未闌。玉庭開粉席，羅袖捧金盤。", "向月穿針易，臨風整線難。不知誰得巧，明旦試相看。"]'),
('yuding-25','望薊門','祖詠','唐','御定全唐诗','yuding','','[]','燕台一望客心驚，簫鼓喧喧漢將營。萬里寒光生積雪，',40,'御定全唐詩/json/131.json','["燕台一望客心驚，簫鼓喧喧漢將營。萬里寒光生積雪，", "少小雖非投筆吏，論功還欲請長纓。"]'),
('yuding-26','家園夜坐寄郭微','祖詠','唐','御定全唐诗','yuding','','[]','前階微雨歇，開戶散窺林。月出夜方淺，水涼池更深。',72,'御定全唐詩/json/131.json','["前階微雨歇，開戶散窺林。月出夜方淺，水涼池更深。", "餘風生竹樹，清露薄衣襟。遇物遂遙歎，懷人滋遠心。", "依稀成夢想，影響絕徽音。誰念窮居者，明時嗟陸沉。"]'),
('yuding-27','酬汴州李別駕贈','祖詠','唐','御定全唐诗','yuding','','[]','秋風多客思，行旅厭艱辛。自洛非才子，游梁得主人。',72,'御定全唐詩/json/131.json','["秋風多客思，行旅厭艱辛。自洛非才子，游梁得主人。", "文章參末議，榮賤豈同倫。歎逝逢三演，懷賢憶四真。", "情因恩舊好，契托死生親。所愧能投贈，清言益潤身。"]'),
('yuding-28','清明宴司勳劉郎中別業','祖詠','唐','御定全唐诗','yuding','','[]','田家複近臣，行樂不違親。霽日園林好，清明煙火新。',72,'御定全唐詩/json/131.json','["田家複近臣，行樂不違親。霽日園林好，清明煙火新。", "以文長會友，唯德自成鄰。池照窗陰晚，杯香藥味春。", "簷前花覆地，竹外鳥窺人。何必桃源裏，深居作隱淪。"]'),
('yuding-29','汝墳秋同仙州王長史翰聞百舌鳥','祖詠','唐','御定全唐诗','yuding','','[]','秋天聞好鳥，驚起出簾帷。卻念殊方月，能鳴巳後時。',120,'御定全唐詩/json/131.json','["秋天聞好鳥，驚起出簾帷。卻念殊方月，能鳴巳後時。", "遷喬誠可早，出谷此何遲。顧影慚無對，懷群空所思。", "淒涼歲欲晚，蕭索燕將辭。留聽未終曲，彌令心獨悲。", "高飛憑力致，巧囀任天姿。返覆知而靜，間關斷若遺。", "花繁上林路，霜落汝川湄。且長淩風翮，乘春自有期。"]'),
('yuding-30','送丘為下第','祖詠','唐','御定全唐诗','yuding','','[]','滄江一身客，獻賦空十年。明主豈能好，今人誰舉賢。',60,'御定全唐詩/json/131.json','["滄江一身客，獻賦空十年。明主豈能好，今人誰舉賢。", "國門稅征駕，旅食謀歸旋。皦日媚春水，綠蘋香客船。", "無媒既不達，予亦思歸田。"]'),
('yuding-31','贈苗發員外','祖詠','唐','御定全唐诗','yuding','','[]','朱戶敞高扉，青槐礙落暉。八龍乘慶重，三虎遞朝歸。',72,'御定全唐詩/json/131.json','["朱戶敞高扉，青槐礙落暉。八龍乘慶重，三虎遞朝歸。", "坐竹人聲絕，橫琴鳥語稀。花慚潘嶽貌，年稱老萊衣。", "葉暗朱櫻熟，絲長粉蝶飛。應憐魯儒賤，空與故山違。"]'),
('yuding-32','寄王長史','祖詠','唐','御定全唐诗','yuding','','[]','汝潁俱宿好，往來托層巒。終日何寂寞，繞籬生蕙蘭。',24,'御定全唐詩/json/131.json','["汝潁俱宿好，往來托層巒。終日何寂寞，繞籬生蕙蘭。"]'),
('yuding-33','別怨','祖詠','唐','御定全唐诗','yuding','','[]','送別到中流，秋船倚渡頭。相看尚不遠，未可即回舟。',24,'御定全唐詩/json/131.json','["送別到中流，秋船倚渡頭。相看尚不遠，未可即回舟。"]'),
('yuding-34','終南望餘雪','祖詠','唐','御定全唐诗','yuding','','[]','終南陰嶺秀，積雪浮雲端。林表明霽色，城中增暮寒。',24,'御定全唐詩/json/131.json','["終南陰嶺秀，積雪浮雲端。林表明霽色，城中增暮寒。"]'),
('yuding-35','句','祖詠','唐','御定全唐诗','yuding','','[]','不知疊嶂夜來雨，清曉石楠花亂流。',16,'御定全唐詩/json/131.json','["不知疊嶂夜來雨，清曉石楠花亂流。"]'),
('yuding-0','湘夫人','李頎','唐','御定全唐诗','yuding','','[]','九嶷日已暮，三湘雲複愁。窅靄羅袂色，潺湲江水流。',36,'御定全唐詩/json/132.json','["九嶷日已暮，三湘雲複愁。窅靄羅袂色，潺湲江水流。", "佳期來北渚，捐佩在芳洲。"]'),
('yuding-1','塞下曲','李頎','唐','御定全唐诗','yuding','','[]','黃雲雁門郡，日暮風沙裏。千騎黑貂裘，皆稱羽林子。',48,'御定全唐詩/json/132.json','["黃雲雁門郡，日暮風沙裏。千騎黑貂裘，皆稱羽林子。", "金笳吹朔雪，鐵馬嘶雲水。帳下飲蒲萄，平生寸心是。"]'),
('yuding-2','古塞下曲','李頎','唐','御定全唐诗','yuding','','[]','行人朝走馬，直指薊城傍。薊城通漠北，萬里別吾鄉。',72,'御定全唐詩/json/132.json','["行人朝走馬，直指薊城傍。薊城通漠北，萬里別吾鄉。", "海上千烽火，沙中百戰場。軍書發上郡，春色度河陽。", "嫋嫋漢宮柳，青青胡地桑。琵琶出塞曲，橫笛斷君腸。"]'),
('yuding-3','漁父歌','李頎','唐','御定全唐诗','yuding','','[]','白首何老人，蓑笠蔽其身。避世長不仕，釣魚清江濱。',96,'御定全唐詩/json/132.json','["白首何老人，蓑笠蔽其身。避世長不仕，釣魚清江濱。", "浦沙明濯足，山月靜垂綸。寓宿湍與瀨，行歌秋複春。", "持竿湘岸竹，爇火蘆洲薪。綠水飯香稻，青荷包紫鱗。", "于中還自樂，所欲全吾真。而笑獨醒者，臨流多苦辛。"]'),
('yuding-4','東京寄萬楚','李頎','唐','御定全唐诗','yuding','','[]','濩落久無用，隱身甘采薇。仍聞薄宦者，還事田家衣。',120,'御定全唐詩/json/132.json','["濩落久無用，隱身甘采薇。仍聞薄宦者，還事田家衣。", "潁水日夜流，故人相見稀。春山不可望，黃鳥東南飛。", "濯足豈長往，一樽聊可依。了然潭上月，適我胸中機。", "在昔同門友，如今出處非。優遊白虎殿，偃息青瑣闈。", "且有薦君表，當看攜手歸。寄書不待面，蘭茝空芳菲。"]'),
('yuding-5','寄焦煉師','李頎','唐','御定全唐诗','yuding','','[]','得道凡百歲，燒丹惟一身。悠悠孤峰頂，日見三花春。',72,'御定全唐詩/json/132.json','["得道凡百歲，燒丹惟一身。悠悠孤峰頂，日見三花春。", "白鶴翠微裏，黃精幽澗濱。始知世上客，不及山中人。", "仙境若在夢，朝雲如可親。何由睹顏色，揮手謝風塵。"]'),
('yuding-6','望鳴皋山白雲寄洛陽盧主簿','李頎','唐','御定全唐诗','yuding','','[]','飲馬伊水中，白雲鳴皋上。氛氳山絕頂，行子時一望。',120,'御定全唐詩/json/132.json','["飲馬伊水中，白雲鳴皋上。氛氳山絕頂，行子時一望。", "照日龍虎姿，攢空冰雪狀。嵡嵸殊未已，崚嶒忽相向。", "皎皎橫綠林，霏霏澹青嶂。遠映村更失，孤高鶴來傍。", "勝氣欣有逢，仙遊且難訪。故人吏京劇，每事多閑放。", "室畫峨眉峰，心格洞庭浪。惜哉清興裏，不見予所尚。"]'),
('yuding-7','寄萬齊融','李頎','唐','御定全唐诗','yuding','','[]','名高不擇仕，委世隨虛舟。小邑常歎屈，故鄉行可遊。',120,'御定全唐詩/json/132.json','["名高不擇仕，委世隨虛舟。小邑常歎屈，故鄉行可遊。", "青楓半村戶，香稻盈田疇。為政日清淨，何人同海鷗。", "搖巾北林夕，把菊東山秋。對酒池雲滿，向家湖水流。", "岸陰止鳴鵠，山色映潛虯。靡靡俗中理，蕭蕭川上幽。", "昔年至吳郡，常隱臨江樓。我有一書劄，因之芳杜洲。"]'),
('yuding-8','贈張旭','李頎','唐','御定全唐诗','yuding','','[]','張公性嗜酒，豁達無所營。皓首窮草隸，時稱太湖精。',144,'御定全唐詩/json/132.json','["張公性嗜酒，豁達無所營。皓首窮草隸，時稱太湖精。", "露頂據胡床，長叫三五聲。興來灑素壁，揮筆如流星。", "下舍風蕭條，寒草滿戶庭。問家何所有，生事如浮萍。", "左手持蟹螯，右手執丹經。瞪目視霄漢，不知醉與醒。", "諸賓且方坐，旭日臨東城。荷葉裹江魚，白甌貯香粳。", "微祿心不屑，放神於八紘。時人不識者，即是安期生。"]'),
('yuding-9','贈蘇明府','李頎','唐','御定全唐诗','yuding','','[]','蘇君年幾許，狀貌如玉童。采藥傍梁宋，共言隨日翁。',120,'御定全唐詩/json/132.json','["蘇君年幾許，狀貌如玉童。采藥傍梁宋，共言隨日翁。", "常辭小縣宰，一往東山東。不復有家室，悠悠人世中。", "子孫皆老死，相識悲轉蓬。發白還更黑，身輕行若風。", "泛然無所系，心與孤雲同。出入雖一杖，安然知始終。", "願聞素女事，去采山花叢。誘我為弟子，逍遙尋葛洪。"]'),
('yuding-10','登首陽山謁夷齊廟','李頎','唐','御定全唐诗','yuding','','[]','古人已不見，喬木竟誰過。寂寞首陽山，白雲空複多。',108,'御定全唐詩/json/132.json','["古人已不見，喬木竟誰過。寂寞首陽山，白雲空複多。", "蒼苔歸地骨，皓首采薇歌。畢命無怨色，成仁其若何。", "我來入遺廟，時候微清和。落日吊山鬼，回風吹女蘿。", "石崖向西豁，引領望黃河。千里一飛鳥，孤光東逝波。", "驅車層城路，惆悵此岩阿。"]'),
('yuding-11','謁張果先生','李頎','唐','御定全唐诗','yuding','','[]','先生谷神者，甲子焉能計。自說軒轅師，於今幾千歲。',240,'御定全唐詩/json/132.json','["先生谷神者，甲子焉能計。自說軒轅師，於今幾千歲。", "寓遊城郭裏，浪跡希夷際。應物雲無心，逢時舟不系。", "餐霞斷火粒，野服兼荷制。白雪淨肌膚，青松養身世。", "韜精殊豹隱，煉骨同蟬蛻。忽去不知誰，偶來寧有契。", "二儀齊壽考，六合隨休憩。彭聃猶嬰孩，松期且微細。", "嘗聞穆天子，更憶漢皇帝。親屈萬乘尊，將窮四海裔。", "車徒遍草木，錦帛招談說。八駿空往還，三山轉虧蔽。", "吾君感至德，玄老欣來詣。受籙金殿開，清齋玉堂閉。", "笙歌迎拜首，羽帳崇嚴衛。禁柳垂香爐，宮花拂仙袂。", "祈年寶祚廣，致福蒼生惠。何必待龍髯，鼎成方取濟。"]'),
('yuding-12','光上座廊下眾山五韻','李頎','唐','御定全唐诗','yuding','','[]','名嶽在廡下，吾師居一床。每聞楞伽經，只對清翠光。',60,'御定全唐詩/json/132.json','["名嶽在廡下，吾師居一床。每聞楞伽經，只對清翠光。", "百穀聚雪色，莓苔侵屋樑。氣盤古壁轉，勢引幽階長。", "願游薜葉下，日見金爐香。"]'),
('yuding-13','九月九日劉十八東堂集','李頎','唐','御定全唐诗','yuding','','[]','風俗尚九日，此情安可忘。菊花辟惡酒，湯餅茱萸香。',72,'御定全唐詩/json/132.json','["風俗尚九日，此情安可忘。菊花辟惡酒，湯餅茱萸香。", "雲入授衣假，風吹閑宇涼。主人盡歡意，林景晝微茫。", "清切晚砧動，東西歸鳥行。淹留悵為別，日醉秋雲光。"]'),
('yuding-14','宋少府東溪泛舟','李頎','唐','御定全唐诗','yuding','','[]','登岸還入舟，水禽驚笑語。晚葉低眾色，濕雲帶殘暑。',36,'御定全唐詩/json/132.json','["登岸還入舟，水禽驚笑語。晚葉低眾色，濕雲帶殘暑。", "落日乘醉歸，溪流複幾許。"]'),
('yuding-15','與諸公遊濟瀆泛舟','李頎','唐','御定全唐诗','yuding','','[]','濟水出王屋，其源來不窮。洑泉數眼沸，平地流清通。',241,'御定全唐詩/json/132.json','["濟水出王屋，其源來不窮。洑泉數眼沸，平地流清通。", "皇帝崇祀典，詔書視三公。分官禱靈廟，奠璧沉河宮。", "神應每如答，松篁氣蔥蘢。蒼螭送飛雨，赤鯉噴回風。", "灑酒布瑤席，吹簫下玉童。玄冥掌陰事，祝史告年豐。", "百穀趨潭底，三光懸鏡中。淺深露沙石，蘋藻生虛空。", "晚景臨泛美，亭皋輕靄紅。晴山傍舟楫，白鷺驚絲桐。", "我本家潁北，開門見維嵩。焉知松峰外，又有天壇東。", "左手正接z5，浩歌眄青穹。夷猶傲清吏，偃仰狎漁翁。", "對此川上閑，非君誰與同。霜凝遠村渚，月淨蒹葭叢。", "茲境信難遇，為歡殊未終。淹留悵言別，煙嶼夕微蒙。"]'),
('yuding-16','送綦毋三謁房給事','李頎','唐','御定全唐诗','yuding','','[]','夫子大名下，家無鐘石儲。惜哉湖海上，曾校蓬萊書。',120,'御定全唐詩/json/132.json','["夫子大名下，家無鐘石儲。惜哉湖海上，曾校蓬萊書。", "外物非本意，此生空澹如。所思但乘興，遠適唯單車。", "高道時坎坷，故交願吹噓。徒言青瑣闥，不愛承明廬。", "百里人戶滿，片言爭訟疏。手持蓮花經，目送飛鳥餘。", "晚景南路別，炎雲中伏初。此行儻不遂，歸食蘆洲魚。"]'),
('yuding-17','送劉四','李頎','唐','御定全唐诗','yuding','','[]','愛君少岐嶷，高視白雲鄉。九歲能屬文，謁帝遊明光。',144,'御定全唐詩/json/132.json','["愛君少岐嶷，高視白雲鄉。九歲能屬文，謁帝遊明光。", "奉詔赤墀下，拜為童子郎。爾來屢遷易，三度尉洛陽。", "洛陽十二門，官寺鬱相望。青槐羅四面，淥水貫中央。", "聽訟破秋毫，應物利幹將。辭滿如脫屣，立言無否臧。", "歲暮風雪暗，秦中川路長。行人飲臘酒，立馬帶晨霜。", "生事豈須問，故園寒草荒。從今署右職，莫笑在農桑。"]'),
('yuding-18','送裴騰','李頎','唐','御定全唐诗','yuding','','[]','養德為眾許，森然此丈夫。放情白雲外，爽氣連虯須。',120,'御定全唐詩/json/132.json','["養德為眾許，森然此丈夫。放情白雲外，爽氣連虯須。", "衡鏡合知子，公心誰謂無。還令不得意，單馬遂長驅。", "桑野蠶忙時，憐君久踟躊。新晴荷卷葉，孟夏雉將雛。", "令弟為縣尹，高城汾水隅。相將簿領閑，倚望恒峰孤。", "香露團百草，紫梨分萬株。歸來授衣假，莫使故園蕪。"]'),
('yuding-19','送司農崔丞','李頎','唐','御定全唐诗','yuding','','[]','黃鸝鳴官寺，香草色未已。同時皆省郎，而我獨留此。',120,'御定全唐詩/json/132.json','["黃鸝鳴官寺，香草色未已。同時皆省郎，而我獨留此。", "維監太倉粟，常對府小史。清陰羅廣庭，政事如流水。", "奉使往長安，今承朝野歡。宰臣應記識，明主必遷官。", "塞外貔將虎，池中鴛與鸞。詞人洞簫賦，公子鵕鸃冠。", "邑裏春方晚，昆明花欲闌。行行取高位，當使路傍看。"]'),
('yuding-20','送崔侍禦赴京','李頎','唐','御定全唐诗','yuding','','[]','綠槐蔭長路，駿馬垂青絲。柱史謁承明，翩翩將有期。',96,'御定全唐詩/json/132.json','["綠槐蔭長路，駿馬垂青絲。柱史謁承明，翩翩將有期。", "千官大朝日，奏事臨赤墀。肅肅儀仗裏，風生鷹隼姿。", "一從登甲科，三拜皆憲司。按俗又如此，為郎何太遲。", "送君暮春月，花落城南陲。惜別醉芳草，前山勞夢思。"]'),
('yuding-21','春送從叔游襄陽','李頎','唐','御定全唐诗','yuding','','[]','言別恨非一，棄置我宗英。向用五經笥，今為千里行。',120,'御定全唐詩/json/132.json','["言別恨非一，棄置我宗英。向用五經笥，今為千里行。", "裹糧顧庭草，羸馬詰朝鳴。鬥酒對寒食，雜花宜晚晴。", "春衣采洲路，夜飲南陽城。客夢峴山曉，漁歌江水清。", "楚俗少相知，遠遊難稱情。同人應館谷，刺史在郊迎。", "只合侍丹扆，翻令辭上京。時方春欲暮，歎息向流鶯。"]'),
('yuding-22','贈別高三十五','李頎','唐','御定全唐诗','yuding','','[]','五十無產業，心輕百萬資。屠酤亦與群，不問君是誰。',168,'御定全唐詩/json/132.json','["五十無產業，心輕百萬資。屠酤亦與群，不問君是誰。", "飲酒或垂釣，狂歌兼詠詩。焉知漢高士，莫識越鴟夷。", "寄跡棲霞山，蓬頭睢水湄。忽然辟命下，眾謂趨丹墀。", "沐浴著賜衣，西來馬行遲。能令相府重，且有函關期。", "黽勉從寸祿，舊游梁宋時。皤皤邑中叟，相候鬢如絲。", "官舍柳林靜，河梁杏葉滋。摘芳雲景晏，把手秋蟬悲。", "小縣情未愜，折腰君莫辭。吾觀主人意，不久召京師。"]'),
('yuding-23','崔五宅送劉跂入京','李頎','唐','御定全唐诗','yuding','','[]','行人惜寸景，系馬暫留歡。昨日辭小沛，何時到長安。',120,'御定全唐詩/json/132.json','["行人惜寸景，系馬暫留歡。昨日辭小沛，何時到長安。", "鄉中飲酒禮，客裏行路難。清洛雲鴻度，故關風日寒。", "維將道可樂，不念身無官。生事東山遠，田園芳歲闌。", "東歸余謝病，西去子加餐。宋伯非徒爾，明時正可幹。", "躬耕守貧賤，失計在林端。宿昔奉顏色，慚無雙玉盤。"]'),
('yuding-24','送馬錄事赴永陽','李頎','唐','御定全唐诗','yuding','','[]','子為郡從事，主印清淮邊。談笑一州裏，從容群吏先。',120,'御定全唐詩/json/132.json','["子為郡從事，主印清淮邊。談笑一州裏，從容群吏先。", "手持三尺令，遣決如流泉。太守既相許，諸公誰不然。", "孤城連海樹，萬室帶山煙。春日溪湖淨，芳洲葭菼連。", "炊粳蟹螯熟，下箸鱸魚鮮。野鶴宿簷際，楚雲飛面前。", "聽歌送離曲，且駐木蘭船。贈爾八行字，當聞佳政傳。"]'),
('yuding-25','臨別送張諲入蜀','李頎','唐','御定全唐诗','yuding','','[]','出門便為客，惘然悲徒禦。四海維一身，茫茫欲何去。',120,'御定全唐詩/json/132.json','["出門便為客，惘然悲徒禦。四海維一身，茫茫欲何去。", "經山複曆水，百恨將千慮。劍閣望梁州，是君斷腸處。", "孤雲傷客心，落日感君深。夢裏蒹葭渚，天邊橘柚林。", "蜀江流不測，蜀路險難尋。木有相思號，猿多愁苦音。", "莫向愚山隱，愚山地非近。故鄉可歸來，眼見芳菲盡。"]'),
('yuding-26','送王昌齡','李頎','唐','御定全唐诗','yuding','','[]','漕水東去遠，送君多暮情。淹留野寺出，向背孤山明。',84,'御定全唐詩/json/132.json','["漕水東去遠，送君多暮情。淹留野寺出，向背孤山明。", "前望數千里，中無蒲稗生。夕陽滿舟楫，但愛微波清。", "舉酒林月上，解衣沙鳥鳴。夜來蓮花界，夢裏金陵城。", "歎息此離別，悠悠江海行。"]'),
('yuding-27','留別王盧二拾遺','李頎','唐','御定全唐诗','yuding','','[]','此別不可道，此心當報誰。春風灞水上，飲馬桃花時。',48,'御定全唐詩/json/132.json','["此別不可道，此心當報誰。春風灞水上，飲馬桃花時。", "誤作好文士，只令游宦遲。留書下朝客，我有故山期。"]'),
('yuding-28','贈別穆元林','李頎','唐','御定全唐诗','yuding','','[]','貳職久辭滿，藏名三十年。丹墀策頻獻，白首官不遷。',120,'御定全唐詩/json/132.json','["貳職久辭滿，藏名三十年。丹墀策頻獻，白首官不遷。", "明主日征士，吏曹何忽賢。空懷濟世業，欲棹滄浪船。", "舉酒洛門外，送君春海邊。彼鄉有令弟，小邑試烹鮮。", "轉浦雲壑媚，涉江花島連。綠芳暗楚水，白鳥飛吳煙。", "贈贐亦奚貴，流亂期早旋。金閨會通籍，生事豈徒然。"]'),
('yuding-29','不調歸東川別業','李頎','唐','御定全唐诗','yuding','','[]','寸祿言可取，托身將見遺。慚無匹夫志，悔與名山辭。',120,'御定全唐詩/json/132.json','["寸祿言可取，托身將見遺。慚無匹夫志，悔與名山辭。", "紱冕謝知己，林園多後時。葛巾方濯足，蔬食但垂帷。", "十室對河岸，漁樵祗在茲。青郊香杜若，白水映茅茨。", "晝景徹雲樹，夕陰澄古逵。渚花獨開晚，田鶴靜飛遲。", "且複樂生事，前賢為我師。清歌聊鼓楫，永日望佳期。"]'),
('yuding-30','晚歸東園','李頎','唐','御定全唐诗','yuding','','[]','出郭喜見山，東行亦未遠。夕陽帶歸路，靄靄秋稼晚。',48,'御定全唐詩/json/132.json','["出郭喜見山，東行亦未遠。夕陽帶歸路，靄靄秋稼晚。", "樵者乘霽歸，野夫及星飯。請謝朱輪客，垂竿不復返。"]'),
('yuding-31','龍門西峰曉望劉十八不至','李頎','唐','御定全唐诗','yuding','','[]','春台臨永路，跂足望行子。片片雲觸峰，離離鳥渡水。',48,'御定全唐詩/json/132.json','["春台臨永路，跂足望行子。片片雲觸峰，離離鳥渡水。", "叢林遠山上，霽景雜花裏。不見攜手人，下山采綠芷。"]'),
('yuding-32','裴尹東溪別業','李頎','唐','御定全唐诗','yuding','','[]','公才廊廟器，官亞河南守。別墅臨都門，驚湍激前後。',120,'御定全唐詩/json/132.json','["公才廊廟器，官亞河南守。別墅臨都門，驚湍激前後。", "舊交與群從，十日一攜手。幅巾望寒山，長嘯對高柳。", "清歡信可尚，散吏亦何有。岸雪清城陰，水光遠林首。", "閑觀野人筏，或飲川上酒。幽雲澹徘徊，白鷺飛左右。", "庭竹垂臥內，村煙隔南阜。始知物外情，簪紱同芻狗。"]'),
('yuding-33','無盡上人東林禪居','李頎','唐','御定全唐诗','yuding','','[]','草堂每多暇，時謁山僧門。所對但群木，終朝無一言。',120,'御定全唐詩/json/132.json','["草堂每多暇，時謁山僧門。所對但群木，終朝無一言。", "我心愛流水，此地臨清源。含吐山上日，蔽虧松外村。", "孤峰隔身世，百衲老寒暄。禪戶積朝雪，花龕來暮猿。", "顧餘守耕稼，十載隱田園。蘿筱慰舂汲，岩潭恣討論。", "泄雲豈知限，至道莫探元。且願啟關鎖，于焉微尚存。"]'),
('yuding-34','題綦毋校書別業','李頎','唐','御定全唐诗','yuding','','[]','常稱掛冠吏，昨日歸滄洲。行客暮帆遠，主人庭樹秋。',96,'御定全唐詩/json/132.json','["常稱掛冠吏，昨日歸滄洲。行客暮帆遠，主人庭樹秋。", "豈伊問天命，但欲為山遊。萬物我何有，白雲空自幽。", "蕭條江海上，日夕見丹丘。生事非漁釣，賞心隨去留。", "惜哉曠微月，欲濟無輕舟。倏忽令人老，相思河水流。"]'),
('yuding-35','題盧道士房','李頎','唐','御定全唐诗','yuding','','[]','秋砧響落木，共坐茅君家。惟見兩童子，林前汲井華。',72,'御定全唐詩/json/132.json','["秋砧響落木，共坐茅君家。惟見兩童子，林前汲井華。", "空壇靜白日，神鼎飛丹砂。麈尾拂霜草，金鈴搖霽霞。", "上章人世隔，看弈桐陰斜。稽首問仙要，黃精堪餌花。"]'),
('yuding-36','題神力師院','李頎','唐','御定全唐诗','yuding','','[]','大師神傑貌，五嶽森禪房。堅持日月珠，豁見滄江長。',72,'御定全唐詩/json/132.json','["大師神傑貌，五嶽森禪房。堅持日月珠，豁見滄江長。", "隨病拔諸苦，致身如法王。階庭藥草遍，飯食天花香。", "樹色向高閣，晝陰橫半牆。每聞第一義，心淨琉璃光。"]'),
('yuding-37','題僧房雙桐','李頎','唐','御定全唐诗','yuding','','[]','青桐雙拂日，傍帶淩霄花。綠葉傳僧磬，清陰潤井華。',36,'御定全唐詩/json/132.json','["青桐雙拂日，傍帶淩霄花。綠葉傳僧磬，清陰潤井華。", "誰能事音律，焦尾蔡邕家。"]'),
('yuding-38','粲公院各賦一物得初荷','李頎','唐','御定全唐诗','yuding','','[]','微風和眾草，大葉長圓陰。晴露珠共合，夕陽花映深。',36,'御定全唐詩/json/132.json','["微風和眾草，大葉長圓陰。晴露珠共合，夕陽花映深。", "從來不著水，清淨本因心。"]'),
('yuding-39','李兵曹壁畫山水各賦得桂水帆','李頎','唐','御定全唐诗','yuding','','[]','片帆浮桂水，落日天涯時。飛鳥看共度，閑雲相與遲。',36,'御定全唐詩/json/132.json','["片帆浮桂水，落日天涯時。飛鳥看共度，閑雲相與遲。", "長波無曉夜，泛泛欲何之。"]'),
('yuding-40','題合歡','李頎','唐','御定全唐诗','yuding','','[]','開花複卷葉，豔眼又驚心。蝶繞西枝露，風披東幹陰。',36,'御定全唐詩/json/132.json','["開花複卷葉，豔眼又驚心。蝶繞西枝露，風披東幹陰。", "黃衫漂細蕊，時拂女郎砧。"]'),
('yuding-0','古從軍行','李頎','唐','御定全唐诗','yuding','','[]','白日登山望烽火，黃昏飲馬傍交河。行人刁鬥風沙暗，',48,'御定全唐詩/json/133.json','["白日登山望烽火，黃昏飲馬傍交河。行人刁鬥風沙暗，", "胡雁哀鳴夜夜飛，胡兒眼淚雙雙落。聞道玉門猶被遮，"]'),
('yuding-1','行路難','李頎','唐','御定全唐诗','yuding','','[]','漢家名臣楊德祖，四代五公享茅土。父子兄弟綰銀黃，',88,'御定全唐詩/json/133.json','["漢家名臣楊德祖，四代五公享茅土。父子兄弟綰銀黃，", "賓客填街複滿座，片言出口生輝光。世人逐勢爭奔走，", "一朝謝病還鄉里，窮巷蒼苔絕知己。秋風落葉閉重門，", "魯連所以蹈東海，古往今來稱達人。"]'),
('yuding-2','緩歌行','李頎','唐','御定全唐诗','yuding','','[]','小來托身攀貴遊，傾財破產無所憂。暮擬經過石渠署，',88,'御定全唐詩/json/133.json','["小來托身攀貴遊，傾財破產無所憂。暮擬經過石渠署，", "一沉一浮會有時，棄我翻然如脫屣。男兒立身須自強，", "二八蛾眉梳墮馬，美酒清歌曲房下。文昌宮中賜錦衣，", "早知今日讀書是，悔作從前任俠非。"]'),
('yuding-3','琴歌','李頎','唐','御定全唐诗','yuding','','[]','主人有酒歡今夕，請奏鳴琴廣陵客。月照城頭烏半飛，',48,'御定全唐詩/json/133.json','["主人有酒歡今夕，請奏鳴琴廣陵客。月照城頭烏半飛，", "一聲已動物皆靜，四座無言星欲稀。清淮奉使千餘裏，"]'),
('yuding-4','放歌行答從弟墨卿','李頎','唐','御定全唐诗','yuding','','[]','小來好文恥學武，世上功名不解取。雖沾寸祿已後時，',96,'御定全唐詩/json/133.json','["小來好文恥學武，世上功名不解取。雖沾寸祿已後時，", "斂跡俯眉心自甘，高歌擊節聲半苦。由是蹉跎一老夫，", "徒爾當年聲籍籍，濫作詞林兩京客。故人鬥酒安陵橋，", "興來逸氣如濤湧，千里長江歸海時。別離短景何蕭索，"]'),
('yuding-5','王母歌','李頎','唐','御定全唐诗','yuding','','[]','武皇齋戒承華殿，端拱須臾王母見。霓旌照耀麒麟車，',96,'御定全唐詩/json/133.json','["武皇齋戒承華殿，端拱須臾王母見。霓旌照耀麒麟車，", "頭上複戴九星冠，總領玉童坐南面。欲聞要言今告汝，", "顧謂侍女董雙成，酒闌可奏雲和笙。紅霞白日儼不動，", "複道歌鐘杳將暮，深宮桃李花成雪。為看青玉五枝燈，"]'),
('yuding-6','鮫人歌','李頎','唐','御定全唐诗','yuding','','[]','鮫人潛織水底居，側身上下隨遊魚。輕綃文彩不可識，',48,'御定全唐詩/json/133.json','["鮫人潛織水底居，側身上下隨遊魚。輕綃文彩不可識，", "泣珠報恩君莫辭，今年相見明年期。始知萬族無不有，"]'),
('yuding-7','夏宴張兵曹東堂','李頎','唐','御定全唐诗','yuding','','[]','重林華屋堪避暑，況乃烹鮮會佳客。主人三十朝大夫，',48,'御定全唐詩/json/133.json','["重林華屋堪避暑，況乃烹鮮會佳客。主人三十朝大夫，", "羽扇搖風卻珠汗，玉盆貯水割甘瓜。雲峰峨峨自冰雪，"]'),
('yuding-8','同張員外諲酬答之作','李頎','唐','御定全唐诗','yuding','','[]','洛中高士日沉冥，手自灌園方帶經。王湛床頭見周易，',48,'御定全唐詩/json/133.json','["洛中高士日沉冥，手自灌園方帶經。王湛床頭見周易，", "清言只到衛家兒，用筆能誇鐘太尉。東籬二月種蘭蓀，"]'),
('yuding-9','欲之新鄉答崔顥綦毋潛','李頎','唐','御定全唐诗','yuding','','[]','數年作吏家屢空，誰道黑頭成老翁。男兒在世無產業，',72,'御定全唐詩/json/133.json','["數年作吏家屢空，誰道黑頭成老翁。男兒在世無產業，", "銅爐將炙相歡飲，星宿縱橫露華白。寒風卷葉度滹沱，", "明朝東路把君手，臘日辭君期歲首。自知寂寞無去思，"]'),
('yuding-10','答高三十五留別便呈于十一','李頎','唐','御定全唐诗','yuding','','[]','累薦賢良皆不就，家近陳留訪耆舊。韓康雖複在人間，',88,'御定全唐詩/json/133.json','["累薦賢良皆不就，家近陳留訪耆舊。韓康雖複在人間，", "妻子歡同五株柳，雲山老對一床書。昨日公車見三事，", "散誕由來自不羈，低頭授職爾何為。故園壁掛烏紗帽，", "藜羹被褐環堵中，歲晚將貽故人恥。"]'),
('yuding-11','送康洽入京進樂府歌','李頎','唐','御定全唐诗','yuding','','[]','識子十年何不遇，只愛歡游兩京路。朝吟左氏嬌女篇，',72,'御定全唐詩/json/133.json','["識子十年何不遇，只愛歡游兩京路。朝吟左氏嬌女篇，", "柳色偏濃九華殿，鶯聲醉殺五陵兒。曳裾此日從何所，", "新詩樂府唱堪愁，禦妓應傳鳷鵲樓。西上雖因長公主，"]'),
('yuding-12','送劉十','李頎','唐','御定全唐诗','yuding','','[]','三十不官亦不娶，時人焉識道高下。房中唯有老氏經，',72,'御定全唐詩/json/133.json','["三十不官亦不娶，時人焉識道高下。房中唯有老氏經，", "西林獨鶴引閒步，南澗飛泉清角巾。前年上書不得意，", "烹葵摘果告我行，落日夏雲縱複橫。聞道謝安掩口笑，"]'),
('yuding-13','送王道士還山','李頎','唐','御定全唐诗','yuding','','[]','嵩陽道士餐柏實，居處三花對石室。心窮伏火陽精丹，',88,'御定全唐詩/json/133.json','["嵩陽道士餐柏實，居處三花對石室。心窮伏火陽精丹，", "出入彤庭佩金印，承恩赫赫如王侯。雙峰樹下曾受業，", "玉膏清泠瀑泉水，白雲溪中日方此。後今不見數十年，", "當有岩前白蝙蝠，迎君日暮雙來飛。"]'),
('yuding-14','別梁鍠','李頎','唐','御定全唐诗','yuding','','[]','梁生倜儻心不羈，途窮氣蓋長安兒。回頭轉眄似雕鶚，',120,'御定全唐詩/json/133.json','["梁生倜儻心不羈，途窮氣蓋長安兒。回頭轉眄似雕鶚，", "抗辭請刃誅部曲，作色論兵犯二帥。一言不合龍額侯，", "庭中犢鼻昔嘗掛，懷裏琅玕今在無。時人見子多落魄，", "洛陽城頭曉霜白，層冰峨峨滿川澤。但聞行路吟新詩，", "莫言富貴長可托，木槿朝看暮還落。不見古時塞上翁，"]'),
('yuding-15','送從弟游江淮兼謁鄱陽劉太守','李頎','唐','御定全唐诗','yuding','','[]','都門柳色朝朝新，念爾今為江上人。穆陵關帶清風遠，',24,'御定全唐詩/json/133.json','["都門柳色朝朝新，念爾今為江上人。穆陵關帶清風遠，"]'),
('yuding-16','雙筍歌送李回兼呈劉四','李頎','唐','御定全唐诗','yuding','','[]','並抽新筍色漸綠，迥出空林雙碧玉。春風解籜雨潤根，',40,'御定全唐詩/json/133.json','["並抽新筍色漸綠，迥出空林雙碧玉。春風解籜雨潤根，", "再三抱此悵為別，嵩洛故人與之說。"]'),
('yuding-17','送劉四赴夏縣','李頎','唐','御定全唐诗','yuding','','[]','九霄特立紅鸞姿，萬仞孤生玉樹枝。劉侯致身能若此，',136,'御定全唐詩/json/133.json','["九霄特立紅鸞姿，萬仞孤生玉樹枝。劉侯致身能若此，", "舉世皆親丞相閣，我心獨愛伊川水。脫略勢利猶埃塵，", "明主拜官麒麟閣，光車駿馬看玉童。高人往來廬山遠，", "赤縣繁詞滿劇曹，白雲孤峰暉永日。朝持手板望飛鳥，", "端坐訟庭更無事，開門咫尺巫咸山。男耕女織蒙惠化，", "聞道桐鄉有遺老，邑中還欲置生祠。"]'),
('yuding-18','少室雪晴送王甯','李頎','唐','御定全唐诗','yuding','','[]','少室眾峰幾峰別，一峰晴見一峰雪。隔城半山連青松，',48,'御定全唐詩/json/133.json','["少室眾峰幾峰別，一峰晴見一峰雪。隔城半山連青松，", "行人與我玩幽境，北風切切吹衣冷。惜別浮橋駐馬時，"]'),
('yuding-19','送陳章甫','李頎','唐','御定全唐诗','yuding','','[]','四月南風大麥黃，棗花未落桐陰長。青山朝別暮還見，',72,'御定全唐詩/json/133.json','["四月南風大麥黃，棗花未落桐陰長。青山朝別暮還見，", "腹中貯書一萬卷，不肯低頭在草莽。東門酤酒飲我曹，", "長河浪頭連天黑，津口停舟渡不得。鄭國遊人未及家，"]'),
('yuding-20','聽安萬善吹觱篥歌','李頎','唐','御定全唐诗','yuding','','[]','南山截竹為觱篥，此樂本自龜茲出。流傳漢地曲轉奇，',72,'御定全唐詩/json/133.json','["南山截竹為觱篥，此樂本自龜茲出。流傳漢地曲轉奇，", "世人解聽不解賞，長飆風中自來往。枯桑老柏寒颼飀，", "忽然更作漁陽摻，黃雲蕭條白日暗。變調如聞楊柳春，"]'),
('yuding-21','魏倉曹東堂檉樹','李頎','唐','御定全唐诗','yuding','','[]','愛君雙檉一樹奇，千葉齊生萬葉垂。長頭拂石帶煙雨，',40,'御定全唐詩/json/133.json','["愛君雙檉一樹奇，千葉齊生萬葉垂。長頭拂石帶煙雨，", "洛陽墨客遊雲間，若到麻源第三穀。"]'),
('yuding-22','照公院雙橙','李頎','唐','御定全唐诗','yuding','','[]','種橙夾階生得地，細葉隔簾見雙翠。抽條向長未及肩，',48,'御定全唐詩/json/133.json','["種橙夾階生得地，細葉隔簾見雙翠。抽條向長未及肩，", "永願香爐灑甘露，夕陽時映東枝斜。南庭黃竹爾不敵，"]'),
('yuding-23','愛敬寺古藤歌','李頎','唐','御定全唐诗','yuding','','[]','古藤池水盤樹根，左攫右拏龍虎蹲。橫空直上相陵突，',48,'御定全唐詩/json/133.json','["古藤池水盤樹根，左攫右拏龍虎蹲。橫空直上相陵突，", "空庭落葉乍開合，十月苦寒常倒垂。憶昨花飛滿空殿，"]'),
('yuding-24','崔五六圖屏風各賦一物得烏孫佩刀','李頎','唐','御定全唐诗','yuding','','[]','烏孫腰間佩兩刀，刃可吹毛錦為帶。握中枕宿穹廬室，',48,'御定全唐詩/json/133.json','["烏孫腰間佩兩刀，刃可吹毛錦為帶。握中枕宿穹廬室，", "磨用陰山一片玉，洗將胡地獨流泉。主人屏風寫奇狀，"]'),
('yuding-25','古意','李頎','唐','御定全唐诗','yuding','','[]','男兒事長征，少小幽燕客。賭勝馬蹄下，由來輕七尺。',60,'御定全唐詩/json/133.json','["男兒事長征，少小幽燕客。賭勝馬蹄下，由來輕七尺。", "殺人莫敢前，須如蝟毛磔。黃雲隴底白雪飛，", "今為羌笛出塞聲，使我三軍淚如雨。"]'),
('yuding-26','採蓮','李頎','唐','御定全唐诗','yuding','','[]','越溪女，越溪蓮。齊菡萏，雙嬋娟。嬉游向何處，',22,'御定全唐詩/json/133.json','["越溪女，越溪蓮。齊菡萏，雙嬋娟。嬉游向何處，"]'),
('yuding-27','雜興','李頎','唐','御定全唐诗','yuding','','[]','沉沉牛渚磯，舊說多靈怪。行人夜秉生犀燭，',84,'御定全唐詩/json/133.json','["沉沉牛渚磯，舊說多靈怪。行人夜秉生犀燭，", "波驚海若潛幽石，龍抱胡髯臥黑泉。水濱丈人曾有語，", "青青蘭艾本殊香，察見泉魚固不祥。濟水自清河自濁，", "善惡死生齊一貫，只應鬥酒任蒼蒼。"]'),
('yuding-28','絕纓歌','李頎','唐','御定全唐诗','yuding','','[]','楚王宴客章華台，章華美人善歌舞。玉顏豔豔空相向，',48,'御定全唐詩/json/133.json','["楚王宴客章華台，章華美人善歌舞。玉顏豔豔空相向，", "寧愛賢，不愛色，青娥買死誰能識，果卻一軍全社稷。"]'),
('yuding-29','鄭櫻桃歌','李頎','唐','御定全唐诗','yuding','','[]','石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。',108,'御定全唐詩/json/133.json','["石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。", "櫻桃美顏香且澤，娥娥侍寢專宮掖。後庭卷衣三萬人，", "織成花映紅綸巾，紅旗掣曳鹵簿新。鳴鼙走馬接飛鳥，", "自言富貴不可量，女為公主男為王。赤花雙簟珊瑚床，", "鄴城蒼蒼白露微，世事翻覆黃雲飛。"]'),
('yuding-30','送劉昱','李頎','唐','御定全唐诗','yuding','','[]','八月寒葦花，秋江浪頭白。北風吹五兩，誰是潯陽客。',48,'御定全唐詩/json/133.json','["八月寒葦花，秋江浪頭白。北風吹五兩，誰是潯陽客。", "鸕鷀山頭微雨晴，揚州郭裏暮潮生。行人夜宿金陵渚，"]'),
('yuding-31','送郝判官','李頎','唐','御定全唐诗','yuding','','[]','楚城木葉落，夏口青山遍。鴻雁向南時，君乘使者傳。',72,'御定全唐詩/json/133.json','["楚城木葉落，夏口青山遍。鴻雁向南時，君乘使者傳。", "楓林帶水驛，夜火明山縣。千里送行人，蔡州如眼見。", "江連清漢東逶迤，遙望荊雲相蔽虧。應問襄陽舊風俗，"]'),
('yuding-32','送劉方平','李頎','唐','御定全唐诗','yuding','','[]','綺紈游上國，多作少年行。二十二詞賦，惟君著美名。',96,'御定全唐詩/json/133.json','["綺紈游上國，多作少年行。二十二詞賦，惟君著美名。", "童顏且白皙，佩德如瑤瓊。荀氏風流盛，胡家公子清。", "有才不偶誰之過，肯即藏鋒事高臥。洛陽草色猶自春，", "別離鬥酒心相許，落日青郊半微雨。請君騎馬望西陵，"]'),
('yuding-33','聽董大彈胡笳聲兼寄語弄房給事','李頎','唐','御定全唐诗','yuding','','[]','蔡女昔造胡笳聲，一彈一十有八拍。胡人落淚沾邊草，',120,'御定全唐詩/json/133.json','["蔡女昔造胡笳聲，一彈一十有八拍。胡人落淚沾邊草，", "先拂商弦後角羽，四郊秋葉驚摵摵。董夫子，通神明，", "空山百鳥散還合，萬里浮雲陰且晴。嘶酸雛雁失群夜，", "烏孫部落家鄉遠，邏娑沙塵哀怨生。幽音變調忽飄灑，", "長安城連東掖垣，鳳凰池對青瑣門。高才脫略名與利，"]'),
('yuding-34','彈棋歌','李頎','唐','御定全唐诗','yuding','','[]','崔侯善彈棋，巧妙盡於此。藍田美玉清如砥，',60,'御定全唐詩/json/133.json','["崔侯善彈棋，巧妙盡於此。藍田美玉清如砥，", "緣邊度隴未可嘉，鳥跂星懸危複斜。回飆轉指速飛電，", "一別常山道路遙，為餘更作三五勢。"]'),
('yuding-35','送山陰姚丞攜妓之任兼寄蘇少府','李頎','唐','御定全唐诗','yuding','','[]','東風香草路，南客心容與。白皙吳王孫，青蛾柳家女。',96,'御定全唐詩/json/133.json','["東風香草路，南客心容與。白皙吳王孫，青蛾柳家女。", "都門數騎出，河口片帆舉。夜簟眠橘洲，春衫傍楓嶼。", "山陰政簡甚從容，到罷惟求物外蹤。落日花邊剡溪水，", "加餐共愛鱸魚肥，醒酒仍憐甘蔗熟。知君練思本清新，"]'),
('yuding-0','塞下曲','李頎','唐','御定全唐诗','yuding','','[]','少年學騎射，勇冠並州兒。直愛出身早，邊功沙漠垂。',48,'御定全唐詩/json/134.json','["少年學騎射，勇冠並州兒。直愛出身早，邊功沙漠垂。", "戎鞭腰下插，羌笛雪中吹。膂力今應盡，將軍猶未知。"]'),
('yuding-1','寄鏡湖朱處士','李頎','唐','御定全唐诗','yuding','','[]','澄霽晚流闊，微風吹綠蘋。鱗鱗遠峰見，淡淡平湖春。',48,'御定全唐詩/json/134.json','["澄霽晚流闊，微風吹綠蘋。鱗鱗遠峰見，淡淡平湖春。", "芳草日堪把，白雲心所親。何時可為樂，夢裏東山人。"]'),
('yuding-2','宴陳十六樓','李頎','唐','御定全唐诗','yuding','','[]','西樓對金谷，此地古人心。白日落庭內，黃花生澗陰。',48,'御定全唐詩/json/134.json','["西樓對金谷，此地古人心。白日落庭內，黃花生澗陰。", "四鄰見疏木，萬井度寒砧。石上題詩處，千年留至今。"]'),
('yuding-3','送相裏造入京','李頎','唐','御定全唐诗','yuding','','[]','子月過秦正，寒雲覆洛城。嗟君未得志，猶作苦辛行。',48,'御定全唐詩/json/134.json','["子月過秦正，寒雲覆洛城。嗟君未得志，猶作苦辛行。", "暖酒嫌衣薄，瞻風候雨晴。春官含笑待，驅馬速前程。"]'),
('yuding-4','送錢子入京','李頎','唐','御定全唐诗','yuding','','[]','夜夢還京北，鄉心恨擣衣。朝逢入秦使，走馬喚君歸。',48,'御定全唐詩/json/134.json','["夜夢還京北，鄉心恨擣衣。朝逢入秦使，走馬喚君歸。", "驛路清霜下，關門黃葉稀。還家應信宿，看子速如飛。"]'),
('yuding-5','送綦毋三寺中賦得紗燈','李頎','唐','御定全唐诗','yuding','','[]','禪室吐香燼，輕紗籠翠煙。長繩掛青竹，百尺垂紅蓮。',48,'御定全唐詩/json/134.json','["禪室吐香燼，輕紗籠翠煙。長繩掛青竹，百尺垂紅蓮。", "熠爚眾星下，玲瓏雙塔前。含光待明發，此別豈徒然。"]'),
('yuding-6','送人尉閩中','李頎','唐','御定全唐诗','yuding','','[]','可歎芳菲日，分為萬里情。閶門折垂柳，御苑聽殘鶯。',48,'御定全唐詩/json/134.json','["可歎芳菲日，分為萬里情。閶門折垂柳，御苑聽殘鶯。", "海戍通閩邑，江航過楚城。客心君莫問，春草是王程。"]'),
('yuding-7','送人歸沔南','李頎','唐','御定全唐诗','yuding','','[]','梅花今正發，失路複何如。舊國雲山在，新年風景餘。',48,'御定全唐詩/json/134.json','["梅花今正發，失路複何如。舊國雲山在，新年風景餘。", "春饒漢陽夢，日寄武陵書。可即明時老，臨川莫羨魚。"]'),
('yuding-8','送盧逸人','李頎','唐','御定全唐诗','yuding','','[]','洛陽為此別，攜手更何時。不復人間見，只應海上期。',48,'御定全唐詩/json/134.json','["洛陽為此別，攜手更何時。不復人間見，只應海上期。", "清溪入雲木，白首臥茅茨。共惜盧敖去，天邊望所思。"]'),
('yuding-9','送顧朝陽還吳','李頎','唐','御定全唐诗','yuding','','[]','寂寞俱不偶，裹糧空入秦。宦途已可識，歸臥包山春。',48,'御定全唐詩/json/134.json','["寂寞俱不偶，裹糧空入秦。宦途已可識，歸臥包山春。", "舊國指飛鳥，滄波愁旅人。開樽洛水上，怨別柳花新。"]'),
('yuding-10','送竇參軍','李頎','唐','御定全唐诗','yuding','','[]','城南送歸客，舉酒對林巒。暄鳥迎風囀，春衣度雨寒。',48,'御定全唐詩/json/134.json','["城南送歸客，舉酒對林巒。暄鳥迎風囀，春衣度雨寒。", "桃花開翠幕，柳色拂金鞍。公子何時至，無令芳草闌。"]'),
('yuding-11','望秦川','李頎','唐','御定全唐诗','yuding','','[]','秦川朝望迥，日出正東峰。遠近山河淨，逶迤城闕重。',48,'御定全唐詩/json/134.json','["秦川朝望迥，日出正東峰。遠近山河淨，逶迤城闕重。", "秋聲萬戶竹，寒色五陵松。客有歸歟歎，淒其霜露濃。"]'),
('yuding-12','晚歸東園','李頎','唐','御定全唐诗','yuding','','[]','荊扉帶郊郭，稼穡滿東菑。倚杖寒山暮，鳴梭秋葉時。',48,'御定全唐詩/json/134.json','["荊扉帶郊郭，稼穡滿東菑。倚杖寒山暮，鳴梭秋葉時。", "回雲覆陰谷，返景照霜梨。澹泊真吾事，清風別自茲。"]'),
('yuding-13','覺公院施鳥石台','李頎','唐','御定全唐诗','yuding','','[]','石台置香飯，齋後施諸禽。童子亦知善，眾生無懼心。',48,'御定全唐詩/json/134.json','["石台置香飯，齋後施諸禽。童子亦知善，眾生無懼心。", "苔痕蒼曉露，盤勢出香林。錫杖或圍繞，吾師一念深。"]'),
('yuding-14','籬筍','李頎','唐','御定全唐诗','yuding','','[]','東園長新筍，映日複穿籬。迸出依青嶂，攢生伴綠池。',48,'御定全唐詩/json/134.json','["東園長新筍，映日複穿籬。迸出依青嶂，攢生伴綠池。", "色因林向背，行逐地高卑。但恐春將老，青青獨爾為。"]'),
('yuding-15','達奚吏部夫人寇氏挽歌','李頎','唐','御定全唐诗','yuding','','[]','存歿令名傳，青青松柏田。事姑稱孝婦，生子繼先賢。',48,'御定全唐詩/json/134.json','["存歿令名傳，青青松柏田。事姑稱孝婦，生子繼先賢。", "露濕銘旌重，風吹鹵簿前。陰堂從此閉，誰誦女師篇。"]'),
('yuding-16','寄司勳盧員外','李頎','唐','御定全唐诗','yuding','','[]','流澌臘月下河陽，草色新年發建章。秦地立春傳太史，',40,'御定全唐詩/json/134.json','["流澌臘月下河陽，草色新年發建章。秦地立春傳太史，", "早晚薦雄文似者，故人今已賦長楊。"]'),
('yuding-17','寄綦毋三','李頎','唐','御定全唐诗','yuding','','[]','新加大邑綬仍黃，近與單車去洛陽。顧眄一過丞相府，',40,'御定全唐詩/json/134.json','["新加大邑綬仍黃，近與單車去洛陽。顧眄一過丞相府，", "共道進賢蒙上賞，看君幾歲作台郎。"]'),
('yuding-18','送魏萬之京','李頎','唐','御定全唐诗','yuding','','[]','朝聞遊子唱離歌，昨夜微霜初渡河。鴻雁不堪愁裏聽，',40,'御定全唐詩/json/134.json','["朝聞遊子唱離歌，昨夜微霜初渡河。鴻雁不堪愁裏聽，", "莫見長安行樂處，空令歲月易蹉跎。"]'),
('yuding-19','送李回','李頎','唐','御定全唐诗','yuding','','[]','知君官屬大司農，詔幸驪山職事雄。歲發金錢供禦府，',40,'御定全唐詩/json/134.json','["知君官屬大司農，詔幸驪山職事雄。歲發金錢供禦府，", "不睹聲明與文物，自傷流滯去關東。"]'),
('yuding-20','宿瑩公禪房聞梵','李頎','唐','御定全唐诗','yuding','','[]','花宮仙梵遠微微，月隱高城鐘漏稀。夜動霜林驚落葉，',40,'御定全唐詩/json/134.json','["花宮仙梵遠微微，月隱高城鐘漏稀。夜動霜林驚落葉，", "始覺浮生無住著，頓令心地欲皈依。"]'),
('yuding-21','題璿公山池','李頎','唐','御定全唐诗','yuding','','[]','遠公遁跡廬山岑，開士幽居祇樹林。片石孤峰窺色相，',40,'御定全唐詩/json/134.json','["遠公遁跡廬山岑，開士幽居祇樹林。片石孤峰窺色相，", "此外俗塵都不染，惟餘玄度得相尋。"]'),
('yuding-22','題盧五舊居','李頎','唐','御定全唐诗','yuding','','[]','物在人亡無見期，閒庭系馬不勝悲。窗前綠竹生空地，',40,'御定全唐詩/json/134.json','["物在人亡無見期，閒庭系馬不勝悲。窗前綠竹生空地，", "憶君淚落東流水，歲歲花開知為誰。"]'),
('yuding-23','贈別張兵曹','李頎','唐','御定全唐诗','yuding','','[]','漢家蕭相國，功蓋五諸侯。勳業河山重，丹青錫命優。',120,'御定全唐詩/json/134.json','["漢家蕭相國，功蓋五諸侯。勳業河山重，丹青錫命優。", "君為禁臠婿，爭看玉人遊。荀令焚香日，潘郎振藻秋。", "新成鸚鵡賦，能衣鷫鸘裘。不憚軒車遠，仍尋薜荔幽。", "苑梨飛絳葉，伊水淨寒流。雪滿故關道，雲遮祥鳳樓。", "一身輕寸祿，萬物任虛舟。別後如相問，滄波雙白鷗。"]'),
('yuding-24','宿香山寺石樓','李頎','唐','御定全唐诗','yuding','','[]','夜宿翠微半，高樓聞暗泉。漁舟帶遠火，山磬發孤煙。',72,'御定全唐詩/json/134.json','["夜宿翠微半，高樓聞暗泉。漁舟帶遠火，山磬發孤煙。", "衣拂雲松外，門清河漢邊。峰巒低枕席，世界接人天。", "靄靄花出霧，輝輝星映川。東林曙鶯滿，惆悵欲言旋。"]'),
('yuding-25','聖善閣送裴迪入京','李頎','唐','御定全唐诗','yuding','','[]','雲華滿高閣，苔色上鉤欄。藥草空階靜，梧桐返照寒。',72,'御定全唐詩/json/134.json','["雲華滿高閣，苔色上鉤欄。藥草空階靜，梧桐返照寒。", "清吟可愈疾，攜手暫同歡。墜葉和金磬，饑烏鳴露盤。", "伊流惜東別，灞水向西看。舊托含香署，雲霄何足難。"]'),
('yuding-26','奉送漪叔游潁川兼謁淮陽太守','李頎','唐','御定全唐诗','yuding','','[]','罷吏今何適，辭家方獨行。嵩陽入歸夢，潁水半前程。',72,'御定全唐詩/json/134.json','["罷吏今何適，辭家方獨行。嵩陽入歸夢，潁水半前程。", "聞道淮陽守，東南臥理清。郡齋觀政日，人馬望鄉情。", "疊嶺雪初霽，寒砧霜後鳴。臨川嗟拜手，寂寞事躬耕。"]'),
('yuding-27','二妃廟送裴侍禦使桂陽','李頎','唐','御定全唐诗','yuding','','[]','沅上秋草晚，蒼蒼堯女祠。無人見精魄，萬古寒猿悲。',72,'御定全唐詩/json/134.json','["沅上秋草晚，蒼蒼堯女祠。無人見精魄，萬古寒猿悲。", "桂水身歿後，椒漿神降時。回雲迎赤豹，驟雨颯文狸。", "受命出炎海，焚香征楚詞。乘驄感遺跡，一吊清川湄。"]'),
('yuding-28','送暨道士還玉清觀','李頎','唐','御定全唐诗','yuding','','[]','仙宮有名籍，度世吳江濆。大道本無我，青春長與君。',72,'御定全唐詩/json/134.json','["仙宮有名籍，度世吳江濆。大道本無我，青春長與君。", "中州俄已到，至理得而聞。明主降黃屋，時人看白雲。", "空山何窈窕，三秀日氛氳。遂此留書客，超遙煙駕分。"]'),
('yuding-29','送劉主簿歸金壇','李頎','唐','御定全唐诗','yuding','','[]','與子十年舊，其如離別何。宦遊鄰故國，歸夢是滄波。',72,'御定全唐詩/json/134.json','["與子十年舊，其如離別何。宦遊鄰故國，歸夢是滄波。", "京口青山遠，金陵芳草多。雲帆曉容裔，江日晝清和。", "縣郭舟人飲，津亭漁者歌。茅山有仙洞，羨爾再經過。"]'),
('yuding-30','送盧少府赴延陵','李頎','唐','御定全唐诗','yuding','','[]','問君從宦所，何日府中趨。遙指金陵縣，青山天一隅。',96,'御定全唐詩/json/134.json','["問君從宦所，何日府中趨。遙指金陵縣，青山天一隅。", "行人懷寸祿，小吏獻新圖。北固波濤險，南天風俗殊。", "春江連橘柚，晚景媚菰蒲。漠漠花生渚，亭亭雲過湖。", "灘沙映村火，水霧斂檣烏。回首東門路，鄉書不可無。"]'),
('yuding-31','送皇甫曾遊襄陽山水兼謁韋太守','李頎','唐','御定全唐诗','yuding','','[]','峴山枕襄陽，滔滔江漢長。山深臥龍宅，水淨斬蛟鄉。',120,'御定全唐詩/json/134.json','["峴山枕襄陽，滔滔江漢長。山深臥龍宅，水淨斬蛟鄉。", "元凱春秋傳，昭明文選堂。風流滿今古，煙島思微茫。", "白雁暮沖雪，青林寒帶霜。蘆花獨戍晚，柑實萬家香。", "舊國欲茲別，輕舟眇未央。百花亭漫漫，一柱觀蒼蒼。", "按俗荊南牧，持衡吏部郎。逢君立五馬，應醉習家塘。"]'),
('yuding-32','龍門送裴侍禦監五嶺選','李頎','唐','御定全唐诗','yuding','','[]','萬里番禺地，官人繼帝憂。君為柱下史，將命出東周。',120,'御定全唐詩/json/134.json','["萬里番禺地，官人繼帝憂。君為柱下史，將命出東周。", "歇馬傍川路，張燈臨石樓。棱棱靜疏木，濞濞響寒流。", "榔葉四荒外，梅花五嶺頭。明珠尉佗國，翠羽夜郎洲。", "夷俗富珍產，土風資宦遊。心清物不雜，弊革事無留。", "舉善必稱最，持奸當去尤。何辭桂江遠，今日用賢秋。"]'),
('yuding-33','送喬琳','李頎','唐','御定全唐诗','yuding','','[]','草綠小平津，花開伊水濱。今君不得意，孤負帝鄉春。',120,'御定全唐詩/json/134.json','["草綠小平津，花開伊水濱。今君不得意，孤負帝鄉春。", "口不言金帛，心常任屈伸。阮公惟飲酒，陶令肯羞貧。", "陽羨風流地，滄江遊寓人。菱歌五湖遠，桂樹八公鄰。", "青鳥迎孤棹，白雲隨一身。潮隨秣陵上，月映石頭新。", "未可逃名利，應須在縉紳。汀洲芳杜色，勸爾暫垂綸。"]'),
('yuding-34','題少府監李丞山池','李頎','唐','御定全唐诗','yuding','','[]','能向府亭內，置茲山與林。他人驌驦馬，而我薜蘿心。',72,'御定全唐詩/json/134.json','["能向府亭內，置茲山與林。他人驌驦馬，而我薜蘿心。", "雨止禁門肅，鶯啼官柳深。長廊閟軍器，積水背城陰。", "窗外王孫草，床頭中散琴。清風多仰慕，吾亦爾知音。"]'),
('yuding-35','長壽寺粲公院新甃井','李頎','唐','御定全唐诗','yuding','','[]','僧房來往久，露井每同觀。白石抱新甃，蒼苔依舊欄。',60,'御定全唐詩/json/134.json','["僧房來往久，露井每同觀。白石抱新甃，蒼苔依舊欄。", "空瓶宛轉下，長綆轆轤盤。境界因心淨，泉源見底寒。", "鐘鳴時灌頂，對此日閑安。"]'),
('yuding-36','魏倉曹宅各賦一物得當軒石竹','李頎','唐','御定全唐诗','yuding','','[]','羅生殊眾色，獨為表華滋。雖雜蕙蘭處，無爭桃李時。',60,'御定全唐詩/json/134.json','["羅生殊眾色，獨為表華滋。雖雜蕙蘭處，無爭桃李時。", "同人趨府暇，落日後庭期。密葉散紅點，靈條驚紫蕤。", "芳菲看不厭，採摘願來茲。"]'),
('yuding-37','奉送五叔入京兼寄綦毋三','李頎','唐','御定全唐诗','yuding','','[]','雲陰帶殘日，悵別此何時。欲望黃山道，無由見所思。',24,'御定全唐詩/json/134.json','["雲陰帶殘日，悵別此何時。欲望黃山道，無由見所思。"]'),
('yuding-38','寄韓鵬','李頎','唐','御定全唐诗','yuding','','[]','為政心閑物自閑，朝看飛鳥暮飛還。',32,'御定全唐詩/json/134.json','["為政心閑物自閑，朝看飛鳥暮飛還。", "寄書河上神明宰，羨爾城頭姑射山。"]'),
('yuding-39','《百花原','李頎','唐','御定全唐诗','yuding','','[]','百花原頭望京師，黃河水流無已時。',32,'御定全唐詩/json/134.json','["百花原頭望京師，黃河水流無已時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('yuding-40','遇劉五','李頎','唐','御定全唐诗','yuding','','[]','洛陽一別梨花新，黃鳥飛飛逢故人。',32,'御定全唐詩/json/134.json','["洛陽一別梨花新，黃鳥飛飛逢故人。", "攜手當年共為樂，無驚蕙草惜殘春。"]'),
('yuding-41','送崔嬰赴漢陽','李頎','唐','御定全唐诗','yuding','','[]','中外相連弟與兄，新加小縣子男名。',32,'御定全唐詩/json/134.json','["中外相連弟與兄，新加小縣子男名。", "才年三十佩銅印，知爾弦歌漢水清。"]'),
('yuding-42','送五叔入京兼寄綦毋三','李頎','唐','御定全唐诗','yuding','','[]','吏部明年拜官後，西城必與故人期。',32,'御定全唐詩/json/134.json','["吏部明年拜官後，西城必與故人期。", "寄書春草年年色，莫道相逢玉女祠。"]'),
('yuding-43','野老曝背','李頎','唐','御定全唐诗','yuding','','[]','百歲老翁不種田，惟知曝背樂殘年。',32,'御定全唐詩/json/134.json','["百歲老翁不種田，惟知曝背樂殘年。", "有時捫虱獨搔首，目送歸鴻籬下眠。"]'),
('yuding-44','送東陽王太守','李頎','唐','御定全唐诗','yuding','','[]','江皋杜蘅綠，芳草日遲遲。檜楫今何去，星郎出守時。',96,'御定全唐詩/json/134.json','["江皋杜蘅綠，芳草日遲遲。檜楫今何去，星郎出守時。", "彤襜問風俗，明主寄惸嫠。令下不徒爾，人和當在茲。", "昔年經此地，微月有佳期。洞口桂花白，岩前春草滋。", "素沙靜津瀨，青壁帶川坻。野鶴每孤立，林鼯常晝悲。"]'),
('yuding-45','詠張諲山水','李頎','唐','御定全唐诗','yuding','','[]','小山破體閑支策，落日梨花照空壁。',32,'御定全唐詩/json/134.json','["小山破體閑支策，落日梨花照空壁。", "詩堪記室妒風流，畫與將軍作勍敵。"]'),
('yuding-46','失題','李頎','唐','御定全唐诗','yuding','','[]','紫極殿前朝伏奏，龍華會裏日相望。',32,'御定全唐詩/json/134.json','["紫極殿前朝伏奏，龍華會裏日相望。", "別離歲歲如流水，誰辨他鄉與故鄉。"]'),
('yuding-0','冬夜寓居寄儲太祝','綦毋潛','唐','御定全唐诗','yuding','','[]','自為洛陽客，夫子吾知音。盡義能下士，時人無此心。',48,'御定全唐詩/json/135.json','["自為洛陽客，夫子吾知音。盡義能下士，時人無此心。", "奈何離居夜，巢鳥悲空林。愁坐至月上，複聞南鄰砧。"]'),
('yuding-1','春泛若耶溪','綦毋潛','唐','御定全唐诗','yuding','','[]','幽意無斷絕，此去隨所偶。晚風吹行舟，花路入溪口。',60,'御定全唐詩/json/135.json','["幽意無斷絕，此去隨所偶。晚風吹行舟，花路入溪口。", "際夜轉西壑，隔山望南斗。潭煙飛溶溶，林月低向後。", "生事且彌漫，願為持竿叟。"]'),
('yuding-2','題鶴林寺','綦毋潛','唐','御定全唐诗','yuding','','[]','道林隱形勝，向背臨層霄。松覆山殿冷，花藏溪路遙。',72,'御定全唐詩/json/135.json','["道林隱形勝，向背臨層霄。松覆山殿冷，花藏溪路遙。", "珊珊寶幡掛，焰焰明燈燒。遲日半空谷，春風連上潮。", "少憑水木興，暫令身心調。願謝攜手客，茲山禪誦饒。"]'),
('yuding-3','題棲霞寺','綦毋潛','唐','御定全唐诗','yuding','','[]','南山勢回合，靈境依此住。殿轉雲崖陰，僧探石泉度。',72,'御定全唐詩/json/135.json','["南山勢回合，靈境依此住。殿轉雲崖陰，僧探石泉度。", "龍蛇爭翕習，神鬼皆密護。萬壑奔道場，群峰向雙樹。", "天花飛不著，水月白成路。今日觀身我，歸心複何處。"]'),
('yuding-4','送儲十二還莊城','綦毋潛','唐','御定全唐诗','yuding','','[]','西阪何繚繞，青林問子家。天寒噪野雀，日晚度城鴉。',48,'御定全唐詩/json/135.json','["西阪何繚繞，青林問子家。天寒噪野雀，日晚度城鴉。", "寂曆道傍樹，曈曨原上霞。茲情不可說，長恨隱淪賒。"]'),
('yuding-5','送章彝下第','綦毋潛','唐','御定全唐诗','yuding','','[]','長安渭橋路，行客別時心。獻賦溫泉畢，無媒魏闕深。',48,'御定全唐詩/json/135.json','["長安渭橋路，行客別時心。獻賦溫泉畢，無媒魏闕深。", "黃鶯啼就馬，白日暗歸林。三十名未立，君還惜寸陰。"]'),
('yuding-6','送崔員外黔中監選','綦毋潛','唐','御定全唐诗','yuding','','[]','持衡出帝畿，星指夜郎飛。神女雲迎馬，荊門雨濕衣。',48,'御定全唐詩/json/135.json','["持衡出帝畿，星指夜郎飛。神女雲迎馬，荊門雨濕衣。", "聽猿收淚罷，系雁待書稀。蠻貊雖殊俗，知君肝膽微。"]'),
('yuding-7','送賈恒明府兼寄溫張二司戶','綦毋潛','唐','御定全唐诗','yuding','','[]','越客新安別，秦人舊國情。舟乘晚風便，月帶上潮平。',48,'御定全唐詩/json/135.json','["越客新安別，秦人舊國情。舟乘晚風便，月帶上潮平。", "花路西施石，雲峰句踐城。明州報兩掾，相憶二毛生。"]'),
('yuding-8','送宋秀才','綦毋潛','唐','御定全唐诗','yuding','','[]','冠古積榮盛，當時數戟門。舊交丞相子，繼世五侯孫。',48,'御定全唐詩/json/135.json','["冠古積榮盛，當時數戟門。舊交丞相子，繼世五侯孫。", "長劍倚天外，短書盈萬言。秋風一送別，江上黯消魂。"]'),
('yuding-9','送平判官入秦','綦毋潛','唐','御定全唐诗','yuding','','[]','謫遠自安命，三年已忘歸。同聲願執手，驛騎到門扉。',48,'御定全唐詩/json/135.json','["謫遠自安命，三年已忘歸。同聲願執手，驛騎到門扉。", "雲是帝鄉去，軍書謁紫微。曾為金馬客，向日淚沾衣。"]'),
('yuding-10','送鄭務拜伯父','綦毋潛','唐','御定全唐诗','yuding','','[]','名公作逐臣，驅馬拂行塵。舊國問鄖子，勞歌過郢人。',48,'御定全唐詩/json/135.json','["名公作逐臣，驅馬拂行塵。舊國問鄖子，勞歌過郢人。", "一川花送客，二月柳宜春。奉料竹林興，寬懷此別晨。"]'),
('yuding-11','題招隱寺絢公房','綦毋潛','唐','御定全唐诗','yuding','','[]','開士度人久，空岩花霧深。徒知燕坐處，不見有為心。',48,'御定全唐詩/json/135.json','["開士度人久，空岩花霧深。徒知燕坐處，不見有為心。", "蘭若門對壑，田家路隔林。還言證法性，歸去比黃金。"]'),
('yuding-12','宿太平觀','綦毋潛','唐','御定全唐诗','yuding','','[]','夕到玉京寢，窅冥雲漢低。魂交仙室蝶，曙聽羽人雞。',48,'御定全唐詩/json/135.json','["夕到玉京寢，窅冥雲漢低。魂交仙室蝶，曙聽羽人雞。", "滴瀝花上露，清泠松下溪。明當訪真隱，揮手入無倪。"]'),
('yuding-13','題靈隱寺山頂禪院','綦毋潛','唐','御定全唐诗','yuding','','[]','招提此山頂，下界不相聞。塔影掛清漢，鐘聲和白雲。',48,'御定全唐詩/json/135.json','["招提此山頂，下界不相聞。塔影掛清漢，鐘聲和白雲。", "觀空靜室掩，行道眾香焚。且駐西來駕，人天日未曛。"]'),
('yuding-14','若耶溪逢孔九','綦毋潛','唐','御定全唐诗','yuding','','[]','相逢此溪曲，勝托在煙霞。潭影竹間動，岩陰簷外斜。',48,'御定全唐詩/json/135.json','["相逢此溪曲，勝托在煙霞。潭影竹間動，岩陰簷外斜。", "人言上皇代，犬吠武陵家。借問淹留日，春風滿若耶。"]'),
('yuding-15','宿龍興寺','綦毋潛','唐','御定全唐诗','yuding','','[]','香刹夜忘歸，松青古殿扉。燈明方丈室，珠系比丘衣。',48,'御定全唐詩/json/135.json','["香刹夜忘歸，松青古殿扉。燈明方丈室，珠系比丘衣。", "白日傳心靜，青蓮喻法微。天花落不盡，處處鳥銜飛。"]'),
('yuding-16','題沈東美員外山池','綦毋潛','唐','御定全唐诗','yuding','','[]','仙郎偏好道，鑿沼象瀛洲。魚樂隨情性，船行任去留。',48,'御定全唐詩/json/135.json','["仙郎偏好道，鑿沼象瀛洲。魚樂隨情性，船行任去留。", "秦人辨雞犬，堯日識巢由。歸客衡門外，仍憐返景幽。"]'),
('yuding-17','茅山洞口','綦毋潛','唐','御定全唐诗','yuding','','[]','華陽仙洞口，半嶺拂雲看。窈窕穿苔壁，差池對石壇。',48,'御定全唐詩/json/135.json','["華陽仙洞口，半嶺拂雲看。窈窕穿苔壁，差池對石壇。", "方隨地脈轉，稍覺水晶寒。未果變金骨，歸來茲路難。"]'),
('yuding-18','過方尊師院','綦毋潛','唐','御定全唐诗','yuding','','[]','羽客北山尋，草堂松徑深。養神宗示法，得道不知心。',48,'御定全唐詩/json/135.json','["羽客北山尋，草堂松徑深。養神宗示法，得道不知心。", "洞戶逢雙履，寥天有一琴。更登玄圃上，仍種杏成林。"]'),
('yuding-19','經陸補闕隱居','綦毋潛','唐','御定全唐诗','yuding','','[]','不敢要君征亦起，致君全得似唐虞。讜言昨歎離天聽，',40,'御定全唐詩/json/135.json','["不敢要君征亦起，致君全得似唐虞。讜言昨歎離天聽，", "學書弟子何人在，點檢猶存諫草無。"]'),
('yuding-20','登天竺寺','綦毋潛','唐','御定全唐诗','yuding','','[]','郡有化城最，西窮疊嶂深。松門當澗口，石路在峰心。',72,'御定全唐詩/json/135.json','["郡有化城最，西窮疊嶂深。松門當澗口，石路在峰心。", "幽見夕陽霽，高逢暮雨陰。佛身瞻紺發，寶地踐黃金。", "雲向竹溪盡，月從花洞臨。因物成真悟，遺世在茲岑。"]'),
('yuding-21','滿公房','綦毋潛','唐','御定全唐诗','yuding','','[]','世界蓮花藏，行人香火緣。燈王照不盡，中夜寂相傳。',24,'御定全唐詩/json/135.json','["世界蓮花藏，行人香火緣。燈王照不盡，中夜寂相傳。"]'),
('yuding-22','過融上人蘭若','綦毋潛','唐','御定全唐诗','yuding','','[]','山頭禪室掛僧衣，窗外無人溪鳥飛。',32,'御定全唐詩/json/135.json','["山頭禪室掛僧衣，窗外無人溪鳥飛。", "黃昏半在下山路，卻聽鐘聲連翠微。"]'),
('yuding-23','早發上東門','綦毋潛','唐','御定全唐诗','yuding','','[]','十五能行西入秦，三十無家作路人。',32,'御定全唐詩/json/135.json','["十五能行西入秦，三十無家作路人。", "時命不將明主合，布衣空染洛陽塵。"]'),
('yuding-24','祇園寺','綦毋潛','唐','御定全唐诗','yuding','','[]','寶坊求往跡，神理駐沿洄。雁塔酬前願，王身更後來。',48,'御定全唐詩/json/135.json','["寶坊求往跡，神理駐沿洄。雁塔酬前願，王身更後來。", "加持將暝合，朗悟豁然開。兩世分明見，餘生複幾哉。"]'),
('yuding-25','送集賢學士伊闕史少府放歸江東覲省','綦毋潛','唐','御定全唐诗','yuding','','[]','墨客鐘張侶，材高吳越珍。千門來謁帝，駟馬去榮親。',48,'御定全唐詩/json/135.json','["墨客鐘張侶，材高吳越珍。千門來謁帝，駟馬去榮親。", "吏邑沿清洛，鄉山指白蘋。歸期應不遠，當及未央春。"]'),
('yuding-0','述韋昭應畫犀牛','儲光羲','唐','御定全唐诗','yuding','','[]','遐方獻文犀，萬里隨南金。大邦柔遠人，以之居山林。',120,'御定全唐詩/json/136.json','["遐方獻文犀，萬里隨南金。大邦柔遠人，以之居山林。", "食棘無秋冬，絕流無淺深。雙角前嶄嶄，三蹄下駸駸。", "朝賢壯其容，未能辨其音。有我衰鳥郎，新邑長鳴琴。", "陛閣飛嘉聲，丘甸盈仁心。閒居命國工，作繪北堂陰。", "眈眈若有神，庶比來儀禽。昔有舞天庭，為君奏龍吟。"]'),
('yuding-1','獻王威儀','儲光羲','唐','御定全唐诗','yuding','','[]','入與真主言，有騎天馬來。但有華清宮，不用神明台。',36,'御定全唐詩/json/136.json','["入與真主言，有騎天馬來。但有華清宮，不用神明台。", "肅肅長自閑，門靜無人開。"]'),
('yuding-2','野田黃雀行','儲光羲','唐','御定全唐诗','yuding','','[]','嘖嘖野田雀，不知軀體微。閑穿深蒿裏，爭食複爭飛。',84,'御定全唐詩/json/136.json','["嘖嘖野田雀，不知軀體微。閑穿深蒿裏，爭食複爭飛。", "窮老一頹舍，棗多桑樹稀。無棗猶可食，無桑何以衣。", "蕭條空倉暮，相引時來歸。斜路豈不捷，渚田豈不肥。", "水長路且壞，惻惻與心違。"]'),
('yuding-3','樵父詞','儲光羲','唐','御定全唐诗','yuding','','[]','山北饒朽木，山南多枯枝。枯枝作采薪，爨室私自知。',84,'御定全唐詩/json/136.json','["山北饒朽木，山南多枯枝。枯枝作采薪，爨室私自知。", "詰朝礪斧尋，視暮行歌歸。先雪隱薜荔，迎暄臥茅茨。", "清澗日濯足，喬木時曝衣。終年登險阻，不復憂安危。", "蕩漾與神游，莫知是與非。"]'),
('yuding-4','漁父詞','儲光羲','唐','御定全唐诗','yuding','','[]','澤魚好鳴水，溪魚好上流。漁梁不得意，下渚潛垂鉤。',84,'御定全唐詩/json/136.json','["澤魚好鳴水，溪魚好上流。漁梁不得意，下渚潛垂鉤。", "亂荇時礙楫，新蘆複隱舟。靜言念終始，安坐看沉浮。", "素發隨風揚，遠心與雲遊。逆浪還極浦，信潮下滄洲。", "非為徇形役，所樂在行休。"]'),
('yuding-5','牧童詞','儲光羲','唐','御定全唐诗','yuding','','[]','不言牧田遠，不道牧陂深。所念牛馴擾，不亂牧童心。',84,'御定全唐詩/json/136.json','["不言牧田遠，不道牧陂深。所念牛馴擾，不亂牧童心。", "圓笠覆我首，長蓑披我襟。方將憂暑雨，亦以懼寒陰。", "大牛隱層阪，小牛穿近林。同類相鼓舞，觸物成謳吟。", "取樂須臾間，寧問聲與音。"]'),
('yuding-6','採蓮詞','儲光羲','唐','御定全唐诗','yuding','','[]','淺渚荇花繁，深潭菱葉疏。獨往方自得，恥邀淇上姝。',72,'御定全唐詩/json/136.json','["淺渚荇花繁，深潭菱葉疏。獨往方自得，恥邀淇上姝。", "廣江無術阡，大澤絕方隅。浪中海童語，流下鮫人居。", "春雁時隱舟，新萍複滿湖。采采乘日暮，不思賢與愚。"]'),
('yuding-7','采菱詞','儲光羲','唐','御定全唐诗','yuding','','[]','濁水菱葉肥，清水菱葉鮮。義不游濁水，志士多苦言。',96,'御定全唐詩/json/136.json','["濁水菱葉肥，清水菱葉鮮。義不游濁水，志士多苦言。", "潮沒具區藪，潦深雲夢田。朝隨北風去，暮逐南風旋。", "浦口多漁家，相與邀我船。飯稻以終日，羹蓴將永年。", "方冬水物窮，又欲休山樊。盡室相隨從，所貴無憂患。"]'),
('yuding-8','射雉詞','儲光羲','唐','御定全唐诗','yuding','','[]','曝暄理新翳，迎春射鳴雉。原田遙一色，皋陸曠千里。',97,'御定全唐詩/json/136.json','["曝暄理新翳，迎春射鳴雉。原田遙一色，皋陸曠千里。", "遙聞咿喔聲，時見雙飛起。冪zx疏蒿下，毰毸深叢裏。", "顧敵已忘生，爭雄方決死。仁心貴勇義，豈能複傷此。", "超遙下故墟，迢遞回高畤。大夫昔何苦，取笑歡妻子。"]'),
('yuding-9','猛虎詞','儲光羲','唐','御定全唐诗','yuding','','[]','寒亦不憂雪，饑亦不食人。人肉豈不甘，所惡傷明神。',96,'御定全唐詩/json/136.json','["寒亦不憂雪，饑亦不食人。人肉豈不甘，所惡傷明神。", "太室為我宅，孟門為我鄰。百獸為我膳，五龍為我賓。", "蒙馬一何威，浮江一以仁。彩章耀朝日，爪牙雄武臣。", "高雲逐氣浮，厚地隨聲震。君能賈餘勇，日夕長相親。"]'),
('yuding-10','渭橋北亭作','儲光羲','唐','御定全唐诗','yuding','','[]','停車渭陽暮，望望入秦京。不見鵷鸞道，如聞歌吹聲。',48,'御定全唐詩/json/136.json','["停車渭陽暮，望望入秦京。不見鵷鸞道，如聞歌吹聲。", "鄉魂涉江水，客路指蒲城。獨有故樓月，今來亭上明。"]'),
('yuding-11','述華清宮五首','儲光羲','唐','御定全唐诗','yuding','','[]','上在蓬萊宮，莫若居華清。朝朝禮玄閣，日日聞體輕。',180,'御定全唐詩/json/136.json','["上在蓬萊宮，莫若居華清。朝朝禮玄閣，日日聞體輕。", "大聖不私己，精禋為群氓。", "上出蓬萊時，六龍儼齊首。長道舒羽儀，彤雲映前後。", "天聲殷宇宙，真氣到林藪。", "昔在軒轅朝，五城十二樓。今我神泉宮，獨在驪山陬。", "群方趨順動，百辟隨天遊。", "正月開陽和，通門緝元化。穆穆睟容歸，豈為明燈夜。", "高山大風起，肅肅隨龍駕。", "上林神君宮，此地即明庭。山開鴻蒙色，天轉招搖星。", "三雪報大有，孰為非我靈。"]'),
('yuding-12','雜詠五首：石子松','儲光羲','唐','御定全唐诗','yuding','','[]','磐石青岩下，松生磐石中。冬春無異色，朝暮有清風。',36,'御定全唐詩/json/136.json','["磐石青岩下，松生磐石中。冬春無異色，朝暮有清風。", "五鬣何人采，西山舊兩童。"]'),
('yuding-13','雜詠五首：架簷藤','儲光羲','唐','御定全唐诗','yuding','','[]','得從軒墀下，殊勝松柏林。生枝逐架遠，吐葉向門深。',36,'御定全唐詩/json/136.json','["得從軒墀下，殊勝松柏林。生枝逐架遠，吐葉向門深。", "何許答君子，簷間朝暝陰。"]'),
('yuding-14','雜詠五首：池邊鶴','儲光羲','唐','御定全唐诗','yuding','','[]','舞鶴傍池邊，水清毛羽鮮。立如依岸雪，飛似向池泉。',36,'御定全唐詩/json/136.json','["舞鶴傍池邊，水清毛羽鮮。立如依岸雪，飛似向池泉。", "江海雖言曠，無如君子前。"]'),
('yuding-15','雜詠五首：釣魚灣','儲光羲','唐','御定全唐诗','yuding','','[]','垂釣綠灣春，春深杏花亂。潭清疑水淺，荷動知魚散。',36,'御定全唐詩/json/136.json','["垂釣綠灣春，春深杏花亂。潭清疑水淺，荷動知魚散。", "日暮待情人，維舟綠楊岸。"]'),
('yuding-16','雜詠五首：幽人居','儲光羲','唐','御定全唐诗','yuding','','[]','幽人下山徑，去去夾青林。滑處莓苔濕，暗中蘿薜深。',36,'御定全唐詩/json/136.json','["幽人下山徑，去去夾青林。滑處莓苔濕，暗中蘿薜深。", "春朝煙雨散，猶帶浮雲陰。"]'),
('yuding-17','題太玄觀','儲光羲','唐','御定全唐诗','yuding','','[]','門外車馬喧，門裏宮殿清。行即翳若木，坐即吹玉笙。',36,'御定全唐詩/json/136.json','["門外車馬喧，門裏宮殿清。行即翳若木，坐即吹玉笙。", "所喧既非我，真道其冥冥。"]'),
('yuding-18','至嵩陽觀，觀即天皇故宅','儲光羲','唐','御定全唐诗','yuding','','[]','真人上清室，乃在中峰前。花霧生玉井，霓裳畫列仙。',72,'御定全唐詩/json/136.json','["真人上清室，乃在中峰前。花霧生玉井，霓裳畫列仙。", "念茲宮故宇，多此地新泉。松柏有清陰，薜蘿亦自妍。", "一聞步虛子，又話逍遙篇。忽若在雲漢，風中意泠然。"]'),
('yuding-19','貽韋煉師','儲光羲','唐','御定全唐诗','yuding','','[]','精思莫知日，意靜如空虛。三鳥自來去，九光遙卷舒。',48,'御定全唐詩/json/136.json','["精思莫知日，意靜如空虛。三鳥自來去，九光遙卷舒。", "新池近天井，玉宇停雲車。餘亦苦山路，洗心祈道書。"]'),
('yuding-20','霽後貽馬十二巽','儲光羲','唐','御定全唐诗','yuding','','[]','高天風雨散，清氣在園林。況我夜初靜，當軒鳴綠琴。',48,'御定全唐詩/json/136.json','["高天風雨散，清氣在園林。況我夜初靜，當軒鳴綠琴。", "雲開北堂月，庭滿南山陰。不見長裾者，空歌遊子吟。"]'),
('yuding-21','題陸山人樓','儲光羲','唐','御定全唐诗','yuding','','[]','暮聲雜初雁，夜色涵早秋。獨見海中月，照君池上樓。',48,'御定全唐詩/json/136.json','["暮聲雜初雁，夜色涵早秋。獨見海中月，照君池上樓。", "山雲拂高棟，天漢入雲流。不惜朝光滿，其如千里遊。"]'),
('yuding-22','獻八舅東歸','儲光羲','唐','御定全唐诗','yuding','','[]','高位莫能舍，舍之世所賢。雲車游日華，豈比龍樓前。',120,'御定全唐詩/json/136.json','["高位莫能舍，舍之世所賢。雲車游日華，豈比龍樓前。", "寢疾乃就枕，情感唯靈仙。帝鴻思道宗，臣彭亦長年。", "天書加羽服，又許歸東川。鏡水涵太清，禹山朝上玄。", "誠亡真混沌，玉立方嬋娟。素業作仙居，子孫當自傳。", "門多松柏樹，篋有逍遙篇。獨往不可群，滄海成桑田。"]'),
('yuding-23','泛茅山東溪','儲光羲','唐','御定全唐诗','yuding','','[]','清晨登仙峰，峰遠行未極。江海霽初景，草木含新色。',60,'御定全唐詩/json/136.json','["清晨登仙峰，峰遠行未極。江海霽初景，草木含新色。", "而我任天和，此時聊動息。望鄉白雲裏，發棹清溪側。", "松柏生深山，無心自貞直。"]'),
('yuding-24','吃茗粥作','儲光羲','唐','御定全唐诗','yuding','','[]','當晝暑氣盛，鳥雀靜不飛。念君高梧陰，複解山中衣。',60,'御定全唐詩/json/136.json','["當晝暑氣盛，鳥雀靜不飛。念君高梧陰，複解山中衣。", "數片遠雲度，曾不蔽炎暉。淹留膳茶粥，共我飯蕨薇。", "敝廬既不遠，日暮徐徐歸。"]'),
('yuding-25','游茅山五首','儲光羲','唐','御定全唐诗','yuding','','[]','十年別鄉縣，西雲入皇州。此意在觀國，不言空遠遊。',360,'御定全唐詩/json/136.json','["十年別鄉縣，西雲入皇州。此意在觀國，不言空遠遊。", "九衢平若水，利往無輕舟。北洛反初路，東江還故丘。", "春山多秀木，碧澗盡清流。不見子桑扈，當從方外求。", "世業傳儒行，行成非不榮。其如懷獨善，況以聞長生。", "家近華陽洞，早年深此情。巾車雲路入，理棹瑤溪行。", "天地朝光滿，江山春色明。王庭有軒冕，此日方知輕。", "平生非作者，望古懷清芬。心以道為際，行將時不群。", "茲山在人境，靈貺久傳聞。遠勢一峰出，近形千嶂分。", "冬春有茂草，朝暮多鮮雲。此去亦何極，但言西日曛。", "昔賢居柱下，今我去人間。良以直心曠，兼之外視閑。", "垂綸非釣國，好學異希顏。落日登高嶼，悠然望遠山。", "溪流碧水去，雲帶清陰還。想見中林士，岩扉長不關。", "名嶽征仙事，清都訪道書。山門入松柏，天路涵空虛。", "南極見朝采，西潭聞夜漁。遠心尚雲宿，浪跡出林居。", "為己存實際，忘形同化初。此行良已矣，不樂複何如。"]'),
('yuding-26','述降聖觀','儲光羲','唐','御定全唐诗','yuding','','[]','一山盡天苑，一峰開道宮。道花飛羽衛，天鳥遊雲空。',72,'御定全唐詩/json/136.json','["一山盡天苑，一峰開道宮。道花飛羽衛，天鳥遊雲空。", "玉殿俯玄水，春旗搖素風。夾門小松柏，覆井新梧桐。", "自昔大仙下，乃知元化功。神皇作桂館，此意與天通。"]'),
('yuding-27','題眄上人禪居','儲光羲','唐','御定全唐诗','yuding','','[]','真王清淨子，燕居複行心。結宇鄰居邑，寤言非遠尋。',72,'御定全唐詩/json/136.json','["真王清淨子，燕居複行心。結宇鄰居邑，寤言非遠尋。", "丹青丈室滿，草樹一庭深。秀色玄冬發，交枝白日陰。", "江流映朱戶，山鳥鳴香林。獨住已寂寂，安知浮與沉。"]'),
('yuding-28','過新豐道中','儲光羲','唐','御定全唐诗','yuding','','[]','西下長樂阪，東入新豐道。雨多車馬稀，道上生秋草。',72,'御定全唐詩/json/136.json','["西下長樂阪，東入新豐道。雨多車馬稀，道上生秋草。", "太陰蔽皋陸，莫知晚與早。雷雨杳冥冥，川穀漫浩浩。", "詔書植嘉木，眾言桃李好。自愧無此容，歸從漢陰老。"]'),
('yuding-29','夜到洛口入黃河','儲光羲','唐','御定全唐诗','yuding','','[]','河洲多青草，朝暮增客愁。客愁惜朝暮，枉渚暫停舟。',72,'御定全唐詩/json/136.json','["河洲多青草，朝暮增客愁。客愁惜朝暮，枉渚暫停舟。", "中宵大川靜，解纜逐歸流。浦漵既清曠，沿洄非阻修。", "登艫望落月，擊汰悲新秋。倘遇乘槎客，永言星漢遊。"]'),
('yuding-30','使過彈箏峽作','儲光羲','唐','御定全唐诗','yuding','','[]','鳥雀知天雪，群飛複群鳴。原田無遺粟，日暮滿空城。',84,'御定全唐詩/json/136.json','["鳥雀知天雪，群飛複群鳴。原田無遺粟，日暮滿空城。", "達士憂世務，鄙夫念王程。晨過彈箏峽，馬足淩兢行。", "雙壁隱靈曜，莫能知晦明。皚皚堅冰白，漫漫陰雲平。", "始信古人言，苦節不可貞。"]'),
('yuding-31','泊舟貽潘少府','儲光羲','唐','御定全唐诗','yuding','','[]','行子苦風潮，維舟未能發。宵分卷前幔，臥視清秋月。',84,'御定全唐詩/json/136.json','["行子苦風潮，維舟未能發。宵分卷前幔，臥視清秋月。", "四澤蒹葭深，中洲煙火絕。蒼蒼水霧起，落落疏星沒。", "所遇盡漁商，與言多楚越。其如念極浦，又以思明哲。", "常若千里餘，況之異鄉別。"]'),
('yuding-32','仲夏入園中東陂','儲光羲','唐','御定全唐诗','yuding','','[]','方塘深且廣，伊昔俯吾廬。環岸垂綠柳，盈澤發紅蕖。',84,'御定全唐詩/json/136.json','["方塘深且廣，伊昔俯吾廬。環岸垂綠柳，盈澤發紅蕖。", "上延北原秀，下屬幽人居。暑雨若混沌，清明如空虛。", "此鄉多隱逸，水陸見樵漁。廢賞亦何貴，為歡良易攄。", "且言重觀國，當此賦歸歟。"]'),
('yuding-33','效古二首','儲光羲','唐','御定全唐诗','yuding','','[]','晨登涼風台，暮走邯鄲道。曜靈何赫烈，四野無青草。',168,'御定全唐詩/json/136.json','["晨登涼風台，暮走邯鄲道。曜靈何赫烈，四野無青草。", "大軍北集燕，天子西居鎬。婦人役州縣，丁男事征討。", "老幼相別離，哭泣無昏早。稼穡既殄絕，川澤複枯槁。", "曠哉遠此憂，冥冥商山皓。", "東風吹大河，河水如倒流。河洲塵沙起，有若黃雲浮。", "赬霞燒廣澤，洪曜赫高丘。野老泣相語，無地可蔭休。", "翰林有客卿，獨負蒼生憂。中夜起躑躅，思欲獻厥謀。", "君門峻且深，踠足空夷猶。"]'),
('yuding-34','雜詩二首','儲光羲','唐','御定全唐诗','yuding','','[]','混沌本無象，末路多是非。達士志寥廓，所在能忘機。',168,'御定全唐詩/json/136.json','["混沌本無象，末路多是非。達士志寥廓，所在能忘機。", "耕鑿時未至，還山聊采薇。虎豹對我蹲，鸑鷟旁我飛。", "仙人空中來，謂我勿複歸。格澤為君駕，虹蜺為君衣。", "西遊昆侖墟，可與世人違。", "秋氣肅天地，太行高崔嵬。猿狖清夜吟，其聲一何哀。", "寂寞掩圭蓽，夢寐游蓬萊。琪樹遠亭亭，玉堂雲中開。", "洪崖吹簫管，玉女飄颻來。雨師既先後，道路無纖埃。", "鄙哉楚襄王，獨好陽雲台。"]'),
('yuding-35','陸著作挽歌','儲光羲','唐','御定全唐诗','yuding','','[]','世業江湖側，郊原休沐處。獨言五日歸，未道千秋去。',240,'御定全唐詩/json/136.json','["世業江湖側，郊原休沐處。獨言五日歸，未道千秋去。", "鄉亭春水綠，昌閣寒光暮。昔為晝錦游，今成逝川路。", "歸路秦城下，寒雲慘平田。故園滄海邊，綠柳覆平川。", "送客異他日，還舟殊昔年。華亭有明日，長向隴頭懸。", "劍水千人石，荊江萬里流。英英有君子，才德滿中州。", "明道俟良佐，惟賢初薄遊。生涯一朝盡，寂寞夜台幽。", "金堂策令名，仙掖居清位。鳴玉朝雙闕，垂纓遊兩地。", "朝夕既論思，春秋仍書事。何言魯聲伯，忽下瓊珠淚。", "令德棄人世，明朝降寵章。起居存有位，著作沒為郎。", "寒水落南浦，月華虛北堂。松門一長想，仿佛見清揚。"]'),
('yuding-36','山居貽裴十二迪','儲光羲','唐','御定全唐诗','yuding','','[]','落葉滿山砌，蒼煙埋竹扉。遠懷青冥士，書劍常相依。',72,'御定全唐詩/json/136.json','["落葉滿山砌，蒼煙埋竹扉。遠懷青冥士，書劍常相依。", "霜臥眇茲地，琴言紛已違。衡陽今萬里，南雁將何歸。", "出徑惜松引，入舟憐釣磯。西林有明月，夜久空微微。"]'),
('yuding-37','秦中歲晏馬舍人宅宴集','儲光羲','唐','御定全唐诗','yuding','','[]','冬暮久無樂，西行至長安。故人處東第，清夜多新歡。',48,'御定全唐詩/json/136.json','["冬暮久無樂，西行至長安。故人處東第，清夜多新歡。", "廣庭竹陰靜，華池月色寒。知音盡詞客，方見交情難。"]'),
('yuding-38','薦玄德公廟','儲光羲','唐','御定全唐诗','yuding','','[]','神道本無已，成化亦自然。君居寥天上，德在玉華泉。',72,'御定全唐詩/json/136.json','["神道本無已，成化亦自然。君居寥天上，德在玉華泉。", "真游踐王豫，永日遲雲仙。表微在營道，明祀將祈年。", "靈山俯新邑，松上生彩煙。豈知穆天子，遠去瑤池邊。"]'),
('yuding-39','上長史王公責躬','儲光羲','唐','御定全唐诗','yuding','','[]','覆舟無伯夷，覆車無仲尼。自咎失明義，甯由貝錦詩。',120,'御定全唐詩/json/136.json','["覆舟無伯夷，覆車無仲尼。自咎失明義，甯由貝錦詩。", "松柏日已堅，桃李日以滋。顧己獨暗昧，所居成蒺藜。", "大賢薦時文，醜婦用蛾眉。惕惕愧不已，豈敢論其私。", "方朔既有言，子建亦有詩。惻隱及先世，析薪成自悲。", "靈鳥酬德輝，黃雀報仁慈。若公庶伏罪，此事安能遲。"]'),
('yuding-40','至嶽寺即大通大照禪塔上溫上人','儲光羲','唐','御定全唐诗','yuding','','[]','秋山下映宮，宮色宜朝陽。迢遞在半嶺，參差非一行。',96,'御定全唐詩/json/136.json','["秋山下映宮，宮色宜朝陽。迢遞在半嶺，參差非一行。", "燕息雲滿門，出遊花隱房。二尊此成道，禪宇遙相望。", "鳳鐸天中鳴，岩梯松下長。山墟響信鼓，蘅薄生蕙香。", "起滅一以雪，往來亦誠亡。悲哉門弟子，要自知心長。"]'),
('yuding-41','終南幽居獻蘇侍郎三首時拜太祝未上','儲光羲','唐','御定全唐诗','yuding','','[]','暮春天氣和，登嶺望層城。朝日懸清景，巍峨宮殿明。',252,'御定全唐詩/json/136.json','["暮春天氣和，登嶺望層城。朝日懸清景，巍峨宮殿明。", "聖君常臨朝，達士複懸衡。道近無艮足，歸來臥山楹。", "靈階曝仙書，深室煉金英。春岩松柏秀，晨路鶤雞鳴。", "羽化既有言，無然悲不成。", "中歲尚微道，始知將穀神。抗策還南山，水木自相親。", "深林開一道，青嶂成四鄰。平明去采薇，日入行刈薪。", "雲歸萬壑暗，雪罷千崖春。始看玄鳥來，已見瑤華新。", "寄言搴芳者，無乃後時人。", "蔔築青岩裏，雲蘿四垂陰。虛室若無人，喬木自成林。", "時有清風至，側聞樵采音。鳳凰鳴南岡，望望隔層岑。", "既言山路遠，複道溪流深。偓佺空中游，虯龍水間吟。", "何當見輕翼，為我達遠心。"]'),
('yuding-42','題應聖觀','儲光羲','唐','御定全唐诗','yuding','','[]','空中望小山，山下見餘雪。皎皎河漢女，在茲養真骨。',96,'御定全唐詩/json/136.json','["空中望小山，山下見餘雪。皎皎河漢女，在茲養真骨。", "登門駭天書，啟鑰問仙訣。池光搖水霧，燈色連松月。", "合磚起花台，折草成玉節。天雞弄白羽，王母垂玄發。", "北有上年宮，一路在雲霓。上心方向道，時複朝金闕。"]'),
('yuding-43','至閒居精舍呈正上人','儲光羲','唐','御定全唐诗','yuding','','[]','太室三招提，其趣皆不同。不同非一趣，況是天游宮。',96,'御定全唐詩/json/136.json','["太室三招提，其趣皆不同。不同非一趣，況是天游宮。", "雙嶺前夾門，閣道複橫空。寶坊若花積，宛轉不可窮。", "流泉自成池，清松信饒風。秋晏景氣迥，皛明丹素功。", "將近隱者鄰，遠與西山通。大師假惠照，念以息微躬。"]'),
('yuding-44','酬綦毋校書夢耶溪見贈之作','儲光羲','唐','御定全唐诗','yuding','','[]','校文在仙掖，每有滄洲心。況以北窗下，夢游清溪陰。',96,'御定全唐詩/json/136.json','["校文在仙掖，每有滄洲心。況以北窗下，夢游清溪陰。", "春看湖水漫，夜入回塘深。往往纜垂葛，出舟望前林。", "山人松下飯，釣客蘆中吟。小隱何足貴，長年固可尋。", "還車首東道，惠言若黃金。以我采薇意，傳之天姥岑。"]'),
('yuding-0','田家即事','儲光羲','唐','御定全唐诗','yuding','','[]','蒲葉日已長，杏花日已滋。老農要看此，貴不違天時。',96,'御定全唐詩/json/137.json','["蒲葉日已長，杏花日已滋。老農要看此，貴不違天時。", "迎晨起飯牛，雙駕耕東菑。蚯蚓土中出，田烏隨我飛。", "群合亂啄噪，嗷嗷如道饑。我心多惻隱，顧此兩傷悲。", "撥食與田烏，日暮空筐歸。親戚更相誚，我心終不移。"]'),
('yuding-1','同王十三維偶然作十首','儲光羲','唐','御定全唐诗','yuding','','[]','仲夏日中時，草木看欲燋。田家惜工力，把鋤來東皋。',540,'御定全唐詩/json/137.json','["仲夏日中時，草木看欲燋。田家惜工力，把鋤來東皋。", "顧望浮雲陰，往往誤傷苗。歸來悲困極，兄嫂共相譊。", "無錢可沽酒，何以解劬勞。夜深星漢明，庭宇虛寥寥。", "高柳三五株，可以獨逍遙。", "北山種松柏，南山種蒺藜。出入雖同趣，所向各有宜。", "孔丘貴仁義，老氏好無為。我心若虛空，此道將安施。", "暫過伊闕間，晼晚三伏時。高閣入雲中，芙蓉滿清池。", "要自非我室，還望南山陲。", "野老本貧賤，冒暑鋤瓜田。一畦未及終，樹下高枕眠。", "荷蓧者誰子，皤皤來息肩。不復問鄉墟，相見但依然。", "腹中無一物，高話羲皇年。落日臨層隅，逍遙望晴川。", "使婦提蠶筐，呼兒榜漁船。悠悠泛綠水，去摘浦中蓮。", "蓮花豔且美，使我不能還。", "浮雲在虛空，隨風複卷舒。我心方處順，動作何憂虞。", "但言嬰世網，不復得閒居。迢遞別東國，超遙來西都。", "見人乃恭敬，曾不問賢愚。雖若不能言，中心亦難誣。", "故鄉滿親戚，道遠情日疏。偶欲陳此意，複無南飛鳧。", "草木花葉生，相與命為春。當非草木意，信是故時人。", "靜念惻群物，何由知至真。狂歌問夫子，夫子莫能陳。", "鳳凰飛且鳴，容裔下天津。清淨無言語，茲焉庶可親。", "黃河流向東，弱水流向西。趨舍各有異，造化安能齊。", "妾本邯鄲女，生長在叢台。既聞容見寵，複想玄為妻。", "刻畫尚風流，幸會君招攜。逶迤歌舞座，婉孌芙蓉閨。", "日月方向除，恩愛忽焉暌。棄置誰複道，但悲生不諧。"]'),
('yuding-2','升天行貽盧六健','儲光羲','唐','御定全唐诗','yuding','','[]','真人居閬風，時奏清商音。聽者即王母，泠泠和瑟琴。',120,'御定全唐詩/json/137.json','["真人居閬風，時奏清商音。聽者即王母，泠泠和瑟琴。", "坐對三花枝，行隨五雲陰。天長昆侖小，日久蓬萊深。", "上由玉華宮，下視首陽岑。神州亦清淨，要自有浮沉。", "惻惻苦哉行，呱呱遊子吟。廬山逢若士，思欲化黃金。", "雨雪沒太山，誰能無歸心。逍遙在雲漢，可以來相尋。"]'),
('yuding-3','田家雜興八首','儲光羲','唐','御定全唐诗','yuding','','[]','春至鶬鶊鳴，薄言向田墅。不能自力作，黽勉娶鄰女。',516,'御定全唐詩/json/137.json','["春至鶬鶊鳴，薄言向田墅。不能自力作，黽勉娶鄰女。", "既念生子孫，方思廣田圃。閒時相顧笑，喜悅好禾黍。", "夜夜登嘯台，南望洞庭渚。百草被霜露，秋山響砧杵。", "卻羨故年時，中情無所取。", "眾人恥貧賤，相與尚膏腴。我情既浩蕩，所樂在畋漁。", "山澤時晦暝，歸家暫閒居。滿園植葵藿，繞屋樹桑榆。", "禽雀知我閑，翔集依我廬。所願在優遊，州縣莫相呼。", "日與南山老，兀然傾一壺。", "逍遙阡陌上，遠近無相識。落日照秋山，千岩同一色。", "網罟繞深莽，鷹鸇始輕翼。獵馬既如風，奔獸莫敢息。", "駐旗滄海上，犒士吳宮側。楚國有夫人，性情本貞直。", "鮮禽徒自致，終歲竟不食。", "田家趨壟畝，當晝掩虛關。鄰里無煙火，兒童共幽閒。", "桔槔懸空圃，雞犬滿桑間。時來農事隙，采藥遊名山。", "但言所采多，不念路險艱。人生如蜉蝣，一往不可攀。", "君看西王母，千載美容顏。", "平生養情性，不復計憂樂。去家行賣畚，留滯南陽郭。", "秋至黍苗黃，無人可刈獲。稚子朝未飯，把竿逐鳥雀。", "忽見梁將軍，乘車出宛洛。意氣軼道路，光輝滿墟落。", "安知負薪者，咥咥笑輕薄。", "楚山有高士，梁國有遺老。築室既相鄰，向田複同道。", "糗糒常共飯，兒孫每更抱。忘此耕耨勞，愧彼風雨好。", "蟪蛄鳴空澤，鶗鴂傷秋草。日夕寒風來，衣裳苦不早。", "梧桐蔭我門，薜荔網我屋。迢迢兩夫婦，朝出暮還宿。"]'),
('yuding-4','題辨覺精舍','儲光羲','唐','御定全唐诗','yuding','','[]','朝隨秋雲陰，乃至青松林。花閣空中遠，方池岩下深。',48,'御定全唐詩/json/137.json','["朝隨秋雲陰，乃至青松林。花閣空中遠，方池岩下深。", "竹風亂天語，溪響成龍吟。試問真君子，游山非世心。"]'),
('yuding-5','題慎言法師故房','儲光羲','唐','御定全唐诗','yuding','','[]','精廬不住子，自有無生鄉。過客知何道，裴回雁子堂。',48,'御定全唐詩/json/137.json','["精廬不住子，自有無生鄉。過客知何道，裴回雁子堂。", "浮雲歸故嶺，落月還西方。日夕虛空裏，時時聞異香。"]'),
('yuding-6','石甕寺','儲光羲','唐','御定全唐诗','yuding','','[]','遙山起真宇，西向盡花林。下見宮殿小，上看廊廡深。',48,'御定全唐詩/json/137.json','["遙山起真宇，西向盡花林。下見宮殿小，上看廊廡深。", "苑花落池水，天語聞松音。君子又知我，焚香期化心。"]'),
('yuding-7','題崔山人別業','儲光羲','唐','御定全唐诗','yuding','','[]','南陽隱居者，築室丹溪源。溪冷懼秋晏，室寒欣景暾。',72,'御定全唐詩/json/137.json','["南陽隱居者，築室丹溪源。溪冷懼秋晏，室寒欣景暾。", "山雞鳴菌閣，水霧入衡門。東嶺或舒嘯，北窗時討論。", "封君渭陽竹，逸士漢陰園。何必崆峒上，獨為堯所尊。"]'),
('yuding-8','行次田家澳梁作','儲光羲','唐','御定全唐诗','yuding','','[]','田家俯長道，邀我避炎氛。當暑日方晝，高天無片雲。',72,'御定全唐詩/json/137.json','["田家俯長道，邀我避炎氛。當暑日方晝，高天無片雲。", "桑間禾黍氣，柳下牛羊群。野雀棲空屋，晨昏不復聞。", "前登澳梁阪，極望溫泉分。逆旅方三舍，西山猶未曛。"]'),
('yuding-9','昭聖觀','儲光羲','唐','御定全唐诗','yuding','','[]','主家隱溪口，微路入花源。數日朝青閣，彩雲獨在門。',96,'御定全唐詩/json/137.json','["主家隱溪口，微路入花源。數日朝青閣，彩雲獨在門。", "雙樓夾一殿，玉女侍玄元。扶橑盡蟠木，步簷多畫翻。", "新松引天籟，小柏繞山樊。坐弄竹陰遠，行隨溪水喧。", "石池辨春色，林獸知人言。未逐鳳凰去，真宮在此原。"]'),
('yuding-10','題辛道士房','儲光羲','唐','御定全唐诗','yuding','','[]','全神不言命，所尚道家流。迨此遠南楚，遂令思北遊。',96,'御定全唐詩/json/137.json','["全神不言命，所尚道家流。迨此遠南楚，遂令思北遊。", "先生秀衡岳，玉立居玄丘。門帶江山靜，房隨瑤草幽。", "逍遙三花發，罔象五雲浮。自有太清紀，曾垂華髮憂。", "大年方橐鑰，小智即蜉蝣。七日赤龍至，莫令餘獨留。"]'),
('yuding-11','登秦嶺作，時陷賊歸國','儲光羲','唐','御定全唐诗','yuding','','[]','朝出猛獸林，躨跜登高峰。僮僕履雲霧，隨我行太空。',156,'御定全唐詩/json/137.json','["朝出猛獸林，躨跜登高峰。僮僕履雲霧，隨我行太空。", "羲和舒靈暉，倏忽西極通。回首望涇渭，隱隱如長虹。", "九逵合蒼蕪，五陵遙瞳蒙。鹿遊大明殿，霧濕華清宮。", "網羅蠛蠓時，顧齒熊羆鋒。失途走江漢，不能有其功。", "氣逐招搖星，魂隨閶闔風。惟言宇宙清，複使車書同。", "林木被繁霜，合遝連山紅。鵬鶚勵羽翼，俯視荊棘叢。", "誓將食鶬鴞，然後歸崆峒。"]'),
('yuding-12','晦日任橋池亭','儲光羲','唐','御定全唐诗','yuding','','[]','溫泉作天邑，直北開新洲。未有菰蒲生，即聞鳧雁遊。',72,'御定全唐詩/json/137.json','["溫泉作天邑，直北開新洲。未有菰蒲生，即聞鳧雁遊。", "六亭在高岸，數島居中流。晦日望清波，相與期泛遊。", "西道苦轉轂，北堤疲行舟。清泠水木陰，才可適我憂。"]'),
('yuding-13','望幸亭','儲光羲','唐','御定全唐诗','yuding','','[]','五年一巡狩，西幸過東畿。周國易居守，周人多怨思。',96,'御定全唐詩/json/137.json','["五年一巡狩，西幸過東畿。周國易居守，周人多怨思。", "君王敷惠政，程作貴從時。大廈非一木，沉沉臨九逵。", "慶雲宿飛棟，嘉樹羅青墀。疏屏宜朝享，方塘堪水嬉。", "雲中仰華蓋，桁下望春旗。天意知如此，星言歸洛師。"]'),
('yuding-14','哥舒大夫頌德','儲光羲','唐','御定全唐诗','yuding','','[]','天紀啟真命，君生臣亦生。乃知赤帝子，複有蒼龍精。',264,'御定全唐詩/json/137.json','["天紀啟真命，君生臣亦生。乃知赤帝子，複有蒼龍精。", "神武建皇極，文昌開將星。超超渭濱器，落落山西名。", "畫閫入受脤，鑿門出扞城。戎人昧正朔，我有軒轅兵。", "隴路起豐鎬，關雲隨旆旌。河湟訓兵甲，義勇方橫行。", "韓魏多銳士，蹶張在幕庭。大非四決軋，石堡高崢嶸。", "攻伐若振槁，孰雲非神明。嘉謀即天意，驟勝由師貞。", "枯草被西陸，烈風昏太清。戢戈旄頭落，牧馬昆侖平。", "賓從儼冠蓋，封山紀天聲。來朝芙蓉闕，鳴玉飄華纓。", "直道濟時憲，天邦遂輕刑。抗書報知己，松柏亦以榮。", "嘉命列上第，德輝照天京。在車持簡墨，粲粲皆詞英。", "顧我搶榆者，莫能翔青冥。游燕非騏驥，躑躅思長鳴。"]'),
('yuding-15','安宜園林獻高使君','儲光羲','唐','御定全唐诗','yuding','','[]','直道已三出，幸從江上回。新居茅茨迥，起見秋雲開。',72,'御定全唐詩/json/137.json','["直道已三出，幸從江上回。新居茅茨迥，起見秋雲開。", "十裏次舟楫，二橋交往來。楚言滿鄰里，雁叫喧池台。", "魚鱉樂仁政，浮沉亦至哉。小山宜大隱，要自望蓬萊。"]'),
('yuding-16','秋庭貽馬九','儲光羲','唐','御定全唐诗','yuding','','[]','伊昔好觀國，自鄉西入秦。往復萬餘裏，相逢皆眾人。',240,'御定全唐詩/json/137.json','["伊昔好觀國，自鄉西入秦。往復萬餘裏，相逢皆眾人。", "大君幸東嶽，世哲扈時巡。予亦從此去，閒居清洛濱。", "稍稍寒木直，彩彩陽華新。迭宕孔文舉，風流石季倫。", "妙年一相得，白首定相親。重此虛賓館，歡言冬及春。", "哲兄盛文史，出入馳高軌。令德本同人，深心重知己。", "絳衣朝聖主，紗帳延才子。伯淮與季江，清浚各孤峙。", "群芳趨泛愛，萬物通情理。而我信空虛，提攜過杞梓。", "夫君美聲德，直道期終始。孰謂忽離居，優遊鄭東裏。", "東裏近王城，山連路亦平。何言相去遠，閑言獨淒清。", "萬里鴻雁度，四鄰砧杵鳴。其如久離別，重以霜風驚。"]'),
('yuding-17','河中望鳥灘作貽呂四郎中','儲光羲','唐','御定全唐诗','yuding','','[]','河流有深曲，舟子莫能知。弭棹臨沙嶼，微吟西日馳。',72,'御定全唐詩/json/137.json','["河流有深曲，舟子莫能知。弭棹臨沙嶼，微吟西日馳。", "平明春色霽，兩岸好風吹。去去川途盡，悠悠親友離。", "漢宮成羽翼，伊水弄參差。為惜淮南子，如何攀桂枝。"]'),
('yuding-18','秦中初霽獻給事二首','儲光羲','唐','御定全唐诗','yuding','','[]','渭水收暮雨，處處多新澤。宮苑傍山明，雲林帶天碧。',144,'御定全唐詩/json/137.json','["渭水收暮雨，處處多新澤。宮苑傍山明，雲林帶天碧。", "君子聳高駕，英聲邈今昔。鏘佩出中台，彯纓入仙掖。", "夙心幸清鑒，晚志欣良覿。鳴盜非足征，願言同下客。", "南國久為思，西都嘗作賓。雲開天地色，日照山河春。", "善聽在知己，揚光唯達人。妙年弄柔翰，弱冠偶良晨。", "擢第文昌閣，還家滄海濱。寸心何所望，東掖有賢臣。"]'),
('yuding-19','晚次東亭獻鄭州宋使君文','儲光羲','唐','御定全唐诗','yuding','','[]','自初賓上國，乃到鄒人鄉。曾點與曾子，俱升闕裏堂。',360,'御定全唐詩/json/137.json','["自初賓上國，乃到鄒人鄉。曾點與曾子，俱升闕裏堂。", "武皇恢大略，逸翮思寥廓。三居清憲台，兩拜文昌閣。", "為道既貞信，處名猶謇諤。鐵柱勵風威，錦軸含光輝。", "夜聞持簡立，朝看伏奏歸。洞門清佩響，廣路玉珂飛。", "驤首入丹掖，摶空趨太微。絲綸逢聖主，出入飄華組。", "愔愔宿帝梧，侃侃居文府。海內語三獨，朝端謀六戶。", "善計在弘羊，清嚴歸仲舉。侍郎跨方朔，中丞蔑周處。", "天眷擇循良，惟賢降寵章。分符指聊攝，為政本農桑。", "籍籍歌五袴，祁祁頌千箱。隨車微雨灑，逐扇清風颺。", "既以遷列國，複茲鄰帝鄉。褰帷乃仍舊，坐嘯非更張。", "居敬物無擾，履端人自康。薄遊出京邑，引領東南望。", "林晚鳥雀噪，田秋稼穡黃。成皋天地險，廣武征戰場。", "道喪苦兵賦，時來開井疆。霏霏渠門色，晻晻制岩光。", "徒念京索近，獨悲溱洧長。大明潛照耀，淑慝自昭彰。", "昔歲幸西土，今茲歸洛陽。同焉知鄭伯，當輔我周王。"]'),
('yuding-20','秋次霸亭寄申大','儲光羲','唐','御定全唐诗','yuding','','[]','橘柚植寒陵，芙蓉蒂修阪。無言不得意，得意何由展。',132,'御定全唐詩/json/137.json','["橘柚植寒陵，芙蓉蒂修阪。無言不得意，得意何由展。", "況我行且徒，而君往猶蹇。既傷人事近，複言天道遠。", "薄暮入空亭，中夜不能飯。南聽鴻雁盡，西見招搖轉。", "千門漢王宮，百里周王苑。杲杲初景出，油油鮮雲卷。", "會朝幸歲正，校獵從新獮。念君久京國，雙涕如露泫。", "無人薦子雲，太息竟誰辨。"]'),
('yuding-21','舟中別武金壇','儲光羲','唐','御定全唐诗','yuding','','[]','曰予輕皎潔，坦率賓混元。忽乃異群萃，高歌信陵門。',120,'御定全唐詩/json/137.json','["曰予輕皎潔，坦率賓混元。忽乃異群萃，高歌信陵門。", "信陵好賓客，清夜開華軒。月光麗池閣，野氣浮林園。", "偶坐爛明星，歸志潛崩奔。漾舟清潭裏，慰我別離魂。", "落日下西山，左右慘無言。蕭條風雨散，窅靄江湖昏。", "秋荷尚幽鬱，暮鳥複翩翻。紙筆亦何為，寫我心中冤。"]'),
('yuding-22','鞏城東莊道中作','儲光羲','唐','御定全唐诗','yuding','','[]','北陵散寒鳥，西山照初日。婉孌晉陽京，踟躕野人室。',144,'御定全唐詩/json/137.json','["北陵散寒鳥，西山照初日。婉孌晉陽京，踟躕野人室。", "南軒草間去，後乘林中出。靄靄長路暖，遲遲狹路歸。", "蜉蝣時蔽月，枳棘複傷衣。城上東風起，河邊早雁飛。", "夏王紀冬令，殷人乃正月。涯口度新雲，山陰留故雪。", "幸逢耆耋話，餘待親鄰別。總轡出叢薄，歇鞍登峻隅。", "春源既蕩漭，伏戰亦睢盱。未獲遵平道，徒言信薄夫。"]'),
('yuding-23','赴馮翊作','儲光羲','唐','御定全唐诗','yuding','','[]','本自江海人，且無寥廓志。大明耀天宇，靄靄風雨被。',120,'御定全唐詩/json/137.json','["本自江海人，且無寥廓志。大明耀天宇，靄靄風雨被。", "迢遞別荊吳，飄颻涉沂泗。廣川俟舟楫，峻阪傷騏驥。", "蹭蹬失歸道，崎嶇從下位。西出太華陰，北走少梁地。", "蔥蘢墟落色，泱漭關河氣。恥從俠烈游，甘為刀筆吏。", "寶劍茱萸匣，豈忘知音貴。大道且泛然，沉浮未雲異。"]'),
('yuding-24','晚霽中園喜赦作','儲光羲','唐','御定全唐诗','yuding','','[]','五月黃梅時，陰氣蔽遠邇。濃雲連晦朔，菰菜生鄰里。',108,'御定全唐詩/json/137.json','["五月黃梅時，陰氣蔽遠邇。濃雲連晦朔，菰菜生鄰里。", "落日燒霞明，農夫知雨止。幾悲衽席濕，長歎垣牆毀。", "曭朗天宇開，家族躍以喜。渙汗發大號，坤元更資始。", "散衣出中園，小徑尚滑履。池光搖萬象，倏忽滅複起。", "嘉樹如我心，欣欣豈雲已。"]'),
('yuding-25','觀范陽遞俘','儲光羲','唐','御定全唐诗','yuding','','[]','北河旄星隕，鬼方獮林胡。群師舞弓矢，電發歸燕墟。',120,'御定全唐詩/json/137.json','["北河旄星隕，鬼方獮林胡。群師舞弓矢，電發歸燕墟。", "皇皇軒轅君，贊贊皋陶謨。方思壯軍實，遠近遞生俘。", "車馬踐大逵，合遝成深渠。牧人過橐駝，校正引騊駼。", "烈風朝送寒，雲雪靄天隅。草木同一色，誰能辨榮枯。", "四履封元戎，百金酬勇夫。大邦武功爵，固與炎皇殊。"]'),
('yuding-26','次天元十載華陰發兵，作時有郎官點發','儲光羲','唐','御定全唐诗','yuding','','[]','鬼方生獫狁，時寇盧龍營。帝念霍嫖姚，詔發咸林兵。',108,'御定全唐詩/json/137.json','["鬼方生獫狁，時寇盧龍營。帝念霍嫖姚，詔發咸林兵。", "天星下文閣，簡師臨我城。三陌觀勇夫，五餌謀長纓。", "雷野大車發，震雲靈鼓鳴。太華色莽蒼，清渭風交橫。", "胡馬悲雨雪，詩人歌旆旌。閼氏為女奴，單于作邊氓。", "神皇麒麟閣，大將不書名。"]'),
('yuding-27','送丘健至州敕放作時任下邽縣','儲光羲','唐','御定全唐诗','yuding','','[]','太史登觀台，天街耀旄頭。大君忽霆震，詔爵冠軍侯。',144,'御定全唐詩/json/137.json','["太史登觀台，天街耀旄頭。大君忽霆震，詔爵冠軍侯。", "南必梁孫源，西將圉昆丘。河隴征擊卒，虎符到我州。", "朝集咸林城，師言亂啁啾。殺氣變木德，凜凜如高秋。", "元戎啟神皇，廟堂發嘉謀。息兵業稼穡，歸馬複休牛。", "和風開陰雪，大耀中天流。歡聲殷河嶽，涵蕩非煙浮。", "邦牧新下車，德禮彼甿謳。乾坤日交泰，吾亦遂優遊。"]'),
('yuding-28','登商丘','儲光羲','唐','御定全唐诗','yuding','','[]','河水日夜流，客心多殷憂。維梢曆宋國，結纜登商丘。',72,'御定全唐詩/json/137.json','["河水日夜流，客心多殷憂。維梢曆宋國，結纜登商丘。", "漢皇封子弟，周室命諸侯。搖搖世祀怨，傷古複兼秋。", "鳴鴻念極浦，征旅慕前儔。太息梁王苑，時非牧馬遊。"]'),
('yuding-29','群鴉詠','儲光羲','唐','御定全唐诗','yuding','','[]','新宮驪山陰，龍袞時出豫。朝陽照羽儀，清吹肅逵路。',108,'御定全唐詩/json/137.json','["新宮驪山陰，龍袞時出豫。朝陽照羽儀，清吹肅逵路。", "群鴉隨天車，夜滿新豐樹。所思在腐餘，不復憂霜露。", "河低宮閣深，燈影鼓鐘曙。繽紛集寒枝，矯翼時相顧。", "塚宰收琳琅，侍臣盡鴛鷺。高舉摩太清，永絕矰繳懼。", "茲禽亦翱翔，不以微小故。"]'),
('yuding-30','尚書省受誓誡貽太廟裴丞','儲光羲','唐','御定全唐诗','yuding','','[]','皇家有恆憲，齋祭崇明祀。嚴車伊洛間，受誓文昌裏。',72,'御定全唐詩/json/137.json','["皇家有恆憲，齋祭崇明祀。嚴車伊洛間，受誓文昌裏。", "沉沉雲閣見，稍稍城烏起。曙色照衣冠，虛庭鳴劍履。", "裴回念私覿，悵望臨清汜。點翰欲何言，相思從此始。"]'),
('yuding-31','夏日尋藍田唐丞登高宴集','儲光羲','唐','御定全唐诗','yuding','','[]','東望春明門，駕言聊出遊。南行小徑盡，綠竹臨清流。',120,'御定全唐詩/json/137.json','["東望春明門，駕言聊出遊。南行小徑盡，綠竹臨清流。", "君出罷六安，居此澹忘憂。園林與城市，閭裏隨人幽。", "披顏辟衡闈，置酒登崇丘。山河臨咫尺，宇宙窮寸眸。", "是時春載陽，佳氣滿皇州。宮殿碧雲裏，鴛鴦初命儔。", "良辰方在茲，志士安得休。成名苟有地，何必東陵侯。"]'),
('yuding-32','田家即事答崔二東皋作四首','儲光羲','唐','御定全唐诗','yuding','','[]','玄鳥雙雙飛，杏林初發花。喣偷命僮僕，可以樹桑麻。',144,'御定全唐詩/json/137.json','["玄鳥雙雙飛，杏林初發花。喣偷命僮僕，可以樹桑麻。", "清旦理犁鋤，日入未還家。", "有客山中至，言傳故人訊。蕩漾敷遠情，飄颻吐清韻。", "猗歟春皋上，無乃成秋興。", "念別求須臾，忽至嚶鳴時。菜田燒故草，初樹養新枝。", "所寓非幽深，夢寐相追隨。", "依依親隴畝，寂寂無鄰里。不聞雞犬音，日見和風起。", "賴君遺掞藻，憂來散能弭。"]'),
('yuding-0','敬酬陳掾親家翁秋夜有贈','儲光羲','唐','御定全唐诗','yuding','','[]','大姬配胡公，位乃三恪賓。盛德百代祀，斯言良不泯。',312,'御定全唐詩/json/138.json','["大姬配胡公，位乃三恪賓。盛德百代祀，斯言良不泯。", "敬仲為齊卿，當國名益震。仲舉登宰輔，太丘榮縉紳。", "武皇受瑤圖，爵土封其新。繁祉既驟集，裔孫生賢臣。", "特達逾珪璋，節操方松筠。雲漢一矯翼，天池三振鱗。", "曳裾朝赤墀，酌醴侍紫宸。大君錫車馬，時複過平津。", "言則廣臺階，道亦資天均。清秋忽高興，震藻若有神。", "曜曜趨宮廷，洸洸邁徐陳。鎬京既賜第，門巷交朱輪。", "方將襲伊皋，永以崇夏殷。宗黨無遠近，敬恭依仁人。", "雪盡宇宙暄，雁歸滄海春。沉吟白華頌，帝闥降絲綸。", "驛騎及蕪城，相逢在郊鄄。別離曠南北，譴謫罹苦辛。", "晝游還荊吳，迷方客咸秦。惟賢慧重義，男女期嘉姻。", "梧桐生朝陽，鶗鴂鳴蕭晨。豈不畏時暮，坎壈無與鄰。", "中夜涼風來，顧我闕音塵。瓊瑤不遐棄，寤寐如日新。"]'),
('yuding-1','蘇十三瞻登玉泉寺峰入寺中見贈作','儲光羲','唐','御定全唐诗','yuding','','[]','慶門疊華組，盛列鐘英彥。貞信發天姿，文明葉邦選。',276,'御定全唐詩/json/138.json','["慶門疊華組，盛列鐘英彥。貞信發天姿，文明葉邦選。", "為情貴深遠，作德齊隱見。別業在春山，懷歸出芳甸。", "逖聽多時友，招邀及浮賤。朝沿霸水窮，暮矚藍田遍。", "百花照阡陌，萬木森鄉縣。澗淨綠蘿深，岩暄新鳥轉。", "依然造華薄，豁爾開靈院。淹留火禁辰，愉樂弦歌宴。", "肅肅列樽俎，鏘鏘引纓弁。天籟激微風，陽光轢奔箭。", "以茲小人腹，不勝君子饌。是日既低迷，中宵方眄眩。", "枕上思獨往，胸中理交戰。碧雲暗雨來，舊原芳色變。", "歡然自此絕，心賞何由見。鴻蒙已笑雲，列缺仍揮電。", "忽與去人遠，俄逢歸者便。想像玉泉宮，依稀明月殿。", "峰巒若登陟，水木以遊衍。息心幸自忘，點翰仍留眷。", "恨無荊文璧，以答丹青絢。"]'),
('yuding-2','酬李處士山中見贈','儲光羲','唐','御定全唐诗','yuding','','[]','厥初遊太學，相與極周旋。含采共朝暮，知言同古先。',192,'御定全唐詩/json/138.json','["厥初遊太學，相與極周旋。含采共朝暮，知言同古先。", "孟陽題劍閣，子雲獻甘泉。斯須曠千里，婉娩將十年。", "今來豔陽月，好鳥鳴翩翩。同聲既求友，不肖亦懷賢。", "引領遲芳信，果枉瑤華篇。成頌非其德，高文徒自妍。", "聲塵邈超越，比興起孤絕。始信郢中人，乃能歌白雪。", "跂予北堂夜，搖筆酬明哲。綠竹動清風，層軒靜華月。", "想像南山下，恬然謝朝列。猶恐鶗鴂鳴，坐看芳草歇。", "邀以青松色，同之白華潔。永願登龍門，相將持此節。"]'),
('yuding-3','同諸公秋日游昆明池思古','儲光羲','唐','御定全唐诗','yuding','','[]','僕人理車騎，西出金光逵。蒼蒼白帝郊，我將游靈池。',360,'御定全唐詩/json/138.json','["僕人理車騎，西出金光逵。蒼蒼白帝郊，我將游靈池。", "太陰連晦朔，雨與天根違。淒風披田原，橫汙益山陂。", "農畯盡顛沛，顧望稼穡悲。皇靈惻群甿，神政張天維。", "坤紀戮屏翳，元綱扶逶迤。回塘清滄流，大曜懸金暉。", "秋色浮渾沌，清光隨漣漪。豫章盡莓苔，柳杞成枯枝。", "驟聞漢天子，征彼西南夷。伐棘開洪淵，秉旄訓我師。", "震雲靈鼉鼓，照水蛟龍旗。銳士千萬人，猛氣如熊羆。", "刑罰一以正，干戈自有儀。坐作河漢傾，進退樓船飛。", "羽發鴻雁落，檜動芙蓉披。峨峨三雲宮，肅肅振旅歸。", "惡德忽小丑，器用窮地貲。上兵貴伐謀，此道不能為。", "籲哉蒸人苦，始曰征伐非。穆穆軒轅朝，耀德守方陲。", "君臣日安閒，遠近無怨思。石鯨既蹭蹬，女牛亦流離。", "猵獺遊渚隅，葭蘆生漘湄。坎埳四十裏，填遊今已微。", "江伯方翱翔，天吳亟往來。桑榆慘無色，佇立暮霏霏。", "老幼樵木還，賓從回鞿羈。帝夢鮮魚索，明月當報時。"]'),
('yuding-4','同諸公登慈恩寺塔','儲光羲','唐','御定全唐诗','yuding','','[]','金祠起真宇，直上青雲垂。地靜我亦閑，登之秋清時。',132,'御定全唐詩/json/138.json','["金祠起真宇，直上青雲垂。地靜我亦閑，登之秋清時。", "蒼蕪宜春苑，片碧昆明池。誰道天漢高，逍遙方在茲。", "虛形賓太極，攜手行翠微。雷雨傍杳冥，鬼神中躨跜。", "靈變在倏忽，莫能窮天涯。冠上閶闔開，履下鴻雁飛。", "宮室低邐迤，群山小參差。俯仰宇宙空，庶隨了義歸。", "崱屴非大廈，久居亦以危。"]'),
('yuding-5','同諸公秋霽曲江俯見南山','儲光羲','唐','御定全唐诗','yuding','','[]','天靜終南高，俯映江水明。有若蓬萊下，淺深見澄瀛。',132,'御定全唐詩/json/138.json','["天靜終南高，俯映江水明。有若蓬萊下，淺深見澄瀛。", "群峰懸中流，石壁如瑤瓊。魚龍隱蒼翠，鳥獸遊清泠。", "菰蒲林下秋，薜荔波中輕。山戛浴蘭址，水若居雲屏。", "嵐氣浮渚宮，孤光隨曜靈。陰陰豫章館，宛宛百花亭。", "大君及群臣，宴樂方嚶鳴。吾党二三子，蕭辰怡性情。", "逍遙滄洲時，乃在長安城。"]'),
('yuding-6','同諸公送李雲南伐蠻','儲光羲','唐','御定全唐诗','yuding','','[]','昆明濱滇池，蠢爾敢逆常。天星耀鈇鑕，吊彼西南方。',240,'御定全唐詩/json/138.json','["昆明濱滇池，蠢爾敢逆常。天星耀鈇鑕，吊彼西南方。", "塚宰統元戎，太守齒軍行。囊括千萬里，矢謨在廟堂。", "耀耀金虎符，一息到炎荒。搜兵自交趾，茇舍出瀘陽。", "群山高嶄岩，淩越如鳥翔。封豕驟跧伏，巨象遙披攘。", "回溪深天淵，揭厲逾舟梁。玄武掃孤蜮，蛟龍除方良。", "雷霆隨神兵，硼磕動穹蒼。斬伐若草木，系縲同犬羊。", "餘醜隱弭河，啁啾亂行藏。君子惡薄險，王師恥重傷。", "廣車設罝梁，太白收光芒。邊吏靜縣道，新書行紀綱。", "劍關掉鞅歸，武弁朝建章。龍樓加命服，獬豸擁秋霜。", "邦人頌靈旗，側聽何洋洋。京觀在七德，休哉我神皇。"]'),
('yuding-7','奉和韋判官獻侍郎叔除河東採訪使','儲光羲','唐','御定全唐诗','yuding','','[]','天卿小塚宰，道大名亦大。醜正在權臣，建旟千裏外。',144,'御定全唐詩/json/138.json','["天卿小塚宰，道大名亦大。醜正在權臣，建旟千裏外。", "楚山俯江漢，汴水連譙沛。兩持方伯珪，再轉諸侯蓋。", "恬淡輕黜陟，優遊邈千載。幹象變台衡，群賢盡交泰。", "聿徠股肱郡，河嶽即襟帶。盛德滋冀方，仁風清汾澮。", "四封盡高足，相府軺車最。超超青雲器，婉婉竹林會。", "賤士敢知言，成頌文明代。燕雀依大廈，期之保貞悔。"]'),
('yuding-8','同王十三維哭殷遙','儲光羲','唐','御定全唐诗','yuding','','[]','生理無不盡，念君在中年。遊道雖未深，舉世莫能賢。',168,'御定全唐詩/json/138.json','["生理無不盡，念君在中年。遊道雖未深，舉世莫能賢。", "筮仕苦貧賤，為客少田園。膏腴不可求，乃在許西偏。", "四鄰盡桑柘，咫尺開牆垣。內艱未及虞，形影隨化遷。", "茅茨俯苫蓋，雙殯兩楹間。時聞孤女號，迥出陌與阡。", "慈烏亂飛鳴，猛獸亦以跧。故人王夫子，靜念無生篇。", "哀樂久已絕，聞之將泫然。太陽蔽空虛，雨雪浮蒼山。", "迢遞親靈櫬，顧予悲絕弦。處順與安時，及此乃空言。"]'),
('yuding-9','貽丁主簿仙芝別','儲光羲','唐','御定全唐诗','yuding','','[]','赫赫明天子，翹翹群秀才。昭昭皇宇廣，隱隱雲門開。',240,'御定全唐詩/json/138.json','["赫赫明天子，翹翹群秀才。昭昭皇宇廣，隱隱雲門開。", "搖曳君初起，聯翩予複來。茲年不得意，相命遊靈台。", "驊騮多逸氣，琳琅有清響。聯行擊水飛，獨影淩虛上。", "關河施芳聽，江海徼新賞。斂衽歸故山，敷言播天壤。", "雲峰雖有異，楚越幸相親。既別複遊處，道深情更殷。", "下愚忝聞見，上德猶邅迍。偃仰東城曲，樓遲依水濱。", "脫巾從會府，結綬歸海裔。親知送河門，邦族迎江澨。", "夫子安恬淡，他人悵迢遞。飛艎既眇然，洲渚徒虧蔽。", "人謀固無准，天德諒難知。高名處下位，逸翮棲卑枝。", "去去水中沚，搖搖天一涯。蓬壺不可見，來泛躍龍池。"]'),
('yuding-10','京口送別王四誼','儲光羲','唐','御定全唐诗','yuding','','[]','江上楓林秋，江中秋水流。清晨惜分袂，秋日尚同舟。',48,'御定全唐詩/json/138.json','["江上楓林秋，江中秋水流。清晨惜分袂，秋日尚同舟。", "落潮洗魚浦，傾荷枕驛樓。明年菊花熟，洛東泛觴遊。"]'),
('yuding-11','同房憲部應旋','儲光羲','唐','御定全唐诗','yuding','','[]','衡山法王子，慧見息諸苦。落發自南州，燕居在西土。',168,'御定全唐詩/json/138.json','["衡山法王子，慧見息諸苦。落發自南州，燕居在西土。", "養正不因晦，得中寧患旅。曠然長虛閑，即理寄行補。", "四句了自性，一音亦非取。橘柚故園枝，隨人植庭戶。", "我地少安住，念天時啟處。憲卿文昌歸，愉悅來晤語。", "車騎踐香草，僕人沐花雨。長風散繁雲，萬里靜天宇。", "起滅信易覺，清真知有所。逍遙高殿陰，六月無炎暑。", "微言發新偈，粲粲如懸圃。直心視惠光，在此大法鼓。"]'),
('yuding-12','奉別長史庾公太守徐公應召','儲光羲','唐','御定全唐诗','yuding','','[]','烈風起江漢，白浪忽如山。方伯驟勤王，杞人亦憂天。',132,'御定全唐詩/json/138.json','["烈風起江漢，白浪忽如山。方伯驟勤王，杞人亦憂天。", "酆鎬頃霾晦，雲龍召我賢。車騎北艱苦，艅艎西溯沿。", "水靈靜湍瀨，猛獸趨後先。龍樓開新陽，萬里出雲間。", "宇宙既焜耀，崇德濟巨川。受命在神宗，振兵猶軒轅。", "煌煌逾涿鹿，穆穆更坤元。明王朝太階，遠邇望嘉言。", "遊子淡何思，江湖將永年。"]'),
('yuding-13','獄中貽姚張薛李鄭柳諸公','儲光羲','唐','御定全唐诗','yuding','','[]','直道時莫親，起羞見讒口。輿人是非怪，西子言有咎。',240,'御定全唐詩/json/138.json','["直道時莫親，起羞見讒口。輿人是非怪，西子言有咎。", "誣善不足悲，失聽一何醜。大來敢遐望，小往且虛受。", "中夜囹圄深，初秋縲絏久。疏螢出暗草，朔風鳴衰柳。", "河漢低在戶，蠨蛸垂向牖。雁聲遠天末，涼氣生霽後。", "負戶愁讀書，劍光忿沖鬥。哀哀害神理，惻惻傷慈母。", "妻子垂涕泣，家僮日奔走。書詞苦人吏，饋食勞交友。", "寒服猶未成，繁霜漸將厚。吉凶問詹尹，倚伏信北叟。", "鬼哭知己冤，鳥言誠所誘。諸公深惠愛，朝夕相左右。", "束濕雖欲操，鉤金庶無負。傷羅念搖翮，踠足思驤首。", "瑾瑜頗匿瑕，邦國方含垢。眷言出深阱，永日常攜手。"]'),
('yuding-14','貽鼓吹李丞，時信安王北伐，李公王之所器者也','儲光羲','唐','御定全唐诗','yuding','','[]','北伐昧天造，王師示有征。轅門統元律，帝室命宗英。',144,'御定全唐詩/json/138.json','["北伐昧天造，王師示有征。轅門統元律，帝室命宗英。", "靈威方首事，仗鉞按邊城。膏雨被春草，黃雲浮太清。", "文儒托後乘，武旅趨前旌。出車發西洛，營軍臨北平。", "曰予深固陋，志氣頗縱橫。嘗思驃騎幕，願逐嫖姚兵。", "惟賢美無度，海內依揚聲。河間舊相許，車騎日逢迎。", "折節下謀士，深心論客卿。忠言雖未列，庶以知君誠。"]'),
('yuding-15','貽王侍禦出臺掾丹陽','儲光羲','唐','御定全唐诗','yuding','','[]','高高琅琊台，台下生菌簵。照車十二乘，光彩不足諭。',505,'御定全唐詩/json/138.json','["高高琅琊台，台下生菌簵。照車十二乘，光彩不足諭。", "既當少微星，複隱高山霧。金丘華陽下，仙伯養晦處。", "茅茨對三峰，梧桐開一路。神溪繞皋陸，樵牧自成趣。", "時登青冥遊，若從天江度。墟裏獻薇蕨，群公致衣縷。", "深沉複清淨，偃仰視太素。猛獸識賓僕，赬霞知早暮。", "峨峨雲龍開，忽有方伯遇。達人無不可，壯志且馳騖。", "融泄長雞鳴，演紛大鵬翥。赤墀高崱屴，一見如三顧。", "禮服正邦祀，刑冠肅王度。三辰明昭代，光啟玄元祚。", "章台收杞梓，太液滿鵷鷺。豐澤耀純仁，八方晏黔庶。", "沉沉閶闔起，殷殷蓬萊曙。旌戟儼成行，雞人傳發煦。", "翔翼一如鶚，百辟莫不懼。清廟奉烝嘗，靈山扈鑾輅。", "天街時蹴踘，直指宴梐枑。四月純陽初，雷雨始奮豫，", "析ds增廣運，直道有好惡。回跡清憲台，傳騎東南去。", "列城異疇昔，近餞寡徒禦。纏綿西關道，婉孌新豐樹。", "伊洛不敢息，淮河任沿溯。鄉亭茱萸津，先後非疏附。", "炎時方怵惕，有若踐霜露。惆悵長岑長，寂寞梁王傅。", "紛吾家延州，結友在童孺。岑陽沐天德，邦邑持民務。", "躑躅望朝陰，如何複淪誤。牙曠三千里，擊轅非所慕。", "秋濤聯滄溟，舟楫湊北固。江汜日綿眇，朝夕空寐寤。", "中洞松栝新，東皋阡陌故。餘輝方焜耀，可以歡邑聚。", "南華在濠上，誰辯魏王瓠。登陟芙蓉樓，為我時一賦。"]'),
('yuding-16','貽劉高士別','儲光羲','唐','御定全唐诗','yuding','','[]','夙駕出東城，城傍早霞散。初日照龍闕，峨峨在天半。',240,'御定全唐詩/json/138.json','["夙駕出東城，城傍早霞散。初日照龍闕，峨峨在天半。", "壯哉麗百常，美矣崇兩觀。俯視趨朝客，簪佩何璀璨。", "而我送將歸，裴回霸陵岸。北雲去吳越，南雁離江漢。", "伊昔蹈丘園，翩翩理文翰。高談閔仲叔，逸氣劉公幹。", "每言竹柏貞，嘗輕朝市玩。山晝猿狖靜，溪曛魚鳥亂。", "寧止臥崆峒，直雲期汗漫。聖君既理曆，族士咸炳煥。", "矯首來天池，振羽泛漪瀾。元淑命不達，伯鸞吟可歎。", "東去姑蘇台，乃過陟陽館。舍轡函關道，浮舟滄海畔。", "耳目曠暄涼，懷抱盈悲惋。沉沉青歲晚，靄靄秋雲換。", "自言永遁棲，無複從羈絆。揮手謝知己，知己莫能贊。"]'),
('yuding-17','山中貽崔六琪華','儲光羲','唐','御定全唐诗','yuding','','[]','恍惚登高嶺，裴回看落日。遙想仲長園，如親幼安室。',120,'御定全唐詩/json/138.json','["恍惚登高嶺，裴回看落日。遙想仲長園，如親幼安室。", "春渚菖蒲登，山中撥穀鳴。相思不道遠，太息未知情。", "意君來此地，時複疏林薄。中夜掃閑門，迎晨閉菌閣。", "屣履清池上，家童奉信歸。憂隨落花散，目送歸雲飛。", "故交在天末，心知複千里。無人暫往來，獨作中林士。"]'),
('yuding-18','貽餘處士','儲光羲','唐','御定全唐诗','yuding','','[]','故園至新浦，遙複未百里。北望是他邦，紛吾即遊士。',156,'御定全唐詩/json/138.json','["故園至新浦，遙複未百里。北望是他邦，紛吾即遊士。", "潮來津門啟，罷楫信流水。客意乃成歡，舟人亦相喜。", "遲遲菱荇上，泛泛菰蒲裏。漸聞商旅喧，猶見鳧鷖起。", "市亭忽雲構，方物如山峙。吳王昔喪元，隋帝又滅祀。", "停艫一以眺，太息興亡理。秋苑故池田，宮門新柳杞。", "我行苦炎月，乃及清昊始。此地日逢迎，終思隱君子。", "莫言異舒卷，形音在心耳。"]'),
('yuding-19','劉先生閒居','儲光羲','唐','御定全唐诗','yuding','','[]','高第後歸道，乃居玉華宮。逍遙人間世，不異浮丘公。',108,'御定全唐詩/json/138.json','["高第後歸道，乃居玉華宮。逍遙人間世，不異浮丘公。", "甘寢何秉羽，出門忽從戎。方將遊昆侖，又欲小崆峒。", "進退既在我，歸來長安中。焚香東海君，侍坐西山童。", "善行無轍跡，吾亦安能窮。但見神色閑，中心如虛空。", "期之比天老，真德輔帝鴻。"]'),
('yuding-20','京口題崇上人山亭','儲光羲','唐','御定全唐诗','yuding','','[]','清旦曆香岩，岩徑紆複直。花林開宿霧，遊目清霄極。',72,'御定全唐詩/json/138.json','["清旦曆香岩，岩徑紆複直。花林開宿霧，遊目清霄極。", "分明窗戶中，遠近山川色。金沙童子戲，香飯諸天食。", "叫叫海鴻聲，軒軒江燕翼。寄言清淨者，閭閻徒自踣。"]'),
('yuding-21','朝邑蔡主簿期不會二首','儲光羲','唐','御定全唐诗','yuding','','[]','下位日趨走，久之賓會疏。空遲偶詞賦，所愧比園廬。',144,'御定全唐詩/json/138.json','["下位日趨走，久之賓會疏。空遲偶詞賦，所愧比園廬。", "朝念池上酌，暮逢林下書。方將固封守，暫欲混畋漁。", "衰柳隱長路，秋雲滿太虛。遙遙望左右，日入未回車。", "日入清風至，知君在西偏。車輿既成列，賓僕複能賢。", "迢遞下墟阪，逍遙看井田。蒼山起暮雨，極浦浮長煙。", "服義大如志，交歡數盡年。寧言十餘裏，不見空來還。"]'),
('yuding-22','鞏城南河作寄徐三景暉','儲光羲','唐','御定全唐诗','yuding','','[]','初年雨候遲，鞏洛河流小。搖搖芳草岸，屢見春山曉。',72,'御定全唐詩/json/138.json','["初年雨候遲，鞏洛河流小。搖搖芳草岸，屢見春山曉。", "清露洗雲林，輕波戲魚鳥。唯言故人遠，不念鄉川眇。", "舟楫去瀠回，湍漵行奔峭。寄書千里路，莫道南鴻少。"]'),
('yuding-23','貽閻處士防卜居終南','儲光羲','唐','御定全唐诗','yuding','','[]','春風搖雜樹，言別還江汜。堅冰生綠潭，又客三千里。',180,'御定全唐詩/json/138.json','["春風搖雜樹，言別還江汜。堅冰生綠潭，又客三千里。", "兆夢唯顏色，懸情乃文史。滌耳貴清言，披歡遲玉趾。", "秦城疑舊廬，佇立問焉如。稚子跪而說，還山將隱居。", "竹林既深遠，松宇複清虛。跡迥事多逸，心安趣有餘。", "石門動高韻，草堂新著書。鶱飛久超絕，蹇足空躊躇。", "猶有昔時意，望君當照車。驅車當六國，何以須潛默。", "聖主常征賢，群公每舉德。此時方獨往，身志將何欲。", "願謝山中人，回車首歸躅。"]'),
('yuding-24','新豐作貽殷四校書','儲光羲','唐','御定全唐诗','yuding','','[]','漢皇思舊邑，秦地作新豐。南出華陽路，西分長樂宮。',72,'御定全唐詩/json/138.json','["漢皇思舊邑，秦地作新豐。南出華陽路，西分長樂宮。", "安知天地久，不與昔年同。雞犬暮聲合，城池秋霽空。", "紛吾從此去，望極咸陽中。不見芸香閣，徒思文雅雄。"]'),
('yuding-25','華陽作貽祖三詠','儲光羲','唐','御定全唐诗','yuding','','[]','朝行敷水上，暮出華山東。高館宿初靜，長亭秋轉空。',96,'御定全唐詩/json/138.json','["朝行敷水上，暮出華山東。高館宿初靜，長亭秋轉空。", "日餘久淪汩，重此聞霜風。淅瀝入溪樹，颼飀驚夕鴻。", "淒然望伊洛，如見息陽宮。舊識無高位，新知盡固窮。", "夫君獨輕舉，遠近善文雄。豈念千里駕，崎嶇秦塞中。"]'),
('yuding-26','貽袁三拾遺謫作','儲光羲','唐','御定全唐诗','yuding','','[]','傾蓋洛之濱，依然心事親。龍門何以峻，曾是好詞人。',192,'御定全唐詩/json/138.json','["傾蓋洛之濱，依然心事親。龍門何以峻，曾是好詞人。", "珥筆朝文陛，含章諷紫宸。帝城多壯觀，被服長如春。", "天子儉為德，而能清約身。公卿盡虛位，天下自趣塵。", "如君物望美，令德聲何已。高帝黜儒生，文皇謫才子。", "朝廷非不盛，譴謫良難恃。路出大江陰，川行碧峰裏。", "斯言徒自玷，白玉豈為滓。希聲盡眾人，深識唯知己。", "知己怨生離，悠悠天一涯。寸心因夢斷，孤憤為年移。", "花滿芙蓉闕，春深朝夕池。空令千萬里，長望白雲垂。"]'),
('yuding-27','洛中貽朝校書衡，朝即日本人也','儲光羲','唐','御定全唐诗','yuding','','[]','萬國朝天中，東隅道最長。吾生美無度，高駕仕春坊。',72,'御定全唐詩/json/138.json','["萬國朝天中，東隅道最長。吾生美無度，高駕仕春坊。", "出入蓬山裏，逍遙伊水傍。伯鸞游太學，中夜一相望。", "落日懸高殿，秋風入洞房。屢言相去遠，不覺生朝光。"]'),
('yuding-28','貽崔太祝','儲光羲','唐','御定全唐诗','yuding','','[]','天都分禮閣，肅肅臨清渠。春山照前屏，高槐蔭內除。',72,'御定全唐詩/json/138.json','["天都分禮閣，肅肅臨清渠。春山照前屏，高槐蔭內除。", "惟賢尚廩祿，弟去兄來居。文雅更驤首，風流信有餘。", "中年幸從事，乃遇兩吹噓。何以知君子，交情複淡如。"]'),
('yuding-29','貽王處士子文','儲光羲','唐','御定全唐诗','yuding','','[]','春草生洞渚，春風入上林。春皋有黃鶴，撫翮未揚音。',72,'御定全唐詩/json/138.json','["春草生洞渚，春風入上林。春皋有黃鶴，撫翮未揚音。", "王屋嘗嘉遁，伊川複陸沉。張弦鶤雞弄，閉室蓬蒿深。", "避地歌三樂，遊山賦九吟。大君思左右，無乃化黃金。"]'),
('yuding-30','獻華陰羅丞別','儲光羲','唐','御定全唐诗','yuding','','[]','華山薄游者，玄發當青春。道德同仙吏，尊卑即丈人。',96,'御定全唐詩/json/138.json','["華山薄游者，玄發當青春。道德同仙吏，尊卑即丈人。", "縣城俯京路，獲見官舍裏。淹留瓊樹枝，謔浪春泉水。", "昔餘在天目，總角奉遊從。寒暑遞來往，今複蓮花峰。", "別情無遠近，道別方愁予。孰想古人言，乃知悲風雨。"]'),
('yuding-31','閒居','儲光羲','唐','御定全唐诗','yuding','','[]','薄游何所愧，所愧在閒居。親故不來往，中園時讀書。',72,'御定全唐詩/json/138.json','["薄游何所愧，所愧在閒居。親故不來往，中園時讀書。", "步欄滴餘雪，春塘抽新蒲。梧桐漸覆井，時鳥自相呼。", "悠然念故鄉，乃在天一隅。安得如浮雲，來往方須臾。"]'),
('yuding-32','送恂上人還吳','儲光羲','唐','御定全唐诗','yuding','','[]','洛城本天邑，洛水即天池。君王既行幸，法子複來儀。',48,'御定全唐詩/json/138.json','["洛城本天邑，洛水即天池。君王既行幸，法子複來儀。", "虛室香花滿，清川楊柳垂。乘閑道歸去，遠意誰能知。"]'),
('yuding-33','送周十一','儲光羲','唐','御定全唐诗','yuding','','[]','秋風隕群木，眾草下嚴霜。複問子何如，自言之帝鄉。',48,'御定全唐詩/json/138.json','["秋風隕群木，眾草下嚴霜。複問子何如，自言之帝鄉。", "豈無親所愛，將欲濟時康。握手別征駕，返悲岐路長。"]'),
('yuding-34','新豐主人','儲光羲','唐','御定全唐诗','yuding','','[]','新豐主人新酒熟，舊客還歸舊堂宿。滿酌香含北砌花，',40,'御定全唐詩/json/138.json','["新豐主人新酒熟，舊客還歸舊堂宿。滿酌香含北砌花，", "醉來忘卻巴陵道，夢中疑是洛陽城。"]'),
('yuding-35','登戲馬台作','儲光羲','唐','御定全唐诗','yuding','','[]','君不見宋公仗鉞誅燕後，英雄踴躍爭趨走。',83,'御定全唐詩/json/138.json','["君不見宋公仗鉞誅燕後，英雄踴躍爭趨走。", "小會衣冠呂梁壑，大征甲卒碻磝口。天門神武樹元勳，", "居人滿目市朝變，霸業猶存齊楚甸。泗水南流桐柏川，", "少年自古未得意，日暮蕭條登古台。"]'),
('yuding-36','貽從軍行','儲光羲','唐','御定全唐诗','yuding','','[]','取勝小非用，來朝明光殿。東平不足先，夢出鳳林間。',50,'御定全唐詩/json/138.json','["取勝小非用，來朝明光殿。東平不足先，夢出鳳林間。", "夢還滄海闕，萬里盡陰色。豈為我離別。馬上吹笛起寒風，"]'),
('yuding-37','酬李壺關奉使行縣憶諸公','儲光羲','唐','御定全唐诗','yuding','','[]','青楓江上滄浪吟，白月宮中鸚鵡林。非有淨清心，',38,'御定全唐詩/json/138.json','["青楓江上滄浪吟，白月宮中鸚鵡林。非有淨清心，", "去時能憶竹園游，來時莫忘桃園記。"]'),
('yuding-38','薔薇','儲光羲','唐','御定全唐诗','yuding','','[]','嫋嫋長數尋，青青不作林。一莖獨秀當庭心，',68,'御定全唐詩/json/138.json','["嫋嫋長數尋，青青不作林。一莖獨秀當庭心，", "枝上鶯嬌不畏人，葉底蛾飛自相亂。秦家女兒愛芳菲，", "蒲萄架上朝光滿，楊柳園中暝鳥飛。連袂踏歌從此去，"]'),
('yuding-39','同張侍禦宴北樓','儲光羲','唐','御定全唐诗','yuding','','[]','今之太守古諸侯，出入雙旌垂七旒。朝覽干戈時聽訟，',88,'御定全唐詩/json/138.json','["今之太守古諸侯，出入雙旌垂七旒。朝覽干戈時聽訟，", "良宵清淨方高會，繡服光輝聯皂蓋。魚龍恍惚階墀下，", "蒼蒼低月半遙城，落落疏星滿太清。不分開襟悲楚奏，", "期君武節朝龍闕，餘亦翱翔歸玉京。"]'),
('yuding-0','臨江亭五詠','儲光羲','唐','御定全唐诗','yuding','','[]','晉家南作帝，京鎮北為關。江水中分地，城樓下帶山。',240,'御定全唐詩/json/139.json','["晉家南作帝，京鎮北為關。江水中分地，城樓下帶山。", "金陵事已往，青蓋理無還。落日空亭上，愁看龍尾灣。", "山橫小苑前，路盡大江邊。此地興王業，無如宋主賢。", "潮生建業水，風散廣陵煙。直望清波里，只言別有天。", "城頭落暮暉，城外搗秋衣。江水青雲挹，蘆花白雪飛。", "南州王氣疾，東國海風微。借問商歌客，年年何處歸。", "古木嘯寒禽，層城帶夕陰。梁園多綠柳，楚岸盡楓林。", "山際空為險，江流長自深。平生何以恨，天地本無心。", "京山千里過，孤憤望中來。江勢將天合，城門向水開。", "落霞明楚岸，夕露濕吳台。去去無相識，陳皇安在哉。"]'),
('yuding-1','餞張七琚任宗城即環之季也同產八人俱以才名知','儲光羲','唐','御定全唐诗','yuding','','[]','他日曾游魏，魏家餘趾存。可憐宮殿所，但見桑榆繁。',48,'御定全唐詩/json/139.json','["他日曾游魏，魏家餘趾存。可憐宮殿所，但見桑榆繁。", "此去拜新職，為榮近故園。高陽八才子，況複在君門。"]'),
('yuding-2','留別安慶李太守','儲光羲','唐','御定全唐诗','yuding','','[]','明牧念行子，又言悲解攜。初筵方落日，醉止到鳴雞。',48,'御定全唐詩/json/139.json','["明牧念行子，又言悲解攜。初筵方落日，醉止到鳴雞。", "過客來自北，大軍居在西。丘家如討逆，敢以庶盤溪。"]'),
('yuding-3','洛陽東門送別','儲光羲','唐','御定全唐诗','yuding','','[]','東城別故人，臘月遲芳辰。不惜孤舟去，其如兩地春。',48,'御定全唐詩/json/139.json','["東城別故人，臘月遲芳辰。不惜孤舟去，其如兩地春。", "花明洛陽苑，水綠小平津。是日不相見，鶯聲徒自新。"]'),
('yuding-4','漢陽即事','儲光羲','唐','御定全唐诗','yuding','','[]','楚國千里遠，孰知方寸違。春遊歡有客，夕寢賦無衣。',48,'御定全唐詩/json/139.json','["楚國千里遠，孰知方寸違。春遊歡有客，夕寢賦無衣。", "江水帶冰綠，桃花隨雨飛。九歌有深意，捐佩乃言歸。"]'),
('yuding-5','泊江潭貽馬校書','儲光羲','唐','御定全唐诗','yuding','','[]','明月掛青天，遙遙如目前。故人游畫閣，卻望似雲邊。',48,'御定全唐詩/json/139.json','["明月掛青天，遙遙如目前。故人游畫閣，卻望似雲邊。", "水宿依漁父，歌聲好採蓮。採蓮江上曲，今夕為君傳。"]'),
('yuding-6','送沈校書吳中搜書','儲光羲','唐','御定全唐诗','yuding','','[]','郊外亭皋遠，野中岐路分。苑門臨渭水，山翠雜春雲。',48,'御定全唐詩/json/139.json','["郊外亭皋遠，野中岐路分。苑門臨渭水，山翠雜春雲。", "秦閣多遺典，吳台訪闕文。君王思校理，莫滯清江濆。"]'),
('yuding-7','寒夜江口泊舟','儲光羲','唐','御定全唐诗','yuding','','[]','寒潮信未起，出浦纜孤舟。一夜苦風浪，自然增旅愁。',48,'御定全唐詩/json/139.json','["寒潮信未起，出浦纜孤舟。一夜苦風浪，自然增旅愁。", "吳山遲海月，楚火照江流。欲有知音者，異鄉誰可求。"]'),
('yuding-8','苑外至龍興院作','儲光羲','唐','御定全唐诗','yuding','','[]','朝游天苑外，忽見法筵開。山勢當空出，雲陰滿地來。',48,'御定全唐詩/json/139.json','["朝游天苑外，忽見法筵開。山勢當空出，雲陰滿地來。", "疏鐘清月殿，幽梵靜花台。日暮香林下，飄飄仙步回。"]'),
('yuding-9','題虯上人房','儲光羲','唐','御定全唐诗','yuding','','[]','禪宮分兩地，釋子一為心。入道無來去，清言見古今。',48,'御定全唐詩/json/139.json','["禪宮分兩地，釋子一為心。入道無來去，清言見古今。", "江寒池水綠，山暝竹園深。別有中天月，遙遙散夕陰。"]'),
('yuding-10','詠山泉','儲光羲','唐','御定全唐诗','yuding','','[]','山中有流水，借問不知名。映地為天色，飛空作雨聲。',48,'御定全唐詩/json/139.json','["山中有流水，借問不知名。映地為天色，飛空作雨聲。", "轉來深澗滿，分出小池平。恬澹無人見，年年長自清。"]'),
('yuding-11','貽主客呂郎中','儲光羲','唐','御定全唐诗','yuding','','[]','上士既開天，中朝為得賢。青雲方羽翼，畫省比神仙。',48,'御定全唐詩/json/139.json','["上士既開天，中朝為得賢。青雲方羽翼，畫省比神仙。", "委佩雲霄裏，含香日月前。君王儻借問，客有上林篇。"]'),
('yuding-12','京口留別徐大補闕趙二零陵','儲光羲','唐','御定全唐诗','yuding','','[]','皇州月初曉，處處鼓鐘喧。樹出蓬萊殿，城開閶闔門。',48,'御定全唐詩/json/139.json','["皇州月初曉，處處鼓鐘喧。樹出蓬萊殿，城開閶闔門。", "近臣朝瑣闥，詞客向文園。獨有三川路，空傷遊子魂。"]'),
('yuding-13','答王十三維','儲光羲','唐','御定全唐诗','yuding','','[]','門生故來往，知欲命浮觴。忽奉朝青閣，回車入上陽。',48,'御定全唐詩/json/139.json','["門生故來往，知欲命浮觴。忽奉朝青閣，回車入上陽。", "落花滿春水，疏柳映新塘。是日歸來暮，勞君奏雅章。"]'),
('yuding-14','奉和中書徐侍郎中書省玩白雲寄穎陽趙大','儲光羲','唐','御定全唐诗','yuding','','[]','青闕朝初退，白雲遙在天。非關取雷雨，故欲伴神仙。',48,'御定全唐詩/json/139.json','["青闕朝初退，白雲遙在天。非關取雷雨，故欲伴神仙。", "泛灩鵷池曲，飄颻瑣闥前。猶多遠山意，幸入侍臣篇。"]'),
('yuding-15','和張太祝冬祭馬步','儲光羲','唐','御定全唐诗','yuding','','[]','故壇何肅肅，中野自無喧。烈火見陳信，颺言聞永存。',48,'御定全唐詩/json/139.json','["故壇何肅肅，中野自無喧。烈火見陳信，颺言聞永存。", "房星隱曙色，朔風動寒原。今日歌天馬，非關征大宛。"]'),
('yuding-16','祭風伯壇應張太祝作','儲光羲','唐','御定全唐诗','yuding','','[]','聖主禦青春，綸言命使臣。將修風伯祀，更福太平人。',48,'御定全唐詩/json/139.json','["聖主禦青春，綸言命使臣。將修風伯祀，更福太平人。", "帟幕宵聯事，壇場曉降神。帝心矜動物，非為屬車人。"]'),
('yuding-17','尋徐山人遇馬舍人','儲光羲','唐','御定全唐诗','yuding','','[]','泊舟伊川右，正見野人歸。日暮春山綠，我心清且微。',48,'御定全唐詩/json/139.json','["泊舟伊川右，正見野人歸。日暮春山綠，我心清且微。", "岩聲風雨度，水氣雲霞飛。複有金門客，來參蘿薜衣。"]'),
('yuding-18','夜觀妓','儲光羲','唐','御定全唐诗','yuding','','[]','白雪宜新舞，清宵召楚妃。嬌童攜錦薦，侍女整羅衣。',48,'御定全唐詩/json/139.json','["白雪宜新舞，清宵召楚妃。嬌童攜錦薦，侍女整羅衣。", "花映垂鬟轉，香迎步履飛。徐徐斂長袖，雙燭送將歸。"]'),
('yuding-19','洛橋送別','儲光羲','唐','御定全唐诗','yuding','','[]','河橋送客舟，河水正安流。遠見輕橈動，遙憐故國遊。',48,'御定全唐詩/json/139.json','["河橋送客舟，河水正安流。遠見輕橈動，遙憐故國遊。", "海禽逢早雁，江月值新秋。一聽南津曲，分明散別愁。"]'),
('yuding-20','秦中送人覲省','儲光羲','唐','御定全唐诗','yuding','','[]','二月清江外，遙遙餞故人。南山晴有雪，東陌霽無塵。',48,'御定全唐詩/json/139.json','["二月清江外，遙遙餞故人。南山晴有雪，東陌霽無塵。", "騎別章台晚，舟行洛水春。知君梁苑去，日見白華新。"]'),
('yuding-21','洛中送人還江東','儲光羲','唐','御定全唐诗','yuding','','[]','洛城春雨霽，相送下江鄉。樹綠天津道，山明伊水陽。',48,'御定全唐詩/json/139.json','["洛城春雨霽，相送下江鄉。樹綠天津道，山明伊水陽。", "孤舟從此去，客思一何長。直望清波里，唯餘落日光。"]'),
('yuding-22','送姚六昆客任會稽何大蹇任孟縣','儲光羲','唐','御定全唐诗','yuding','','[]','越城臨渤澥，晉國在河汾。仙綬兩鄉意，青郊一路分。',48,'御定全唐詩/json/139.json','["越城臨渤澥，晉國在河汾。仙綬兩鄉意，青郊一路分。", "野棠春未發，田雀暮成群。他日思吳會，嘗因西北雲。"]'),
('yuding-23','洛潭送人覲省','儲光羲','唐','御定全唐诗','yuding','','[]','清洛帶芝田，東流入大川。舟輕水複急，別望杳如仙。',48,'御定全唐詩/json/139.json','["清洛帶芝田，東流入大川。舟輕水複急，別望杳如仙。", "細草生春岸，明霞散早天。送君唯一曲，當是白華篇。"]'),
('yuding-24','送人隨大夫和蕃','儲光羲','唐','御定全唐诗','yuding','','[]','西方有六國，國國願來賓。聖主今無外，懷柔遣使臣。',48,'御定全唐詩/json/139.json','["西方有六國，國國願來賓。聖主今無外，懷柔遣使臣。", "大夫開幕府，才子作行人。解劍聊相送，邊城二月春。"]'),
('yuding-25','仲夏餞魏四河北覲叔','儲光羲','唐','御定全唐诗','yuding','','[]','落日臨禦溝，送君還北州。樹涼征馬去，路暝歸人愁。',48,'御定全唐詩/json/139.json','["落日臨禦溝，送君還北州。樹涼征馬去，路暝歸人愁。", "吳岳夏雲盡，渭河秋水流。東籬摘芳菊，想見竹林遊。"]'),
('yuding-26','送人尋裴斐','儲光羲','唐','御定全唐诗','yuding','','[]','柱史回清憲，謫居臨漢川。遲君千里駕，方外賞雲泉。',48,'御定全唐詩/json/139.json','["柱史回清憲，謫居臨漢川。遲君千里駕，方外賞雲泉。", "路斷因春水，山深隔暝煙。湘江見遊女，寄摘一枝蓮。"]'),
('yuding-27','隴頭水送別','儲光羲','唐','御定全唐诗','yuding','','[]','相送隴山頭，東西隴水流。從來心膽盛，今日為君愁。',48,'御定全唐詩/json/139.json','["相送隴山頭，東西隴水流。從來心膽盛，今日為君愁。", "暗雪迷征路，寒雲隱戍樓。唯餘旌旆影，相逐去悠悠。"]'),
('yuding-28','送王上人還襄陽','儲光羲','唐','御定全唐诗','yuding','','[]','朝看法雲散，知有至人還。送客臨伊水，行車出故關。',48,'御定全唐詩/json/139.json','["朝看法雲散，知有至人還。送客臨伊水，行車出故關。", "天花滿南國，精舍在空山。雖複時來去，中心長日閑。"]'),
('yuding-29','官莊池觀競渡','儲光羲','唐','御定全唐诗','yuding','','[]','落日吹簫管，清池發棹歌。船爭先後渡，岸激去來波。',48,'御定全唐詩/json/139.json','["落日吹簫管，清池發棹歌。船爭先後渡，岸激去來波。", "水葉藏魚鳥，林花間綺羅。踟躕仙女處，猶似望天河。"]'),
('yuding-30','重寄虯上人','儲光羲','唐','御定全唐诗','yuding','','[]','一作雲峰別，三看花柳朝。青山隔遠路，明月空長霄。',48,'御定全唐詩/json/139.json','["一作雲峰別，三看花柳朝。青山隔遠路，明月空長霄。", "鵲浴西江雨，雞鳴東海潮。此情勞夢寐，況道雙林遙。"]'),
('yuding-31','藍上茅茨期王維補闕','儲光羲','唐','御定全唐诗','yuding','','[]','山中人不見，雲去夕陽過。淺瀨寒魚少，叢蘭秋蝶多。',48,'御定全唐詩/json/139.json','["山中人不見，雲去夕陽過。淺瀨寒魚少，叢蘭秋蝶多。", "老年疏世事，幽性樂天和。酒熟思才子，溪頭望玉珂。"]'),
('yuding-32','大酺得長字韻時任安宜尉','儲光羲','唐','御定全唐诗','yuding','','[]','大道啟元命，時人居太康。中朝發玄澤，下國被天光。',72,'御定全唐詩/json/139.json','["大道啟元命，時人居太康。中朝發玄澤，下國被天光。", "明詔始端午，初筵當履霜。鼓鼙迎爽氣，羽鑰映新陽。", "太守即懸圃，淮夷成葆疆。小臣慚下位，拜手頌靈長。"]'),
('yuding-33','同張侍禦鼎和京兆蕭兵曹華歲晚南園','儲光羲','唐','御定全唐诗','yuding','','[]','公府傳休沐，私庭效陸沉。方知從大隱，非複在幽林。',96,'御定全唐詩/json/139.json','["公府傳休沐，私庭效陸沉。方知從大隱，非複在幽林。", "闕下忠貞志，人間孝友心。既將冠蓋雅，仍與薜蘿深。", "寒變中園柳，春歸上苑禽。池涵青草色，山帶白雲陰。", "潘岳閒居賦，鐘期流水琴。一經當自足，何用遺黃金。"]'),
('yuding-34','奉酬張五丈垂贈','儲光羲','唐','御定全唐诗','yuding','','[]','彩服去江汜，白雲生大樑。星辰動異色，羔雁成新行。',72,'御定全唐詩/json/139.json','["彩服去江汜，白雲生大樑。星辰動異色，羔雁成新行。", "日望天朝近，時憂郢路長。情言間薖軸，惠念及滄浪。", "松柏以之茂，江湖亦自忘。賈生方吊屈，豈敢比南昌。"]'),
('yuding-35','秦中守歲','儲光羲','唐','御定全唐诗','yuding','','[]','眾星已窮次，青帝方行春。永感易成戚，離居難重陳。',72,'御定全唐詩/json/139.json','["眾星已窮次，青帝方行春。永感易成戚，離居難重陳。", "闔門守初夜，燎火到清晨。或念無生法，多傷未出塵。", "廣庭日將晏，虛室自為賓。願以桑榆末，常逢甲子新。"]'),
('yuding-36','獻高使君大酺作','儲光羲','唐','御定全唐诗','yuding','','[]','肅穆郊禋畢，工歌賞事並。三朝遵湛露，一道洽仁明。',60,'御定全唐詩/json/139.json','["肅穆郊禋畢，工歌賞事並。三朝遵湛露，一道洽仁明。", "布德言皆應，無為物自成。花添羅綺色，鶯亂管弦聲。", "獨有同高唱，空陪樂太平。"]'),
('yuding-37','滎陽馬氏二子','儲光羲','唐','御定全唐诗','yuding','','[]','聖君封太嶽，十月建行旃。輦路開千里，寒雲霽九天。',96,'御定全唐詩/json/139.json','["聖君封太嶽，十月建行旃。輦路開千里，寒雲霽九天。", "故人多侍從，二子留伊川。河兗冰初合，關城月屢圓。", "暝過滎水上，聞說鄭卿賢。材蔽行人右，名居東裏先。", "制岩開別業，桑柘亦依然。待至金園側，相將居一廛。"]'),
('yuding-38','觀競渡','儲光羲','唐','御定全唐诗','yuding','','[]','大夫沉楚水，千祀國人哀。習棹江流長，迎神雨霧開。',60,'御定全唐詩/json/139.json','["大夫沉楚水，千祀國人哀。習棹江流長，迎神雨霧開。", "標隨綠雲動，船逆清波來。下怖魚龍起，上驚鳧雁回。", "能令秋大有，鼓吹遠相催。"]'),
('yuding-39','太學貽張筠','儲光羲','唐','御定全唐诗','yuding','','[]','璧池忝門子，俄頃變炎涼。綠竹深虛館，清流響洞房。',72,'御定全唐詩/json/139.json','["璧池忝門子，俄頃變炎涼。綠竹深虛館，清流響洞房。", "園林在建業，新友去咸陽。中夜鼓鐘靜，初秋漏刻長。", "浮雲開太室，華蓋上明堂。空此遠相望，勞歌還自傷。"]'),
('yuding-40','田家即事','儲光羲','唐','御定全唐诗','yuding','','[]','桑柘悠悠水蘸堤，晚風晴景不妨犁。高機猶織臥蠶子，',40,'御定全唐詩/json/139.json','["桑柘悠悠水蘸堤，晚風晴景不妨犁。高機猶織臥蠶子，", "生時樂死皆由命，事在皇天志不迷。"]'),
('yuding-41','洛陽道五首獻呂四郎中','儲光羲','唐','御定全唐诗','yuding','','[]','洛水春冰開，洛城春水綠。朝看大道上，落花亂馬足。',120,'御定全唐詩/json/139.json','["洛水春冰開，洛城春水綠。朝看大道上，落花亂馬足。", "劇孟不知名，千金買寶劍。出入平津邸，自言嬌且豔。", "大道直如發，春日佳氣多。五陵貴公子，雙雙鳴玉珂。", "春風二月時，道傍柳堪把。上枝覆官閣，下枝覆車馬。", "洛水照千門，千門碧空裏。少年不得志，走馬遊新市。"]'),
('yuding-42','同武平一員外游湖','儲光羲','唐','御定全唐诗','yuding','','[]','竹吹留歌扇，蓮香入舞衣。前溪多曲漵，乘興莫先歸。',24,'御定全唐詩/json/139.json','["竹吹留歌扇，蓮香入舞衣。前溪多曲漵，乘興莫先歸。"]'),
('yuding-43','長安道','儲光羲','唐','御定全唐诗','yuding','','[]','鳴鞭過酒肆，袨服遊倡門。百萬一時盡，含情無片言。',48,'御定全唐詩/json/139.json','["鳴鞭過酒肆，袨服遊倡門。百萬一時盡，含情無片言。", "西行一千里，暝色生寒樹。暗聞歌吹聲，知是長安路。"]'),
('yuding-44','江南曲四首','儲光羲','唐','御定全唐诗','yuding','','[]','綠江深見底，高浪直翻空。慣是湖邊住，舟輕不畏風。',96,'御定全唐詩/json/139.json','["綠江深見底，高浪直翻空。慣是湖邊住，舟輕不畏風。", "逐流牽荇葉，緣岸摘蘆苗。為惜鴛鴦鳥，輕輕動畫橈。", "日暮長江裏，相邀歸渡頭。落花如有意，來去逐船流。", "隔江看樹色，沿月聽歌聲。不是長幹住，那從此路行。"]'),
('yuding-45','關山月','儲光羲','唐','御定全唐诗','yuding','','[]','一雁過連營，繁霜覆古城。胡笳在何處，半夜起邊聲。',24,'御定全唐詩/json/139.json','["一雁過連營，繁霜覆古城。胡笳在何處，半夜起邊聲。"]'),
('yuding-46','玉真公主山居','儲光羲','唐','御定全唐诗','yuding','','[]','山北天泉苑，山西鳳女家。不言沁園好，獨隱武陵花。',24,'御定全唐詩/json/139.json','["山北天泉苑，山西鳳女家。不言沁園好，獨隱武陵花。"]'),
('yuding-47','滄浪峽','儲光羲','唐','御定全唐诗','yuding','','[]','滄浪臨古道，道上若成塵。自有滄浪峽，誰為無事人。',24,'御定全唐詩/json/139.json','["滄浪臨古道，道上若成塵。自有滄浪峽，誰為無事人。"]'),
('yuding-48','奉真觀','儲光羲','唐','御定全唐诗','yuding','','[]','真門迥向北，馳道直向西。為與天光近，雲色成虹霓。',24,'御定全唐詩/json/139.json','["真門迥向北，馳道直向西。為與天光近，雲色成虹霓。"]'),
('yuding-49','明妃曲四首','儲光羲','唐','御定全唐诗','yuding','','[]','西行隴上泣胡天，南向雲中指渭川。',128,'御定全唐詩/json/139.json','["西行隴上泣胡天，南向雲中指渭川。", "毳幕夜來時宛轉，何由得似漢王邊。", "胡王知妾不勝悲，樂府皆傳漢國辭。", "朝來馬上箜篌引，稍似宮中閑夜時。", "日暮驚沙亂雪飛，傍人相勸易羅衣。", "強來前殿看歌舞，共待單于夜獵歸。", "彩騎雙雙引寶車，羌笛兩兩奏胡笳。", "若為別得橫橋路，莫隱宮中玉樹花。"]'),
('yuding-50','同武平一員外游湖五首時武貶金壇令','儲光羲','唐','御定全唐诗','yuding','','[]','紅荷碧筱夜相鮮，皂蓋蘭橈浮翠筵。',160,'御定全唐詩/json/139.json','["紅荷碧筱夜相鮮，皂蓋蘭橈浮翠筵。", "舟中對舞邯鄲曲，月下雙彈盧女弦。", "青林碧嶼暗相期，緩楫揮觥欲賦詩。", "借問高歌凡幾轉，河低月落五更時。", "朝來仙閣聽弦歌，暝入花亭見綺羅。", "池邊命酒憐風月，浦口回船惜芰荷。", "朦朧竹影蔽岩扉，淡蕩荷風飄舞衣。", "舟尋綠水宵將半，月隱青林人未歸。", "花潭竹嶼傍幽蹊，畫楫浮空入夜溪。", "芰荷覆水船難進，歌舞留人月易低。"]'),
('yuding-51','題茅山華陽洞','儲光羲','唐','御定全唐诗','yuding','','[]','華陽洞口片雲飛，細雨濛濛欲濕衣。',32,'御定全唐詩/json/139.json','["華陽洞口片雲飛，細雨濛濛欲濕衣。", "玉簫遍滿仙壇上，應是茅家兄弟歸。"]'),
('yuding-52','寄孫山人','儲光羲','唐','御定全唐诗','yuding','','[]','新林二月孤舟還，水滿清江花滿山。',32,'御定全唐詩/json/139.json','["新林二月孤舟還，水滿清江花滿山。", "借問故園隱君子，時時來往住人間。"]'),
('yuding-0','變行路難','王昌齡','唐','御定全唐诗','yuding','','[]','向晚橫吹悲，風動馬嘶合。前驅引旗節，千里陣雲匝。',48,'御定全唐詩/json/140.json','["向晚橫吹悲，風動馬嘶合。前驅引旗節，千里陣雲匝。", "單于下陰山，砂礫空颯颯。封侯取一戰，豈複念閨閣。"]'),
('yuding-1','塞下曲四首','王昌齡','唐','御定全唐诗','yuding','','[]','蟬鳴空桑林，八月蕭關道。出塞入塞寒，處處黃蘆草。',192,'御定全唐詩/json/140.json','["蟬鳴空桑林，八月蕭關道。出塞入塞寒，處處黃蘆草。", "從來幽並客，皆共塵沙老。莫學遊俠兒，矜誇紫騮好。", "飲馬渡秋水，水寒風似刀。平沙日未沒，黯黯見臨洮。", "昔日長城戰，咸言意氣高。黃塵足今古，白骨亂蓬蒿。", "奉詔甘泉宮，總征天下兵。朝廷備禮出，郡國豫郊迎。", "紛紛幾萬人，去者無全生。臣願節宮廄，分以賜邊城。", "邊頭何慘慘，已葬霍將軍。部曲皆相吊，燕南代北聞。", "功勳多被黜，兵馬亦尋分。更遣黃龍戍，唯當哭塞雲。"]'),
('yuding-2','塞上曲','王昌齡','唐','御定全唐诗','yuding','','[]','秋風夜渡河，吹卻雁門桑。遙見胡地獵，韝馬宿嚴霜。',48,'御定全唐詩/json/140.json','["秋風夜渡河，吹卻雁門桑。遙見胡地獵，韝馬宿嚴霜。", "五道分兵去，孤軍百戰場。功多翻下獄，士卒但心傷。"]'),
('yuding-3','從軍行二首','王昌齡','唐','御定全唐诗','yuding','','[]','向夕臨大荒，朔風軫歸慮。平沙萬里餘，飛鳥宿何處。',180,'御定全唐詩/json/140.json','["向夕臨大荒，朔風軫歸慮。平沙萬里餘，飛鳥宿何處。", "虜騎獵長原，翩翩傍河去。邊聲搖白草，海氣生黃霧。", "百戰苦風塵，十年履霜露。雖投定遠筆，未坐將軍樹。", "早知行路難，悔不理章句。", "秋草馬蹄輕，角弓持弦急。去為龍城戰，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。長風金鼓動，白露鐵衣濕。", "四起愁邊聲，南庭時佇立。斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，平原冰霰澀。惟聞漢使還，獨向刀環泣。"]'),
('yuding-4','少年行二首','王昌齡','唐','御定全唐诗','yuding','','[]','西陵俠少年，送客短長亭。青槐夾兩道，白馬如流星。',96,'御定全唐詩/json/140.json','["西陵俠少年，送客短長亭。青槐夾兩道，白馬如流星。", "聞道羽書急，單于寇井陘。氣高輕赴難，誰顧燕山銘。", "走馬遠相尋，西樓下夕陰。結交期一劍，留意贈千金。", "高閣歌聲遠，重門柳色深。夜闌須盡飲，莫負百年心。"]'),
('yuding-5','長歌行','王昌齡','唐','御定全唐诗','yuding','','[]','曠野饒悲風，颼颼黃蒿草。系馬倚白楊，誰知我懷抱。',96,'御定全唐詩/json/140.json','["曠野饒悲風，颼颼黃蒿草。系馬倚白楊，誰知我懷抱。", "所是同袍者，相逢盡衰老。北登漢家陵，南望長安道。", "下有枯樹根，上有鼯鼠窠。高皇子孫盡，千載無人過。", "寶玉頻發掘，精靈其奈何。人生須達命，有酒且長歌。"]'),
('yuding-6','悲哉行','王昌齡','唐','御定全唐诗','yuding','','[]','勿聽白頭吟，人間易憂怨。若非滄浪子，安得從所願。',84,'御定全唐詩/json/140.json','["勿聽白頭吟，人間易憂怨。若非滄浪子，安得從所願。", "北上太行山，臨風閱吹萬。長雲數千里，倏忽還膚寸。", "觀其微滅時，精意莫能論。百年不容息，是處生意蔓。", "始悟海上人，辭君永飛遁。"]'),
('yuding-7','古意','王昌齡','唐','御定全唐诗','yuding','','[]','桃花四面發，桃葉一枝開。欲暮黃鸝囀，傷心玉鏡臺。',36,'御定全唐詩/json/140.json','["桃花四面發，桃葉一枝開。欲暮黃鸝囀，傷心玉鏡臺。", "清箏向明月，半夜春風來。"]'),
('yuding-8','放歌行','王昌齡','唐','御定全唐诗','yuding','','[]','南渡洛陽津，西望十二樓。明堂坐天子，月朔朝諸侯。',144,'御定全唐詩/json/140.json','["南渡洛陽津，西望十二樓。明堂坐天子，月朔朝諸侯。", "清樂動千門，皇風被九州。慶雲從東來，泱漭抱日流。", "升平貴論道，文墨將何求。有詔征草澤，微誠將獻謀。", "冠冕如星羅，拜揖曹與周。望塵非吾事，入賦且遲留。", "幸蒙國士識，因脫負薪裘。今者放歌行，以慰梁甫愁。", "但營數鬥祿，奉養每豐羞。若得金膏遂，飛雲亦可儔。"]'),
('yuding-9','《越女','王昌齡','唐','御定全唐诗','yuding','','[]','越女作桂舟，還將桂為楫。湖上水渺漫，清江不可涉。',48,'御定全唐詩/json/140.json','["越女作桂舟，還將桂為楫。湖上水渺漫，清江不可涉。", "摘取芙蓉花，莫摘芙蓉葉。將歸問夫婿，顏色何如妾。"]'),
('yuding-10','鄭縣宿陶太公館中贈馮六元二','王昌齡','唐','御定全唐诗','yuding','','[]','儒有輕王侯，脫略當世務。本家藍田下，非為漁弋故。',192,'御定全唐詩/json/140.json','["儒有輕王侯，脫略當世務。本家藍田下，非為漁弋故。", "無何困躬耕，且欲馳永路。幽居與君近，出穀同所騖。", "昨日辭石門，五年變秋露。雲龍未相感，幹謁亦已屢。", "子為黃綬羈，餘忝蓬山顧。京門望西嶽，百里見郊樹。", "飛雨祠上來，靄然關中暮。驅車鄭城宿，秉燭論往素。", "山月出華陰，開此河渚霧。清光比故人，豁達展心晤。", "馮公尚戢翼，元子仍局步。拂衣易為高，淪跡難有趣。", "張範善終始，吾等豈不慕。罷酒當涼風，屈伸備冥數。"]'),
('yuding-11','聽彈風入松闋贈楊補闕','王昌齡','唐','御定全唐诗','yuding','','[]','商風入我弦，夜竹深有露。弦悲與林寂，清景不可度。',72,'御定全唐詩/json/140.json','["商風入我弦，夜竹深有露。弦悲與林寂，清景不可度。", "寥落幽居心，颼飀青松樹。松風吹草白，溪水寒日暮。", "聲意去複還，九變待一顧。空山多雨雪，獨立君始悟。"]'),
('yuding-12','緱氏尉沈興宗置酒南溪留贈','王昌齡','唐','御定全唐诗','yuding','','[]','林色與溪古，深篁引幽翠。山尊在漁舟，棹月情已醉。',144,'御定全唐詩/json/140.json','["林色與溪古，深篁引幽翠。山尊在漁舟，棹月情已醉。", "始窮清源口，壑絕人境異。春泉滴空崖，萌草拆陰地。", "久之風榛寂，遠聞樵聲至。海雁時獨飛，永然滄洲意。", "古時青冥客，滅跡淪一尉。吾子躊躇心，豈其紛埃事。", "緱峰信所克，濟北餘乃遂。齊物意已會，息肩理猶未。", "卷舒形性表，脫略賢哲議。仲月期角巾，飯僧嵩陽寺。"]'),
('yuding-13','為張僓贈閻使臣','王昌齡','唐','御定全唐诗','yuding','','[]','哀哀獻玉人，楚國同悲辛。泣盡繼以血，何由辨其真。',48,'御定全唐詩/json/140.json','["哀哀獻玉人，楚國同悲辛。泣盡繼以血，何由辨其真。", "賴承琢磨惠，複使光輝新。猶畏讒口疾，棄之如埃塵。"]'),
('yuding-14','贈史昭','王昌齡','唐','御定全唐诗','yuding','','[]','東林月未升，廓落星與漢。是夕鴻始來，齋中起長歎。',72,'御定全唐詩/json/140.json','["東林月未升，廓落星與漢。是夕鴻始來，齋中起長歎。", "懷哉望南浦，眇然夜將半。但有秋水聲，愁使心神亂。", "握中何為贈，瑤草已衰散。海鱗未化時，各在天一岸。"]'),
('yuding-15','秋山寄陳讜言','王昌齡','唐','御定全唐诗','yuding','','[]','岩間寒事早，眾山木已黃。北風何蕭蕭，茲夕露為霜。',72,'御定全唐詩/json/140.json','["岩間寒事早，眾山木已黃。北風何蕭蕭，茲夕露為霜。", "感激未能寐，中宵時慨慷。黃蟲初悲鳴，玄鳥去我梁。", "獨臥時易晚，離群情更傷。思君若不及，鴻雁今南翔。"]'),
('yuding-16','出郴山口至疊石灣野人室中寄張十一','王昌齡','唐','御定全唐诗','yuding','','[]','櫧楠無冬春，柯葉連峰稠。陰壁下蒼黑，煙含清江樓。',204,'御定全唐詩/json/140.json','["櫧楠無冬春，柯葉連峰稠。陰壁下蒼黑，煙含清江樓。", "景開獨沿曳，響答隨興酬。旦夕望吾友，如何迅孤舟。", "疊沙積為崗，崩剝雨露幽。石脈盡橫亙，潛潭何時流。", "既見萬古色，頗盡一物由。永與世人遠，氣還草木收。", "盈縮理無餘，今往何必憂。郴土群山高，耆老如中州。", "孰雲議舛降，豈是娛宦遊。陰火昔所伏，丹砂將爾謀。", "昨臨蘇耽井，複向衡陽求。同疚來相依，脫身當有籌。", "數月乃離居，風湍成阻修。野人善竹器，童子能溪謳。", "寒月波蕩漾，羈鴻去悠悠。"]'),
('yuding-17','宿灞上寄侍禦璵弟','王昌齡','唐','御定全唐诗','yuding','','[]','獨飲灞上亭，寒山青門外。長雲驟落日，桑棗寂已晦。',360,'御定全唐詩/json/140.json','["獨飲灞上亭，寒山青門外。長雲驟落日，桑棗寂已晦。", "古人驅馳者，宿此凡幾代。佐邑由東南，豈不知進退。", "吾宗秉全璞，楚得璆琳最。茅山就一征，柏署起三載。", "道契非物理，神交無留礙。知我滄溟心，脫略腐儒輩。", "孟冬鑾輿出，陽穀群臣會。半夜馳道喧，五侯擁軒蓋。", "是時燕齊客，獻術蓬瀛內。甚悅我皇心，得與王母對。", "賤臣欲幹謁，稽首期殞碎。哲弟感我情，問易窮否泰。", "良馬足尚踠，寶刀光未淬。昨聞羽書飛，兵氣連朔塞。", "諸將多失律，廟堂始追悔。安能召書生，願得論要害。", "戎夷非草木，侵逐使狼狽。雖有屠城功，亦有降虜輩。", "兵糧如山積，恩澤如雨霈。羸卒不可興，磧地無足愛。", "若用匹夫策，坐令軍圍潰。不費黃金資，甯求白璧賚。", "明主憂既遠，邊事亦可大。荷寵務推誠，離言深慷慨。", "霜搖直指草，燭引明光佩。公論日夕阻，朝廷蹉跎會。", "孤城海門月，萬里流光帶。不應百尺松，空老鐘山靄。"]'),
('yuding-18','次汝中寄河南陳贊府','王昌齡','唐','御定全唐诗','yuding','','[]','汝山方聯延，伊水才明滅。遙見入楚雲，又此空館月。',72,'御定全唐詩/json/140.json','["汝山方聯延，伊水才明滅。遙見入楚雲，又此空館月。", "紛然馳夢想，不謂遠離別。京邑多歡娛，衡湘暫沿越。", "明湖春草遍，秋桂白花發。豈惟長思君，日夕在魏闕。"]'),
('yuding-19','同從弟銷南齋玩月憶山陰崔少府','王昌齡','唐','御定全唐诗','yuding','','[]','高臥南齋時，開帷月初吐。清輝淡水木，演漾在窗戶。',60,'御定全唐詩/json/140.json','["高臥南齋時，開帷月初吐。清輝淡水木，演漾在窗戶。", "苒苒幾盈虛，澄澄變今古。美人清江畔，是夜越吟苦。", "千里其如何，微風吹蘭杜。"]'),
('yuding-20','代扶風主人答','王昌齡','唐','御定全唐诗','yuding','','[]','殺氣凝不流，風悲日彩寒。浮埃起四遠，遊子彌不歡。',228,'御定全唐詩/json/140.json','["殺氣凝不流，風悲日彩寒。浮埃起四遠，遊子彌不歡。", "依然宿扶風，沽酒聊自寬。寸心亦未理，長鋏誰能彈。", "主人就我飲，對我還慨歎。便泣數行淚，因歌行路難。", "十五役邊地，三回討樓蘭。連年不解甲，積日無所餐。", "將軍降匈奴，國使沒桑幹。去時三十萬，獨自還長安。", "不信沙場苦，君看刀箭瘢。鄉親悉零落，塚墓亦摧殘。", "仰攀青松枝，慟絕傷心肝。禽獸悲不去，路傍誰忍看。", "幸逢休明代，寰宇靜波瀾。老馬思伏櫪，長鳴力已殫。", "少年與運會，何事發悲端。天子初封禪，賢良刷羽翰。", "三邊悉如此，否泰亦須觀。"]'),
('yuding-21','酬鴻臚裴主簿雨後北樓見贈','王昌齡','唐','御定全唐诗','yuding','','[]','暮霞照新晴，歸雲猶相逐。有懷晨昏暇，想見登眺目。',120,'御定全唐詩/json/140.json','["暮霞照新晴，歸雲猶相逐。有懷晨昏暇，想見登眺目。", "問禮侍彤襜，題詩訪茅屋。高樓多古今，陳事滿陵穀。", "地久微子封，台餘孝王築。裴回顧霄漢，豁達俯川陸。", "遠水對孤城，長天向喬木。公門何清靜，列戟森已肅。", "不歎攜手稀，常思著鞭速。終當拂羽翰，輕舉隨鴻鵠。"]'),
('yuding-22','送任五之桂林','王昌齡','唐','御定全唐诗','yuding','','[]','楚客醉孤舟，越水將引棹。山為兩鄉別，月帶千里貌。',48,'御定全唐詩/json/140.json','["楚客醉孤舟，越水將引棹。山為兩鄉別，月帶千里貌。", "羈譴同繒綸，僻幽聞虎豹。桂林寒色在，苦節知所效。"]'),
('yuding-23','山中別龐十','王昌齡','唐','御定全唐诗','yuding','','[]','幽娟松筱徑，月出寒蟬鳴。散發臥其下，誰知孤隱情。',48,'御定全唐詩/json/140.json','["幽娟松筱徑，月出寒蟬鳴。散發臥其下，誰知孤隱情。", "吟時白雲合，釣處玄潭清。瓊樹方杳靄，鳳兮保其貞。"]'),
('yuding-24','留別伊闕張少府郭大都尉','王昌齡','唐','御定全唐诗','yuding','','[]','遷客就一醉，主人空金罍。江湖青山底，欲去仍裴回。',96,'御定全唐詩/json/140.json','["遷客就一醉，主人空金罍。江湖青山底，欲去仍裴回。", "郭侯未相識，策馬伊川來。把手相勸勉，不應老塵埃。", "孟陽逢山舊，仙館留清才。日晚勸趣別，風長雲逐開。", "幸隨板輿遠，負譴何憂哉。唯有仗忠信，音書報雲雷。"]'),
('yuding-25','送韋十二兵曹','王昌齡','唐','御定全唐诗','yuding','','[]','縣職如長纓，終日檢我身。平明趨郡府，不得展故人。',132,'御定全唐詩/json/140.json','["縣職如長纓，終日檢我身。平明趨郡府，不得展故人。", "故人念江湖，富貴如埃塵。跡在戎府掾，心遊天臺春。", "獨立浦邊鶴，白雲長相親。南風忽至吳，分散還入秦。", "寒夜天光白，海淨月色真。對坐論歲暮，弦悲豈無因。", "平生馳驅分，非謂杯酒仁。出處兩不合，忠貞何由伸。", "看君孤舟去，且欲歌垂綸。"]'),
('yuding-26','東京府縣諸公與綦毋潛李頎相送至白馬寺宿','王昌齡','唐','御定全唐诗','yuding','','[]','鞍馬上東門，裴回入孤舟。賢豪相追送，即棹千里流。',84,'御定全唐詩/json/140.json','["鞍馬上東門，裴回入孤舟。賢豪相追送，即棹千里流。", "赤岸落日在，空波微煙收。薄宦忘機括，醉來即淹留。", "月明見古寺，林外登高樓。南風開長廊，夏夜如涼秋。", "江月照吳縣，西歸夢中游。"]'),
('yuding-27','送東林廉上人歸廬山','王昌齡','唐','御定全唐诗','yuding','','[]','石溪流已亂，苔徑人漸微。日暮東林下，山僧還獨歸。',60,'御定全唐詩/json/140.json','["石溪流已亂，苔徑人漸微。日暮東林下，山僧還獨歸。", "昔為廬峰意，況與遠公違。道性深寂寞，世情多是非。", "會尋名山去，豈複望清輝。"]'),
('yuding-28','留別武陵袁丞','王昌齡','唐','御定全唐诗','yuding','','[]','皇恩暫遷謫，待罪逢知己。從此武陵溪，孤舟二千里。',48,'御定全唐詩/json/140.json','["皇恩暫遷謫，待罪逢知己。從此武陵溪，孤舟二千里。", "桃花遺古岸，金澗流春水。誰識馬將軍，忠貞抱生死。"]'),
('yuding-29','別劉諝','王昌齡','唐','御定全唐诗','yuding','','[]','天地寒更雨，蒼茫楚城陰。一尊廣陵酒，十載衡陽心。',72,'御定全唐詩/json/140.json','["天地寒更雨，蒼茫楚城陰。一尊廣陵酒，十載衡陽心。", "倚仗不可料，悲歡豈易尋。相逢成遠別，後會何如今。", "身在江海上，雲連京國深。行當務功業，策馬何駸駸。"]'),
('yuding-30','岳陽別李十七越賓','王昌齡','唐','御定全唐诗','yuding','','[]','相逢楚水寒，舟在洞庭驛。具陳江波事，不異淪棄跡。',120,'御定全唐詩/json/140.json','["相逢楚水寒，舟在洞庭驛。具陳江波事，不異淪棄跡。", "杉上秋雨聲，悲切蒹葭夕。彈琴收餘響，來送千里客。", "平明孤帆心，歲晚濟代策。時在身未充，瀟湘不盈畫。", "湖小洲渚聯，澹淡煙景碧。魚鱉自有性，龜龍無能易。", "譴黜同所安，風土任所適。閉門觀玄化，攜手遺損益。"]'),
('yuding-31','留別岑參兄弟','王昌齡','唐','御定全唐诗','yuding','','[]','江城建業樓，山盡滄海頭。副職守茲縣，東南棹孤舟。',144,'御定全唐詩/json/140.json','["江城建業樓，山盡滄海頭。副職守茲縣，東南棹孤舟。", "長安故人宅，秣馬經前秋。便以風雪暮，還為縱飲留。", "貂蟬七葉貴，鴻鵠萬里遊。何必念鐘鼎，所在烹肥牛。", "為君嘯一曲，且莫彈箜篌。徒見枯者豔，誰言直如鉤。", "岑家雙瓊樹，騰光難為儔。誰言青門悲，俯期吳山幽。", "日西石門嶠，月吐金陵洲。追隨探靈怪，豈不驕王侯。"]'),
('yuding-32','送劉昚虛歸取宏詞解','王昌齡','唐','御定全唐诗','yuding','','[]','太清聞海鶴，遊子引鄉眄。聲隨羽儀遠，勢與歸雲便。',48,'御定全唐詩/json/140.json','["太清聞海鶴，遊子引鄉眄。聲隨羽儀遠，勢與歸雲便。", "青桂春再榮，白雲暮來變。遷飛在禮儀，豈複淚如霰。"]'),
('yuding-33','巴陵別劉處士','王昌齡','唐','御定全唐诗','yuding','','[]','劉生隱岳陽，心遠洞庭水。偃帆入山郭，一宿楚雲裏。',72,'御定全唐詩/json/140.json','["劉生隱岳陽，心遠洞庭水。偃帆入山郭，一宿楚雲裏。", "竹映秋館深，月寒江風起。煙波桂陽接，日夕數千里。", "嫋嫋清夜猿，孤舟坐如此。湘中有來雁，雨雪候音旨。"]'),
('yuding-34','宿裴氏山莊','王昌齡','唐','御定全唐诗','yuding','','[]','蒼蒼竹林暮，吾亦知所投。靜坐山齋月，清溪聞遠流。',48,'御定全唐詩/json/140.json','["蒼蒼竹林暮，吾亦知所投。靜坐山齋月，清溪聞遠流。", "西峰下微雨，向曉白雲收。遂解塵中組，終南春可遊。"]'),
('yuding-35','淇上酬薛據兼寄郭微','王昌齡','唐','御定全唐诗','yuding','','[]','自從別京華，我心乃蕭索。十年守章句，萬里空寥落。',216,'御定全唐詩/json/140.json','["自從別京華，我心乃蕭索。十年守章句，萬里空寥落。", "北上登薊門，茫茫見沙漠。倚劍對風塵，慨然思衛霍。", "拂衣去燕趙，驅馬悵不樂。天長滄洲路，日暮邯鄲郭。", "酒肆或淹留，漁澤屢棲泊。獨行備艱難，孰辭幹鼎鑊。", "皇情念淳古，時俗何浮薄。理道須任賢，安人在求瘼。", "故交負奇才，逸氣包謇諤。隱軫經濟策，縱橫建安作。", "才望忽先鳴，風期無宿諾。飄颻勞州縣，迢遞限言謔。", "東馳眇貝丘，西顧彌虢略。淇水徒自深，浮雲不堪托。", "吾謀適可用，天道豈遼廓。不然買山田，一身與耕鑿。"]'),
('yuding-0','詠史','王昌齡','唐','御定全唐诗','yuding','','[]','荷畚至洛陽，杖策遊北門。天下盡兵甲，豺狼滿中原。',96,'御定全唐詩/json/141.json','["荷畚至洛陽，杖策遊北門。天下盡兵甲，豺狼滿中原。", "明夷方遘患，顧我徒崩奔。自慚菲薄才，誤蒙國士恩。", "位重任亦重，時危志彌敦。西北未及終，東南不可吞。", "進則恥保躬，退乃為觸藩。歎息嵩山老，而後知其尊。"]'),
('yuding-1','雜興','王昌齡','唐','御定全唐诗','yuding','','[]','握中銅匕首，粉銼楚山鐵。義士頻報讎，殺人不曾缺。',72,'御定全唐詩/json/141.json','["握中銅匕首，粉銼楚山鐵。義士頻報讎，殺人不曾缺。", "可悲燕丹事，終被狼虎滅。一舉無兩全，荊軻遂為血。", "誠知匹夫勇，何取萬人傑。無道吞諸侯，坐見九州裂。"]'),
('yuding-2','秋興','王昌齡','唐','御定全唐诗','yuding','','[]','日暮西北堂，涼風洗修木。著書在南窗，門館常肅肅。',48,'御定全唐詩/json/141.json','["日暮西北堂，涼風洗修木。著書在南窗，門館常肅肅。", "苔草延古意，視聽轉幽獨。或問余所營，刈黍就寒穀。"]'),
('yuding-3','齋心','王昌齡','唐','御定全唐诗','yuding','','[]','女蘿覆石壁，溪水幽蒙朧。紫葛蔓黃花，娟娟寒露中。',60,'御定全唐詩/json/141.json','["女蘿覆石壁，溪水幽蒙朧。紫葛蔓黃花，娟娟寒露中。", "朝飲花上露，夜臥松下風。雲英化為水，光采與我同。", "日月蕩精魄，寥寥天宇空。"]'),
('yuding-4','獨游','王昌齡','唐','御定全唐诗','yuding','','[]','林臥情每閑，獨游景常晏。時從灞陵下，垂釣往南澗。',84,'御定全唐詩/json/141.json','["林臥情每閑，獨游景常晏。時從灞陵下，垂釣往南澗。", "手攜雙鯉魚，目送千里雁。悟彼飛有適，知此罹憂患。", "放之清冷泉，因得省疏慢。永懷青岑客，回首白雲間。", "神超物無違，豈系名與宦。"]'),
('yuding-5','香積寺禮拜萬回平等二聖僧塔','王昌齡','唐','御定全唐诗','yuding','','[]','真無禦化來，借有乘化歸。如彼雙塔內，孰能知是非。',84,'御定全唐詩/json/141.json','["真無禦化來，借有乘化歸。如彼雙塔內，孰能知是非。", "愚也駭蒼生，聖哉為帝師。當為時世出，不由天地資。", "萬回主此方，平等性無違。今我一禮心，億劫同不移。", "肅肅松柏下，諸天來有時。"]');
